/**
 * DST Verification Engine
 *
 * Walks a NeuralMap and verifies security properties hold.
 * Each CWE maps to a verification path: a specific gap pattern
 * checked against the graph structure.
 *
 * The neural map IS the query. The node types ARE the verification logic.
 * The CWE→assertion mapping is just an index into which path to run.
 */

import type { NeuralMap, NeuralMapNode, NodeType, EdgeType } from './types';
import { evaluateControlEffectiveness, getContainingScopeSnapshots } from './generated/_helpers.js';
import { GENERATED_REGISTRY } from './generated/index.js';

// ---------------------------------------------------------------------------
// Comment stripping — prevents comments from defeating safe-pattern detection
// ---------------------------------------------------------------------------

/**
 * Strip comments from a code snapshot so that safe-pattern regexes only match
 * actual code, not comments. Handles:
 *   - Single-line comments (// ...) and (# ...) for Python/Ruby/PHP
 *   - Multi-line comments (/* ... *​/)
 *   - Preserves string literals — won't strip // inside "strings" or 'strings'
 *   - Preserves template literals — won't strip // inside `backtick strings`
 */
export function stripComments(code: string): string {
  let result = '';
  let i = 0;
  const len = code.length;

  while (i < len) {
    const ch = code[i];
    const next = i + 1 < len ? code[i + 1] : '';

    // String literals — skip through without stripping
    if (ch === '"' || ch === "'" || ch === '`') {
      const quote = ch;
      result += ch;
      i++;
      while (i < len) {
        if (code[i] === '\\') {
          // Escaped character — consume both
          result += code[i] + (i + 1 < len ? code[i + 1] : '');
          i += 2;
          continue;
        }
        if (code[i] === quote) {
          result += code[i];
          i++;
          break;
        }
        result += code[i];
        i++;
      }
      continue;
    }

    // Multi-line comment: /* ... */
    if (ch === '/' && next === '*') {
      i += 2;
      while (i < len) {
        if (code[i] === '*' && i + 1 < len && code[i + 1] === '/') {
          i += 2;
          break;
        }
        i++;
      }
      result += ' '; // Replace comment with space to avoid token merging
      continue;
    }

    // Single-line comment: // ...
    if (ch === '/' && next === '/') {
      // Skip to end of line
      i += 2;
      while (i < len && code[i] !== '\n') {
        i++;
      }
      continue;
    }

    // Hash comment: # ... (Python, Ruby, PHP)
    if (ch === '#') {
      // Skip to end of line
      i++;
      while (i < len && code[i] !== '\n') {
        i++;
      }
      continue;
    }

    result += ch;
    i++;
  }

  return result;
}

// ---------------------------------------------------------------------------
// Verification result types
// ---------------------------------------------------------------------------

export interface VerificationResult {
  /** CWE identifier */
  cwe: string;
  /** Human-readable name */
  name: string;
  /** Whether the property holds */
  holds: boolean;
  /** Specific findings — empty if property holds */
  findings: Finding[];
}

export interface Finding {
  /** The source node (where tainted data originates) */
  source: NodeRef;
  /** The sink node (where tainted data arrives without control) */
  sink: NodeRef;
  /** What's missing between source and sink */
  missing: string;
  /** Severity */
  severity: 'critical' | 'high' | 'medium' | 'low';
  /** Plain-language description */
  description: string;
  /** Remediation guidance */
  fix: string;
}

export interface NodeRef {
  id: string;
  label: string;
  line: number;
  code: string;
}

// ---------------------------------------------------------------------------
// Graph traversal helpers
// ---------------------------------------------------------------------------

/**
 * Edge types that represent actual data flow between nodes.
 * CONTAINS is structural containment (function contains statement) and
 * DEPENDS is a dependency relationship — neither represents data movement.
 * BFS for vulnerability path detection should only follow flow edges.
 */
const FLOW_EDGE_TYPES: ReadonlySet<EdgeType> = new Set([
  'DATA_FLOW', 'CALLS', 'READS', 'WRITES', 'RETURNS',
]);

function nodeRef(node: NeuralMapNode): NodeRef {
  return {
    id: node.id,
    label: node.label,
    line: node.line_start,
    code: node.code_snapshot.slice(0, 200),
  };
}

/** Find all nodes of a given type */
function nodesOfType(map: NeuralMap, type: NodeType): NeuralMapNode[] {
  return map.nodes.filter(n => n.node_type === type);
}

/** Find all nodes with a specific subtype */
function nodesOfSubtype(map: NeuralMap, subtype: string): NeuralMapNode[] {
  return map.nodes.filter(n => n.node_subtype === subtype);
}

/** Find all nodes with a specific attack surface tag */
function nodesWithSurface(map: NeuralMap, surface: string): NeuralMapNode[] {
  return map.nodes.filter(n => n.attack_surface.includes(surface));
}

/**
 * Infer the primary language of a NeuralMap from node languages or source_file extension.
 * Returns a lowercase language string (e.g. 'javascript', 'go', 'python', 'ruby', 'php').
 */
function inferMapLanguage(map: NeuralMap): string {
  // Try map-level language first (may be set dynamically)
  if ((map as any).language) return (map as any).language.toLowerCase();
  // Check majority node language
  const langCounts = new Map<string, number>();
  for (const n of map.nodes) {
    if (n.language) {
      const lang = n.language.toLowerCase();
      langCounts.set(lang, (langCounts.get(lang) ?? 0) + 1);
    }
  }
  if (langCounts.size > 0) {
    let best = ''; let bestCount = 0;
    for (const [l, c] of langCounts) { if (c > bestCount) { best = l; bestCount = c; } }
    return best;
  }
  // Fall back to source file extension
  const ext = map.source_file?.split('.').pop()?.toLowerCase() ?? '';
  const EXT_MAP: Record<string, string> = {
    js: 'javascript', jsx: 'javascript', mjs: 'javascript', cjs: 'javascript',
    ts: 'typescript', tsx: 'typescript', mts: 'typescript',
    py: 'python', rb: 'ruby', php: 'php', go: 'go',
    java: 'java', kt: 'kotlin', kts: 'kotlin',
    rs: 'rust', cs: 'csharp', swift: 'swift',
    c: 'c', cpp: 'c++', cc: 'c++', cxx: 'c++', h: 'c', hpp: 'c++',
  };
  return EXT_MAP[ext] ?? '';
}

/**
 * Detect whether the scanned file is a library/framework rather than application code.
 *
 * Library code exports building blocks (middleware helpers, protocol handlers, response
 * utilities) that applications consume.  Many CWEs that are valid for application code
 * are false positives on library internals — e.g. "no clickjacking header" or "throw
 * without local catch" are perfectly fine in a library that exposes primitives.
 *
 * Heuristics (any ONE is sufficient):
 *   1. Path in a known framework/library directory.
 *   2. Prototype-heavy code (>= 3 proto assignments).
 *   3. module.exports = {} with many method assignments on the exported object.
 *   4. Many named exports (exports.xxx = ...).
 *   5. High STRUCTURAL-to-INGRESS ratio with multiple function definitions.
 *   6. File defines methods on an exported object (e.g., app.xxx = function, or res.xxx = function).
 */
function isLibraryCode(map: NeuralMap): boolean {
  const allCode = map.nodes.map(n => n.code_snapshot).join('\n');
  const filePath = (map.source_file ?? '').replace(/\\/g, '/').toLowerCase();

  // Path-based detection: known framework/library directories
  // Match express*/lib, fastify*/lib, koa*/lib, etc. (handles express-clean, fastify-v4, etc.)
  if (/(?:node_modules|(?:express|fastify|koa|hapi|restify|connect)[\w-]*\/lib|\/lib\/(?:middleware|utils|helpers|internal))/.test(filePath)) {
    return true;
  }

  // Prototype assignment pattern — strong library signal
  const protoAssignments = (allCode.match(/\.\s*prototype\s*\.\s*\w+\s*=/g) || []).length;
  if (protoAssignments >= 3) return true;

  // module.exports = {} with many method assignments — library utility module
  if (/module\.exports\s*=\s*\{/.test(allCode) && protoAssignments >= 1) return true;

  // Many named exports (exports.xxx = function)
  if (/exports\.\w+\s*=\s*function/.test(allCode) && (allCode.match(/exports\.\w+\s*=/g) || []).length >= 5) return true;

  // Methods assigned to an exported object variable (e.g., app.xxx = function, res.xxx = function)
  // This catches Express's pattern: var app = module.exports = {}; app.init = function() {...}
  const methodAssignRe = /\b\w+\.\w+\s*=\s*function\b/g;
  const methodAssignments = (allCode.match(methodAssignRe) || []).length;
  if (methodAssignments >= 8 && /module\.exports/.test(allCode)) return true;

  // High structural-to-ingress ratio with many function definitions — library pattern
  const structural = nodesOfType(map, 'STRUCTURAL').length;
  const ingress = nodesOfType(map, 'INGRESS').length;
  if (structural > 20 && ingress <= 2 && methodAssignments >= 5) return true;

  return false;
}

/**
 * Check if tainted data flows from source to sink without passing through a CONTROL node.
 * Uses composite visited keys (nodeId:passedControl) to prevent safe-path pruning —
 * if a safe path (through CONTROL) reaches a node first, BFS must still explore the
 * unsafe path to that same node. Only follows data-flow edges (DATA_FLOW, CALLS,
 * READS, WRITES, RETURNS) — structural containment (CONTAINS) and dependency
 * (DEPENDS) edges are excluded because they do not represent data movement.
 */
function hasTaintedPathWithoutControl(
  map: NeuralMap,
  sourceId: string,
  sinkId: string,
): boolean {
  // BFS from source, following flow edges, tracking whether we pass through CONTROL
  const nodeMap = new Map(map.nodes.map(n => [n.id, n]));
  const visited = new Set<string>();
  const queue: Array<{ nodeId: string; passedControl: boolean }> = [
    { nodeId: sourceId, passedControl: false },
  ];

  while (queue.length > 0) {
    const { nodeId, passedControl } = queue.shift()!;
    const visitKey = `${nodeId}:${passedControl}`;
    if (visited.has(visitKey)) continue;
    visited.add(visitKey);

    const node = nodeMap.get(nodeId);
    if (!node) continue;

    // Check if this node is CONTROL (validation/sanitization)
    const controlNow = passedControl || node.node_type === 'CONTROL';

    // Reached the sink
    if (nodeId === sinkId) {
      // If we got here WITHOUT passing through CONTROL, the path is vulnerable
      if (!controlNow) return true;
      continue;
    }

    // Follow only data-flow edges
    for (const edge of node.edges) {
      if (!FLOW_EDGE_TYPES.has(edge.edge_type)) continue;
      const edgeKey = `${edge.target}:${controlNow}`;
      if (!visited.has(edgeKey)) {
        queue.push({ nodeId: edge.target, passedControl: controlNow });
      }
    }
  }

  // No uncontrolled path found — not vulnerable via this source→sink pair
  return false;
}

/** Check if any data_in on the sink has tainted=true from a source */
function sinkReceivesTaintedData(sink: NeuralMapNode): boolean {
  return sink.data_in.some(d => d.tainted);
}

/**
 * Check if tainted data flows from source to sink without passing through an AUTH node.
 * Same BFS as hasTaintedPathWithoutControl but gates on AUTH instead of CONTROL.
 * Uses composite visited keys and only follows data-flow edges.
 */
function hasTaintedPathWithoutAuth(
  map: NeuralMap,
  sourceId: string,
  sinkId: string,
): boolean {
  const nodeMap = new Map(map.nodes.map(n => [n.id, n]));
  const visited = new Set<string>();
  const queue: Array<{ nodeId: string; passedAuth: boolean }> = [
    { nodeId: sourceId, passedAuth: false },
  ];

  while (queue.length > 0) {
    const { nodeId, passedAuth } = queue.shift()!;
    const visitKey = `${nodeId}:${passedAuth}`;
    if (visited.has(visitKey)) continue;
    visited.add(visitKey);

    const node = nodeMap.get(nodeId);
    if (!node) continue;

    const authNow = passedAuth || node.node_type === 'AUTH';

    if (nodeId === sinkId) {
      if (!authNow) return true;
      continue;
    }

    for (const edge of node.edges) {
      if (!FLOW_EDGE_TYPES.has(edge.edge_type)) continue;
      const edgeKey = `${edge.target}:${authNow}`;
      if (!visited.has(edgeKey)) {
        queue.push({ nodeId: edge.target, passedAuth: authNow });
      }
    }
  }

  return false;
}

/**
 * Check if there is ANY path from source to sink without passing through a CONTROL node.
 * Unlike hasTaintedPathWithoutControl, this does not require taint — it checks structural flow.
 * Used for CWE-200 where the source is STORAGE (not user input).
 * Uses composite visited keys and only follows data-flow edges.
 */
function hasPathWithoutControl(
  map: NeuralMap,
  sourceId: string,
  sinkId: string,
): boolean {
  const nodeMap = new Map(map.nodes.map(n => [n.id, n]));
  const visited = new Set<string>();
  const queue: Array<{ nodeId: string; passedControl: boolean }> = [
    { nodeId: sourceId, passedControl: false },
  ];

  while (queue.length > 0) {
    const { nodeId, passedControl } = queue.shift()!;
    const visitKey = `${nodeId}:${passedControl}`;
    if (visited.has(visitKey)) continue;
    visited.add(visitKey);

    const node = nodeMap.get(nodeId);
    if (!node) continue;

    const controlNow = passedControl || node.node_type === 'CONTROL';

    if (nodeId === sinkId) {
      if (!controlNow) return true;
      continue;
    }

    for (const edge of node.edges) {
      if (!FLOW_EDGE_TYPES.has(edge.edge_type)) continue;
      const edgeKey = `${edge.target}:${controlNow}`;
      if (!visited.has(edgeKey)) {
        queue.push({ nodeId: edge.target, passedControl: controlNow });
      }
    }
  }

  return false;
}

/**
 * Find the containing function (STRUCTURAL node) for a given node by walking
 * CONTAINS edges backwards. Returns the STRUCTURAL parent's id, or null.
 */
function findContainingFunction(map: NeuralMap, nodeId: string): string | null {
  // Look for a STRUCTURAL node that has a CONTAINS edge pointing to this node
  for (const n of map.nodes) {
    if (n.node_type === 'STRUCTURAL') {
      for (const edge of n.edges) {
        if (edge.target === nodeId && edge.edge_type === 'CONTAINS') {
          return n.id;
        }
      }
    }
  }
  return null;
}

/**
 * Check if two nodes share a common function scope.
 * Uses two strategies:
 *   1. Direct CONTAINS edge matching (both contained by the same STRUCTURAL node)
 *   2. Line-range containment (both within the line range of the same function STRUCTURAL node)
 * Strategy 2 handles cases where destructured parameters create INGRESS nodes
 * that aren't properly linked via CONTAINS edges.
 */
function sharesFunctionScope(map: NeuralMap, nodeIdA: string, nodeIdB: string): boolean {
  const nodeMap = new Map(map.nodes.map(n => [n.id, n]));
  const nodeA = nodeMap.get(nodeIdA);
  const nodeB = nodeMap.get(nodeIdB);
  if (!nodeA || !nodeB) return false;

  // Strategy 1: Direct CONTAINS edge matching
  const getAncestors = (nodeId: string): Set<string> => {
    const ancestors = new Set<string>();
    for (const n of map.nodes) {
      if (n.node_type === 'STRUCTURAL') {
        for (const edge of n.edges) {
          if (edge.target === nodeId && edge.edge_type === 'CONTAINS') {
            ancestors.add(n.id);
          }
        }
      }
    }
    return ancestors;
  };

  const ancestorsA = getAncestors(nodeIdA);
  const ancestorsB = getAncestors(nodeIdB);
  for (const a of ancestorsA) {
    if (ancestorsB.has(a)) return true;
  }

  // Strategy 2: Line-range containment
  // Find STRUCTURAL/function nodes whose line range encompasses both nodes
  const funcNodes = map.nodes.filter(n =>
    n.node_type === 'STRUCTURAL' &&
    (n.node_subtype === 'function' || n.node_subtype === 'route_def' ||
     n.code_snapshot.match(/\bfunction\b|\b=>\b/i) !== null)
  );

  for (const func of funcNodes) {
    const funcStart = func.line_start;
    const funcEnd = func.line_end;

    // Both nodes must be within the function's line range
    if (nodeA.line_start >= funcStart && nodeA.line_start <= funcEnd &&
        nodeB.line_start >= funcStart && nodeB.line_start <= funcEnd) {
      return true;
    }
  }

  return false;
}

// ---------------------------------------------------------------------------
// CWE Verification Paths
// ---------------------------------------------------------------------------

/**
 * CWE-89: SQL Injection
 * Pattern: INGRESS → STORAGE(sql) without CONTROL(parameterization)
 * Property: All database queries use parameterized statements when handling user input
 */
function verifyCWE89(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const storage = map.nodes.filter(n =>
    n.node_type === 'STORAGE' &&
    (n.node_subtype.includes('sql') || n.node_subtype.includes('query') ||
     n.node_subtype.includes('db_read') || n.node_subtype.includes('db_write') ||
     n.attack_surface.includes('sql_sink') ||
     n.code_snapshot.match(/\b(query|exec|execute\w*|prepare|raw)\s*\(/i) !== null)
  );

  for (const src of ingress) {
    for (const sink of storage) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // Check if the sink or containing scope uses parameterized queries
        const scopeSnapshots = getContainingScopeSnapshots(map, sink.id);
        const combinedScope = stripComments(scopeSnapshots.join('\n') || sink.code_snapshot);
        const isParameterized = combinedScope.match(
          /\$\d|\?\s*[,)]|\bprepare\b|\bparameterized\b|\bplaceholder/i
        ) !== null;

        if (!isParameterized) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (input validation or parameterized query)',
            severity: 'critical',
            description: `User input from ${src.label} flows to SQL query at ${sink.label} without parameterization. ` +
              `Tainted data reaches the query builder directly.`,
            fix: 'Use parameterized queries (prepared statements) instead of string concatenation. ' +
              'Example: db.query("SELECT * FROM users WHERE id = $1", [userId]) instead of ' +
              'db.query("SELECT * FROM users WHERE id = " + userId)',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-89',
    name: 'SQL Injection',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-79: Cross-Site Scripting (XSS)
 * Pattern: INGRESS → EGRESS(html/response) without CONTROL(encoding)
 * Property: All user input is encoded before being included in HTML output
 */
function verifyCWE79(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const egress = map.nodes.filter(n =>
    // EGRESS nodes that produce HTML output
    (n.node_type === 'EGRESS' &&
    (n.node_subtype.includes('html') || n.node_subtype.includes('response') ||
     n.node_subtype.includes('render') || n.node_subtype.includes('display') ||
     n.attack_surface.includes('html_output') ||
     n.code_snapshot.match(/\b(innerHTML|render|send|write|res\.send|\.body\s*\(|echo|print)\b/i) !== null)) ||
    // EXTERNAL nodes that produce HTML via template engines (render_template_string, Jinja2, etc.)
    (n.node_type === 'EXTERNAL' &&
    (n.node_subtype.includes('template_exec') ||
     n.code_snapshot.match(/\b(render_template_string|render_template|Template)\b/i) !== null))
  );

  for (const src of ingress) {
    for (const sink of egress) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const scopeSnapshots = getContainingScopeSnapshots(map, sink.id);
        const combinedScope = stripComments(scopeSnapshots.join('\n') || sink.code_snapshot);
        const isEncoded = combinedScope.match(
          /\bescape\s*\(|\bescapeHtml\b|\bencode\s*\(|\bencodeURI\b|\bsanitize\s*\(|\bDOMPurify\b|\btextContent\b/i
        ) !== null;

        // JSON responses are not vulnerable to XSS — Content-Type: application/json
        // prevents browser script execution. Detect .send({...}), .json({...}), res.json()
        const sinkCode = stripComments(sink.code_snapshot);
        const isJsonResponse = sinkCode.match(
          /\.send\s*\(\s*\{|\.json\s*\(\s*\{|\.json\s*\(|res\.send\s*\(\s*\{|reply\.send\s*\(\s*\{|response\.json\s*\(/i
        ) !== null;

        if (!isEncoded && !isJsonResponse) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (output encoding or sanitization)',
            severity: 'high',
            description: `User input from ${src.label} is reflected in HTML output at ${sink.label} without encoding. ` +
              `This allows script injection.`,
            fix: 'Encode output for the target context. Use textContent instead of innerHTML. ' +
              'Use a sanitizer like DOMPurify for rich text. Never trust user input in HTML.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-79',
    name: 'Cross-Site Scripting (XSS)',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-22: Path Traversal
 * Pattern: INGRESS → STORAGE(filesystem) without CONTROL(path validation)
 * Property: All file operations validate that paths stay within allowed directories
 */
function verifyCWE22(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const fileOps = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' &&
     (n.node_subtype.includes('file') || n.node_subtype.includes('fs') ||
      n.attack_surface.includes('file_access') ||
      n.code_snapshot.match(/\b(readFile|writeFile|createReadStream|open|unlink|readdir)\b/i) !== null)) ||
    // Python: open(filename) is classified as INGRESS/file_read, not STORAGE/file
    (n.node_type === 'INGRESS' && n.node_subtype === 'file_read') ||
    // Go: http.ServeFile serves file content from a user-controlled path
    (n.node_type === 'EGRESS' && n.node_subtype === 'file_serve')
  );

  for (const src of ingress) {
    for (const sink of fileOps) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const scopeSnapshots = getContainingScopeSnapshots(map, sink.id);
        const combinedScope = stripComments(scopeSnapshots.join('\n') || sink.code_snapshot);
        const isValidated = combinedScope.match(
          /\bpath\.resolve\b|\bpath\.normalize\b|\bstartsWith\b|\b\.\.\/\b|\bsanitize.*path/i
        ) !== null;

        if (!isValidated) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (path validation / directory restriction)',
            severity: 'high',
            description: `User input from ${src.label} controls a file path at ${sink.label} without validation. ` +
              `An attacker can use ../../ to access files outside the intended directory.`,
            fix: 'Resolve the full path with path.resolve(), then verify it starts with your allowed base directory. ' +
              'Never use user input directly in file operations.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-22',
    name: 'Path Traversal',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-502: Deserialization of Untrusted Data
 * Pattern: INGRESS → TRANSFORM(deserialize) without CONTROL(type validation)
 * Property: All deserialization of user input uses safe parsers with type constraints
 */
function verifyCWE502(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const deserialize = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' &&
     (n.node_subtype.includes('deserialize') || n.node_subtype.includes('parse') ||
      n.code_snapshot.match(/\b(unserialize|pickle\.load|yaml\.load|eval|JSON\.parse)\b/i) !== null)) ||
    // Python: pickle.loads is classified as EXTERNAL/deserialize, not TRANSFORM
    (n.node_type === 'EXTERNAL' && n.node_subtype === 'deserialize') ||
    // Rust: serde_json::from_str etc. are classified as INGRESS/deserialize
    (n.node_type === 'INGRESS' && n.node_subtype === 'deserialize')
  );

  for (const src of ingress) {
    for (const sink of deserialize) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // EXTERNAL/deserialize nodes are inherently dangerous (yaml.load, pickle.loads, etc.)
        // TRANSFORM/parse nodes need code_snapshot check to distinguish safe vs unsafe
        const isDangerous =
          (sink.node_type === 'EXTERNAL' && sink.node_subtype === 'deserialize') ||
          // Rust: serde_json::from_str/from_value/from_slice on untrusted INGRESS data
          (sink.node_type === 'INGRESS' && sink.node_subtype === 'deserialize') ||
          sink.code_snapshot.match(
            /\b(unserialize|pickle\.load|yaml\.load|yaml\.loadAll|eval|Function\s*\(|deserialize|serde_json::from_str|serde_json::from_value|serde_json::from_slice)\b/i
          ) !== null;

        if (isDangerous) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (safe deserialization with type constraints)',
            severity: 'critical',
            description: `User input from ${src.label} is deserialized at ${sink.label} using an unsafe method. ` +
              `This can lead to arbitrary code execution.`,
            fix: 'Use safe parsers: JSON.parse for JSON, yaml.safeLoad / yaml.safe_load for YAML. ' +
              'Never use eval, unserialize, pickle.load, or yaml.load on untrusted data. ' +
              'Add schema validation (zod, joi) after parsing.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-502',
    name: 'Deserialization of Untrusted Data',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-918: Server-Side Request Forgery (SSRF)
 * Pattern: INGRESS → EXTERNAL without CONTROL(URL validation)
 * Property: All user-controlled URLs are validated against an allowlist before making requests
 */
function verifyCWE918(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const external = map.nodes.filter(n =>
    n.node_type === 'EXTERNAL' &&
    (n.node_subtype.includes('http') || n.node_subtype.includes('request') ||
     n.node_subtype.includes('fetch') || n.node_subtype.includes('api_call') ||
     n.code_snapshot.match(/\b(fetch|axios|request|http\.get|https\.get|got|requests\.get|requests\.post|requests\.put|requests\.delete|urllib\.request)\b/i) !== null)
  );

  for (const src of ingress) {
    for (const sink of external) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const scopeSnapshots = getContainingScopeSnapshots(map, sink.id);
        const combinedScope = stripComments(scopeSnapshots.join('\n') || sink.code_snapshot);
        const isValidated = combinedScope.match(
          /\ballowlist\b|\bwhitelist\b|\bvalidateUrl\b|\bURL\b.*\bnew\b|\bstartsWith\b/i
        ) !== null;

        if (!isValidated) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (URL validation / allowlist)',
            severity: 'high',
            description: `User input from ${src.label} controls the URL for an HTTP request at ${sink.label}. ` +
              `An attacker can make the server request internal resources (SSRF).`,
            fix: 'Validate URLs against an allowlist of permitted domains. ' +
              'Parse the URL with new URL() and check the hostname. ' +
              'Never let user input directly control request destinations.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-918',
    name: 'Server-Side Request Forgery (SSRF)',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-798: Hardcoded Credentials
 * Pattern: META missing — secrets embedded directly in source code
 * Property: No hardcoded passwords, API keys, or tokens in source code
 *
 * Unlike flow-based CWEs, this is a static scan: walk all nodes looking
 * for credential patterns in code_snapshot, flagging any node that lacks
 * a corresponding META(env_ref) node indicating the value comes from
 * an external secret store.
 */
function verifyCWE798(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Patterns that indicate hardcoded secrets
  const secretPatterns = [
    /(?:password|passwd|pwd)\s*[:=]\s*['"][^'"]{4,}['"]/i,
    /(?:api[_-]?key|apikey)\s*[:=]\s*['"][^'"]{8,}['"]/i,
    /(?:secret|token)\s*[:=]\s*['"][^'"]{8,}['"]/i,
    /(?:access[_-]?key|auth[_-]?token)\s*[:=]\s*['"][^'"]{8,}['"]/i,
    /(?:private[_-]?key)\s*[:=]\s*['"][^'"]{8,}['"]/i,
    /(?:connection[_-]?string)\s*[:=]\s*['"][^'"]{8,}['"]/i,
    // Rust/Go/Kotlin: const/static with credential-like names (allow prefixes like JWT_SECRET, DB_PASSWORD)
    /(?:const|static|val|var)\s+\w*(?:PASSWORD|SECRET|API_KEY|TOKEN|AUTH_TOKEN|PRIVATE_KEY|ACCESS_KEY)\w*\s*[=:][^=].*['"][^'"]{4,}['"]/i,
    // Module-scope credential assignments: UPPER_CASE names with string literals
    /\b(?:PASS|SECRET|KEY|TOKEN|CRED)\w*\s*=\s*['"][^'"]{4,}['"]/,
  ];

  // Safe patterns that suppress findings
  const safePatterns = [
    /process\.env\b/,
    /config\.get\s*\(/,
    /\benv\s*\(/,
    /\bvault\b/,
    /\bsecretManager\b/,
    /\byour_|\$\{|<[A-Z]|\bREPLACE\b|\bCHANGEME\b|\bTODO\b|\bEXAMPLE\b|\bTEST\b|\bPLACEHOLDER\b/i,
  ];

  // Check if there's a META node that marks this value as env-sourced
  const metaNodes = nodesOfType(map, 'META');
  const envRefs = new Set(
    metaNodes
      .filter(n => n.node_subtype.includes('env_ref') || n.node_subtype.includes('secret_ref') ||
        n.code_snapshot.match(/\bprocess\.env\b|\benv\(\b|\bvault\b|\bsecretManager/i) !== null)
      .flatMap(n => n.edges.map(e => e.target))
  );

  // Phase 1: scan all neural map nodes (catches in-function and config_value nodes)
  for (const node of map.nodes) {
    // Skip META nodes — except config_value nodes which may contain hardcoded creds
    if (node.node_type === 'META' && node.node_subtype !== 'config_value') continue;
    // Skip nodes that are known to source from env
    if (envRefs.has(node.id)) continue;

    for (const pattern of secretPatterns) {
      if (pattern.test(node.code_snapshot)) {
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'META (external secret reference — environment variable, vault, or secret manager)',
          severity: 'critical',
          description: `Hardcoded credential found in ${node.label}. ` +
            `Secrets in source code can be leaked via version control, logs, or build artifacts.`,
          fix: 'Move secrets to environment variables or a secret manager. ' +
            'Use process.env.SECRET_NAME or a vault client. ' +
            'Never commit secrets to source control.',
        });
        break; // One finding per node is enough
      }
    }
  }

  // Phase 2: module-scope fallback — scan raw source_code line by line.
  // Module-scope const/var declarations are NOT emitted as neural map nodes
  // by the tree-sitter mapper, so the node walk above misses them entirely.
  // This fallback catches `const DB_PASSWORD = "secret"` at the top level.
  if (map.source_code) {
    const lines = map.source_code.split('\n');
    // Build a set of code already flagged by Phase 1 (node scan) so we don't double-report.
    // Use normalized (trimmed, semicolon-stripped) comparison to handle minor formatting differences.
    const phase1Snippets = findings.map(f => f.source.code.trim().replace(/;$/, ''));

    // Helper: check if a line was already covered by a Phase 1 finding
    const alreadyCoveredByNodeScan = (lineContent: string): boolean => {
      const norm = lineContent.trim().replace(/;$/, '');
      return phase1Snippets.some(s => s.includes(norm) || norm.includes(s));
    };

    const alreadyFlaggedLines = new Set<number>();

    lines.forEach((line, idx) => {
      const trimmed = line.trim();
      // Skip blank lines and pure comment lines
      if (!trimmed || trimmed.startsWith('//') || trimmed.startsWith('#') || trimmed.startsWith('*')) return;
      // Skip lines that use safe sourcing patterns
      if (safePatterns.some(sp => sp.test(line))) return;
      // Skip if already covered by Phase 1 node scan
      if (alreadyCoveredByNodeScan(line)) return;

      for (const pattern of secretPatterns) {
        if (pattern.test(line)) {
          if (alreadyFlaggedLines.has(idx)) break;
          alreadyFlaggedLines.add(idx);
          const snippet = line.trim().slice(0, 200);
          findings.push({
            source: { id: `module-scope-line-${idx + 1}`, label: `module-scope (line ${idx + 1})`, line: idx + 1, code: snippet },
            sink:   { id: `module-scope-line-${idx + 1}`, label: `module-scope (line ${idx + 1})`, line: idx + 1, code: snippet },
            missing: 'META (external secret reference — environment variable, vault, or secret manager)',
            severity: 'critical',
            description: `Hardcoded credential at module scope (line ${idx + 1}). ` +
              `Secrets in source code can be leaked via version control, logs, or build artifacts.`,
            fix: 'Move secrets to environment variables or a secret manager. ' +
              'Use process.env.SECRET_NAME or a vault client. ' +
              'Never commit secrets to source control.',
          });
          break; // One finding per line is enough
        }
      }
    });
  }

  return {
    cwe: 'CWE-798',
    name: 'Hardcoded Credentials',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-306: Missing Authentication
 * Pattern: INGRESS → sensitive operation (STORAGE/EXTERNAL) without AUTH
 * Property: All sensitive operations are gated by authentication checks
 *
 * Similar to CONTROL-gating but checks specifically for AUTH nodes.
 */
function verifyCWE306(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const sensitive = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'EXTERNAL') &&
    (n.attack_surface.includes('sensitive') || n.attack_surface.includes('admin') ||
     n.attack_surface.includes('write') || n.attack_surface.includes('delete') ||
     n.node_subtype.includes('write') || n.node_subtype.includes('delete') ||
     n.node_subtype.includes('admin') || n.node_subtype.includes('update') ||
     n.code_snapshot.match(/\b(delete|remove|update|insert|drop|admin|modify|destroy)\b/i) !== null)
  );

  for (const src of ingress) {
    for (const sink of sensitive) {
      if (hasTaintedPathWithoutAuth(map, src.id, sink.id)) {
        findings.push({
          source: nodeRef(src),
          sink: nodeRef(sink),
          missing: 'AUTH (authentication check before sensitive operation)',
          severity: 'critical',
          description: `Request from ${src.label} reaches sensitive operation ${sink.label} without authentication. ` +
            `An unauthenticated attacker can perform privileged actions.`,
          fix: 'Add authentication middleware before sensitive routes. ' +
            'Use session tokens, JWTs, or API keys to verify identity. ' +
            'Example: app.delete("/users/:id", requireAuth, handler)',
        });
      }
    }
  }

  return {
    cwe: 'CWE-306',
    name: 'Missing Authentication',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-200: Information Exposure
 * Pattern: STORAGE → EGRESS without CONTROL (data filtering/redaction)
 * Property: Sensitive data from storage is filtered before being sent to clients
 */
function verifyCWE200(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const storage = map.nodes.filter(n =>
    n.node_type === 'STORAGE' &&
    (n.data_out.some(d => d.sensitivity !== 'NONE') ||
     n.attack_surface.includes('sensitive_data') ||
     n.code_snapshot.match(/\b(password|ssn|credit.?card|token|secret|private|hash)\b/i) !== null)
  );
  const egress = nodesOfType(map, 'EGRESS');

  for (const src of storage) {
    for (const sink of egress) {
      if (hasPathWithoutControl(map, src.id, sink.id)) {
        // Check if the egress node filters fields (strip comments to avoid bypass)
        const isFiltered = stripComments(sink.code_snapshot).match(
          /\bselect\s*\(|\bpick\s*\(|\bomit\s*\(|\b\.filter\s*\(|\bredact\s*\(|\bexclude\s*\(|\bsanitize\s*\(|\btoJSON\s*\(|\b\.map\s*\(/i
        ) !== null;

        if (!isFiltered) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (data filtering or field redaction)',
            severity: 'high',
            description: `Sensitive data from ${src.label} flows to ${sink.label} without filtering. ` +
              `Internal fields (passwords, tokens, PII) may be exposed to clients.`,
            fix: 'Explicitly select which fields to return (allowlist pattern). ' +
              'Use DTO/view models to strip sensitive fields before sending. ' +
              'Never send raw database records directly to clients.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-200',
    name: 'Information Exposure',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-78: OS Command Injection
 * Pattern: INGRESS → EXTERNAL(shell/exec) without CONTROL(input sanitization)
 * Property: User input is never passed directly to shell commands
 */
function verifyCWE78(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const shellExec = map.nodes.filter(n =>
    n.node_type === 'EXTERNAL' &&
    (n.node_subtype.includes('shell') || n.node_subtype.includes('exec') ||
     n.node_subtype.includes('command') || n.attack_surface.includes('shell_exec') ||
     n.code_snapshot.match(/\b(exec|execSync|spawn|system|child_process|popen|shell_exec)\b/i) !== null)
  );

  for (const src of ingress) {
    for (const sink of shellExec) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // Check if the command uses safe patterns (strip comments to avoid bypass)
        const isSafe = stripComments(sink.code_snapshot).match(
          /\bexecFile\b|\bspawn\b.*\[|\bshellEscape\b|\bescapeShell\b|\bsanitize\s*\(/i
        ) !== null;

        if (!isSafe) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (input sanitization or safe command API)',
            severity: 'critical',
            description: `User input from ${src.label} flows to shell command at ${sink.label} without sanitization. ` +
              `An attacker can inject arbitrary OS commands (e.g., ; rm -rf /).`,
            fix: 'Never pass user input to shell commands. Use execFile or spawn with an argument array ' +
              'instead of exec with string interpolation. If shell is unavoidable, use a strict allowlist ' +
              'of permitted values.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-78',
    name: 'OS Command Injection',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-611: XML External Entity (XXE)
 * Pattern: INGRESS → TRANSFORM(xml) without CONTROL(parser configuration)
 * Property: XML parsers disable external entity processing when handling user input
 */
function verifyCWE611(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // XML parser regex — matches across TRANSFORM, EXTERNAL, and STORAGE nodes
  const xmlParserPattern = /\b(parseXml|parseXmlString|parseXML|DOMParser|SAXParser|xml2js|libxml|libxmljs2?|etree\.parse|etree\.fromstring|xml\.sax|minidom\.parseString|XmlReader|ElementTree\.parse|lxml\.etree|parseFromString)\b/i;
  const xmlParsers = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL' || n.node_type === 'STORAGE') &&
    (n.node_subtype.includes('xml') || n.node_subtype.includes('xpath') ||
     n.attack_surface.includes('xml_parse') ||
     xmlParserPattern.test(n.code_snapshot))
  );

  // Dangerous XML parser configurations that ENABLE XXE
  // libxmljs: parseXmlString(data, {noent:true}) — noent:true substitutes entities (DANGEROUS)
  // xml2js: explicitCharkey enables character key processing (DANGEROUS with crafted XML)
  const dangerousXmlConfigPattern = /noent\s*:\s*true|explicitCharkey/i;

  for (const src of ingress) {
    for (const sink of xmlParsers) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // Check if the parser is configured dangerously (explicit XXE-enabling config)
        // Strip comments so dangerous config in comments doesn't misfire
        const sinkCodeOnly = stripComments(sink.code_snapshot);
        const hasDangerousConfig = dangerousXmlConfigPattern.test(sinkCodeOnly);

        // Check if external entities are properly disabled
        const isSecure = !hasDangerousConfig && sinkCodeOnly.match(
          /\bnoent\s*:\s*false\b|\bdisable.*entity\b|\bresolveEntities\s*:\s*false\b|\bXMLReader.*FEATURE.*external.*false\b|\bdefusedxml\b|\bsafe.*parse/i
        ) !== null;

        if (!isSecure) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (XML parser security configuration — disable external entities)',
            severity: 'high',
            description: `User-supplied XML from ${src.label} is parsed at ${sink.label} without disabling external entities. ` +
              (hasDangerousConfig
                ? `The parser is configured with dangerous options (noent:true or explicitCharkey) that enable entity expansion.`
                : `An attacker can read local files, perform SSRF, or cause denial of service via entity expansion.`),
            fix: 'Disable external entity processing in the XML parser configuration. ' +
              'Use defusedxml (Python), set resolveEntities: false, or use noent: false. ' +
              'For libxmljs: NEVER use {noent:true}. Consider using JSON instead of XML where possible.',
          });
        }
      }
    }
  }

  // Secondary check: XML parsing with dangerous config inside vm.runInContext or similar
  // code execution sinks. The taint flows through a sandbox object literal which breaks
  // the normal BFS taint path. Detect: any EXTERNAL/system_exec node whose code_snapshot
  // contains XML parsing with dangerous config, when INGRESS nodes exist in the same graph.
  if (findings.length === 0 && ingress.length > 0) {
    const execWithXml = map.nodes.filter(n =>
      n.node_type === 'EXTERNAL' &&
      n.node_subtype === 'system_exec' &&
      xmlParserPattern.test(n.code_snapshot) &&
      dangerousXmlConfigPattern.test(n.code_snapshot)
    );

    for (const execNode of execWithXml) {
      // Check if the exec node is in the same function scope as an INGRESS node
      const ingressInScope = ingress.find(src =>
        sharesFunctionScope(map, src.id, execNode.id)
      );

      if (ingressInScope) {
        const closestIngress = ingressInScope;
        findings.push({
          source: nodeRef(closestIngress),
          sink: nodeRef(execNode),
          missing: 'CONTROL (XML parser security configuration — disable external entities)',
          severity: 'critical',
          description: `User-supplied data from ${closestIngress.label} reaches XML parsing inside ${execNode.label} with dangerous configuration. ` +
            `The parser is configured with noent:true or explicitCharkey inside a code execution sink (vm.runInContext), enabling entity expansion.`,
          fix: 'Disable external entity processing in the XML parser configuration. ' +
            'NEVER use {noent:true} with libxmljs/libxmljs2. ' +
            'Use noent: false or remove the noent option entirely.',
        });
      }
    }
  }

  return {
    cwe: 'CWE-611',
    name: 'XML External Entity (XXE)',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-94: Code Injection
 * Pattern: INGRESS → EXTERNAL(system_exec) without CONTROL, where code_snapshot contains eval/exec/Function
 * Property: User input is never passed to code evaluation functions
 */
function verifyCWE94(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const vmExecPattern = /\b(eval|exec|compile|Function\s*\(|execScript|setInterval|setTimeout|vm\.run|vm\.compile|vm\.create|runInContext|runInNewContext|runInThisContext|compileFunction|ejs\.render|pug\.render|nunjucks\.render)\b/i;
  const codeExec = map.nodes.filter(n =>
    n.node_type === 'EXTERNAL' &&
    (n.node_subtype.includes('system_exec') || n.node_subtype.includes('exec') ||
     n.node_subtype.includes('eval') || n.node_subtype.includes('template_exec')) &&
    vmExecPattern.test(n.code_snapshot)
  );

  for (const src of ingress) {
    for (const sink of codeExec) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // "sandbox" and "safeEval" are NOT safe for vm.runInContext --
        // vm modules execute arbitrary code even inside sandbox contexts.
        // Only treat as safe if it's ast.literal_eval or JSON.parse (truly safe parsers).
        const sinkCodeOnly94 = stripComments(sink.code_snapshot);
        const isVmExec = /\bvm\.|runInContext|runInNewContext|runInThisContext|compileFunction\b/i.test(sinkCodeOnly94);
        const isSafe = !isVmExec && sinkCodeOnly94.match(
          /\bsandbox\b|\bsafe.*eval\b|\bast\.literal_eval\b|\bJSON\.parse\b/i
        ) !== null;

        if (!isSafe) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (input validation or sandboxed evaluation)',
            severity: 'critical',
            description: `User input from ${src.label} flows to code evaluation at ${sink.label} without sanitization. ` +
              (isVmExec
                ? `Node.js vm module does NOT provide a security sandbox -- user-controlled data in vm.runInContext enables arbitrary code execution.`
                : `An attacker can execute arbitrary code on the server.`),
            fix: isVmExec
              ? 'NEVER use vm.runInContext/runInNewContext with user-controlled data. ' +
                'The Node.js vm module is NOT a security mechanism. ' +
                'Use a true sandbox (vm2, isolated-vm) or avoid dynamic code evaluation entirely.'
              : 'Never pass user input to eval(), exec(), or Function(). ' +
                'Use ast.literal_eval() for Python or JSON.parse() for JSON data. ' +
                'If dynamic evaluation is required, use a sandboxed environment with strict allowlists.',
          });
        }
      }
    }
  }

  // Secondary check: vm.runInContext/runInNewContext where taint flows through
  // object literals (sandbox pattern). The pattern is:
  //   const data = req.body.x;              // tainted
  //   const sandbox = { safeEval, data };   // object literal contains tainted var
  //   vm.runInContext('safeEval(data)', sandbox);  // taint reaches code exec via sandbox
  // BFS doesn't find this because the object literal breaks the edge chain.
  // Detect: vm.* EXTERNAL nodes that reference variables also referenced by INGRESS,
  // when both are in the same function scope.
  if (findings.length === 0 && ingress.length > 0) {
    const vmNodes = codeExec.filter(n =>
      /\bvm\.|runInContext|runInNewContext|runInThisContext\b/i.test(n.code_snapshot)
    );

    for (const vmNode of vmNodes) {
      // Check if any INGRESS node shares a function scope with this vm node
      for (const src of ingress) {
        if (sharesFunctionScope(map, src.id, vmNode.id)) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(vmNode),
            missing: 'CONTROL (input validation or sandboxed evaluation)',
            severity: 'critical',
            description: `User input from ${src.label} is accessible within the vm execution context at ${vmNode.label}. ` +
              `Node.js vm module does NOT provide a security sandbox -- user-controlled data passed through object literals (sandbox pattern) enables arbitrary code execution.`,
            fix: 'NEVER use vm.runInContext/runInNewContext with user-controlled data. ' +
              'The Node.js vm module is NOT a security mechanism. ' +
              'Use a true sandbox (vm2, isolated-vm) or avoid dynamic code evaluation entirely.',
          });
          break; // One finding per vm node is sufficient
        }
      }
    }
  }

  // Tertiary check: When TypeScript type annotations cause the JS parser to
  // swallow destructured request parameters into ERROR nodes (0 INGRESS nodes),
  // but the function clearly handles HTTP request data (body, params, query)
  // and passes it to vm.*. Detect by code_snapshot analysis of sibling nodes.
  if (findings.length === 0 && ingress.length === 0) {
    const vmNodes = codeExec.filter(n =>
      /\bvm\.|runInContext|runInNewContext|runInThisContext\b/i.test(n.code_snapshot)
    );

    for (const vmNode of vmNodes) {
      // Find the containing function by line range
      const containingFunc = map.nodes.find(n =>
        n.node_type === 'STRUCTURAL' &&
        n.node_subtype === 'function' &&
        n.line_start <= vmNode.line_start &&
        n.line_end >= vmNode.line_start &&
        // Must be an Express-like handler (references body, params, query, req)
        /\b(body|params|query|req\b|Request)\b/i.test(n.code_snapshot)
      );

      if (containingFunc) {
        // Check if any sibling node in the same function references request data
        const requestDataPattern = /\bbody\.([\w]+)|\breq\.(body|params|query|headers)\b|\brequest\.(body|params|query)\b/i;
        const hasRequestData = map.nodes.some(n =>
          n.line_start >= containingFunc.line_start &&
          n.line_start <= containingFunc.line_end &&
          requestDataPattern.test(n.code_snapshot)
        );

        if (hasRequestData) {
          findings.push({
            source: nodeRef(containingFunc),
            sink: nodeRef(vmNode),
            missing: 'CONTROL (input validation or sandboxed evaluation)',
            severity: 'critical',
            description: `HTTP request data is passed to code execution at ${vmNode.label} within ${containingFunc.label}. ` +
              `Node.js vm module does NOT provide a security sandbox -- user-controlled data in vm.runInContext enables arbitrary code execution.`,
            fix: 'NEVER use vm.runInContext/runInNewContext with user-controlled data. ' +
              'The Node.js vm module is NOT a security mechanism. ' +
              'Use a true sandbox (vm2, isolated-vm) or avoid dynamic code evaluation entirely.',
          });
          break;
        }
      }
    }
  }

  return {
    cwe: 'CWE-94',
    name: 'Code Injection',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-352: Cross-Site Request Forgery (CSRF)
 * Pattern: INGRESS → STORAGE(write) without CONTROL(csrf)
 * Property: All state-changing operations from user requests are protected by CSRF tokens
 */
function verifyCWE352(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Fix 2: Check for global CSRF middleware anywhere in the map
  const GLOBAL_CSRF_MW = /\bapp\.use\s*\(\s*(?:csrf|csurf)\s*\(|\bapp\.use\s*\(\s*(?:csrfProtection|csrfMiddleware)\b/i;
  const hasGlobalCsrfMiddleware = map.nodes.some(n => GLOBAL_CSRF_MW.test(stripComments(n.code_snapshot)));
  if (hasGlobalCsrfMiddleware) {
    return { cwe: 'CWE-352', name: 'Cross-Site Request Forgery (CSRF)', holds: true, findings };
  }

  // Fix 1: Broaden sink detection beyond raw SQL DML
  const STATE_CHANGE_PATTERN = /\b(transfer|delete|remove|update|create|send|pay|purchase|withdraw|admin)\b/i;
  const stateChanging = map.nodes.filter(n => {
    if (n.node_type === 'STORAGE') {
      if (n.node_subtype.includes('write') || n.node_subtype.includes('delete') ||
          n.node_subtype.includes('update') || n.node_subtype.includes('insert') ||
          n.node_subtype.includes('db_write') || n.node_subtype.includes('file_write') ||
          n.node_subtype.includes('cache_write') ||
          n.code_snapshot.match(/\b(INSERT|UPDATE|DELETE|CREATE|DROP|ALTER|TRUNCATE)\b/i) !== null) {
        return true;
      }
    }
    if (n.node_type === 'EGRESS') {
      return true;
    }
    if (n.node_type === 'TRANSFORM' && STATE_CHANGE_PATTERN.test(n.label + ' ' + n.code_snapshot)) {
      return true;
    }
    return false;
  });

  // CSRF-specific CONTROL check: look for CONTROL nodes with csrf-related labels
  function hasCsrfControl(map: NeuralMap, sourceId: string, sinkId: string): boolean {
    const nodeMap = new Map(map.nodes.map(n => [n.id, n]));
    const visited = new Set<string>();
    const queue: Array<{ nodeId: string; passedCsrf: boolean }> = [
      { nodeId: sourceId, passedCsrf: false },
    ];

    while (queue.length > 0) {
      const { nodeId, passedCsrf } = queue.shift()!;
      const visitKey = `${nodeId}:${passedCsrf}`;
      if (visited.has(visitKey)) continue;
      visited.add(visitKey);

      const node = nodeMap.get(nodeId);
      if (!node) continue;

      const isCsrf = node.node_type === 'CONTROL' &&
        (node.node_subtype.includes('csrf') || node.label.match(/csrf/i) !== null ||
         node.code_snapshot.match(/\bcsrf\b|\b_token\b|\bCSRFProtect\b|\bcsurf\b/i) !== null);
      const csrfNow = passedCsrf || isCsrf;

      if (nodeId === sinkId) {
        return csrfNow;
      }

      for (const edge of node.edges) {
        if (!FLOW_EDGE_TYPES.has(edge.edge_type)) continue;
        const edgeKey = `${edge.target}:${csrfNow}`;
        if (!visited.has(edgeKey)) {
          queue.push({ nodeId: edge.target, passedCsrf: csrfNow });
        }
      }
    }

    return false;
  }

  for (const src of ingress) {
    // Only check ingress from HTTP POST/PUT/DELETE (state-changing methods)
    const isStateChangingIngress = src.code_snapshot.match(
      /\b(post|put|delete|patch)\b/i
    ) !== null || src.node_subtype.includes('http');

    if (!isStateChangingIngress) continue;

    for (const sink of stateChanging) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id) && !hasCsrfControl(map, src.id, sink.id)) {
        findings.push({
          source: nodeRef(src),
          sink: nodeRef(sink),
          missing: 'CONTROL (CSRF token validation)',
          severity: 'high',
          description: `State-changing request from ${src.label} modifies data at ${sink.label} without CSRF protection. ` +
            `An attacker can forge requests from a victim's browser to perform unauthorized actions.`,
          fix: 'Add CSRF token validation middleware. Use csurf (Express), CSRFProtect (Flask), ' +
            'or framework-provided CSRF protection. Ensure all state-changing endpoints verify the token.',
        });
      }
    }
  }

  return {
    cwe: 'CWE-352',
    name: 'Cross-Site Request Forgery (CSRF)',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-1321: Prototype Pollution (Improperly Controlled Modification of Object Prototype Attributes)
 * Pattern: INGRESS → TRANSFORM(mass_assignment) without CONTROL
 * Property: User input is never used to set arbitrary object properties without allowlisting
 *
 * Primarily JS-specific (Object.assign, spread into user-controlled keys, lodash.merge),
 * but the pattern extends to any language with dynamic property assignment.
 */
function verifyCWE1321(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  // Only check languages with dynamic prototypes/object mutation
  const lang = map.language?.toLowerCase() ?? '';
  const PROTOTYPE_LANGUAGES = new Set(['javascript', 'typescript', 'python', 'ruby', 'php']);
  if (lang && !PROTOTYPE_LANGUAGES.has(lang)) {
    return { cwe: 'CWE-1321', name: 'Prototype Pollution', holds: true, findings: [] };
  }

  const massAssign = map.nodes.filter(n =>
    n.node_type === 'TRANSFORM' &&
    (n.node_subtype.includes('mass_assignment') || n.node_subtype.includes('merge') ||
     (n.node_subtype.includes('assign') && n.code_snapshot.match(/\bObject\.assign\b|\bmerge\b|\bextend\b|\b__dict__\b|\battr_accessor\b/i)) ||
     n.code_snapshot.match(/\bObject\.assign\b|\b\.merge\b|\b\.extend\b|\b\.\.\.\s*req\b|\bdeepMerge\b|\bdefaultsDeep\b/i) !== null)
  );

  for (const src of ingress) {
    for (const sink of massAssign) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const isSafe = stripComments(sink.code_snapshot).match(
          /\ballowlist\b|\bwhitelist\b|\bpick\s*\(|\bsanitize\s*\(|\bObject\.create\(null\)/i
        ) !== null;

        if (!isSafe) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (property allowlisting or safe merge)',
            severity: 'high',
            description: `User input from ${src.label} is merged into an object at ${sink.label} without property filtering. ` +
              `An attacker can inject __proto__ or constructor.prototype to pollute Object.prototype.`,
            fix: 'Never merge user input directly into objects. Use an allowlist of permitted keys. ' +
              'Use Object.create(null) for lookup objects. Avoid lodash.merge/defaultsDeep with untrusted data. ' +
              'Consider using Map instead of plain objects for dynamic keys.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-1321',
    name: 'Prototype Pollution',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-158: Improper Neutralization of Null Byte or NUL Character
 * Pattern: CONTROL(validation using includes/endsWith/match) → file operation,
 *          where the validation does not strip null bytes before checking.
 * Classic pattern: filename.includes('.js') passes for "file.js%00.txt"
 *
 * Also detects: INGRESS → file_read/file_write where validation occurs but
 * cutOffPoisonNullByte/replace(\x00) is called AFTER the validation check.
 */
function verifyCWE158(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Null byte sanitization patterns
  const nullByteSanitizePattern = /cutOffPoisonNullByte|replace\s*\(\s*['"`]?\\x00|replace\s*\(\s*['"`]?\\0|replace\s*\(\s*['"`]?%00|\bnull.*byte\b.*strip|\breplace.*\\x00/i;

  // File type validation patterns — broad: includes function calls that check file types
  const fileValidationPattern = /\b(endsWith|includes|match|test|indexOf|startsWith)\s*\(.*\.(md|pdf|xml|zip|jpg|png|gif|js|ts|txt|html|css|json|yml|yaml)/i;
  const fileValidationFnPattern = /\b(endsWithAllowlisted|allowlistedFileType|validFileType|checkFileType|isValidExtension|fileTypeCheck|acceptedFileType|isAllowedExt)/i;

  // Find nodes that do file type validation — both CONTROL nodes and any node in the graph
  const validationNodes = map.nodes.filter(n =>
    fileValidationPattern.test(n.code_snapshot) ||
    fileValidationFnPattern.test(n.code_snapshot)
  );

  // Find nodes that do null byte sanitization
  const sanitizeNodes = map.nodes.filter(n =>
    nullByteSanitizePattern.test(n.code_snapshot)
  );

  // File operation sinks
  const fileOps = map.nodes.filter(n =>
    (n.node_type === 'EGRESS' || n.node_type === 'INGRESS' || n.node_type === 'STORAGE') &&
    (n.node_subtype.includes('file') ||
     n.code_snapshot.match(/\b(sendFile|readFile|createReadStream|createWriteStream|writeFile|unlink|open|access|stat|path\.resolve)\s*\(/i) !== null)
  );

  // Pattern 1: File type validation exists, null byte sanitization exists,
  // but sanitization is AFTER the validation (wrong order).
  // This is the fileServer.ts pattern: endsWithAllowlistedFileType(file) -> cutOffPoisonNullByte(file)
  if (validationNodes.length > 0 && sanitizeNodes.length > 0) {
    for (const valNode of validationNodes) {
      for (const sanNode of sanitizeNodes) {
        // Sanitization happens AFTER validation (wrong order)
        if (sanNode.line_start > valNode.line_start) {
          // Check if there's NO sanitization BEFORE the validation
          const hasPreSanitize = sanitizeNodes.some(s => s.line_start < valNode.line_start);
          if (!hasPreSanitize) {
            const sourceNode = ingress.length > 0 ? ingress[0]! : valNode;
            findings.push({
              source: nodeRef(sourceNode),
              sink: nodeRef(sanNode),
              missing: 'TRANSFORM (null byte neutralization BEFORE validation, not after)',
              severity: 'high',
              description: `Null byte sanitization at ${sanNode.label} (line ${sanNode.line_start}) occurs AFTER filename validation at ${valNode.label} (line ${valNode.line_start}). ` +
                `An attacker can bypass the file type check with a poison null byte (e.g., "evil.txt%00.pdf" passes an endsWith(".pdf") check, then the null byte is stripped, serving "evil.txt").`,
              fix: 'Move null byte sanitization BEFORE the file type/extension validation. ' +
                'The correct order is: (1) strip null bytes, (2) validate file type, (3) perform file operation.',
            });
            break;
          }
        }
      }
      if (findings.length > 0) break;
    }
  }

  // Pattern 2: File type validation with file operation but NO null byte sanitization at all
  if (findings.length === 0 && validationNodes.length > 0 && sanitizeNodes.length === 0 && fileOps.length > 0) {
    for (const src of ingress) {
      for (const fileOp of fileOps) {
        if (src.id === fileOp.id) continue;
        // Check if there's a validation node between them
        const hasVal = validationNodes.some(v =>
          v.line_start >= src.line_start && v.line_start <= fileOp.line_start
        );
        if (hasVal) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(fileOp),
            missing: 'TRANSFORM (null byte neutralization before filename validation)',
            severity: 'high',
            description: `Filename from ${src.label} is validated using file type checks but null bytes are never stripped. ` +
              `An attacker can bypass the validation with a poison null byte (e.g., "malicious.txt%00.pdf").`,
            fix: 'Strip null bytes from filenames BEFORE validation. ' +
              'Use filename.replace(/\\0/g, "") or a dedicated function like cutOffPoisonNullByte(). ' +
              'Always sanitize null bytes before any file type or extension check.',
          });
          break;
        }
      }
      if (findings.length > 0) break;
    }
  }

  return {
    cwe: 'CWE-158',
    name: 'Improper Neutralization of Null Byte or NUL Character',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-384: Session Fixation
 * Pattern: AUTH(login/authenticate) → STORAGE/EGRESS(session write/redirect) without
 *          TRANSFORM(session regeneration like req.session.regenerate)
 * When a user authenticates, the session ID should be regenerated to prevent
 * an attacker from fixing the session ID before authentication.
 */
function verifyCWE384(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Auth/login patterns - look for authentication actions
  // The BCRYPT_AUTH_RE covers cases where bcrypt.compareSync appears in a CONTROL
  // node (if-condition) rather than as a standalone AUTH node.
  const BCRYPT_AUTH_RE = /\bbcrypt\.(compare|compareSync|hash|hashSync)\b/i;
  const authNodes = map.nodes.filter(n =>
    (n.node_type === 'AUTH' ||
     // Also check STRUCTURAL nodes that define login/auth routes
     (n.node_type === 'STRUCTURAL' && n.node_subtype === 'route_def') ||
     // CONTROL nodes that contain bcrypt auth checks (bcrypt.compareSync in if-condition)
     (n.node_type === 'CONTROL' && BCRYPT_AUTH_RE.test(n.code_snapshot))) &&
    n.code_snapshot.match(/\b(login|authenticate|passport\.authenticate|sign\s*in|logIn|createSession|doLogin|bcrypt\.compare|bcrypt\.compareSync)\b/i) !== null
  );

  // Also check for direct passport strategy patterns
  const passportStrategies = map.nodes.filter(n =>
    n.code_snapshot.match(/\bpassport\.use\s*\(\s*['"]login['"]/i) !== null ||
    n.code_snapshot.match(/\bLocalStrategy\b/i) !== null ||
    n.code_snapshot.match(/\bdone\s*\(\s*null\s*,\s*user\b/i) !== null
  );

  // Session regeneration patterns — must match actual regeneration calls, not words like
  // "regenerated" in comments. Use \b on both sides of the root word.
  const sessionRegenPattern = /\bregenerate\s*\(|\bsession\.regenerate\b|\breq\.session\.regenerate\b|\bsession\.destroy\b|\brotateSession\b|\bnewSession\b|\breq\.session\.destroy\s*\(\s*\)\s*.*session/i;

  // Check if there are auth nodes but no session regeneration anywhere in the map
  const allAuthNodes = [...authNodes, ...passportStrategies];

  if (allAuthNodes.length > 0) {
    // Check if session regeneration exists anywhere in the graph
    const hasSessionRegen = map.nodes.some(n =>
      sessionRegenPattern.test(n.code_snapshot)
    );

    if (!hasSessionRegen) {
      // Authentication happens but no session regeneration found
      // SUCCESS_PATH_RE: patterns that indicate a successful login completes
      const SUCCESS_PATH_RE = /\bdone\s*\(\s*null\s*,\s*user\b|\bres\.\s*(redirect|json|send)\b|\breq\.login\b|\breq\.logIn\b|\bpassport\.authenticate\b|\breq\.session\.\w+\s*=/i;
      for (const authNode of allAuthNodes) {
        // Check if this auth node (or any node in the same function scope) leads to a successful login
        const hasSuccessPath = SUCCESS_PATH_RE.test(authNode.code_snapshot) ||
          map.nodes.some(n =>
            n.line_start >= authNode.line_start &&
            n.line_start <= authNode.line_start + 30 &&
            SUCCESS_PATH_RE.test(n.code_snapshot)
          );

        if (hasSuccessPath) {
          // Build a reasonable sink - find the closest session/redirect action
          const loginSuccess = map.nodes.find(n =>
            n.line_start >= authNode.line_start &&
            n.code_snapshot.match(/\bdone\s*\(\s*null\s*,\s*user\b|\bres\.\s*(redirect|json|send)\b|\breq\.session\.\w+\s*=/i) !== null
          ) ?? authNode;

          findings.push({
            source: nodeRef(authNode),
            sink: nodeRef(loginSuccess),
            missing: 'TRANSFORM (session ID regeneration after authentication)',
            severity: 'high',
            description: `Authentication at ${authNode.label} succeeds without regenerating the session ID. ` +
              `An attacker who knows or sets the session ID before login can hijack the authenticated session.`,
            fix: 'Call req.session.regenerate() after successful authentication. ' +
              'This creates a new session ID while preserving session data. ' +
              'Example: req.session.regenerate((err) => { req.session.userId = user.id; ... }). ' +
              'For Passport.js, add session regeneration in the login callback.',
          });
          break; // One finding per auth flow is sufficient
        }
      }
    }
  }

  return {
    cwe: 'CWE-384',
    name: 'Session Fixation',
    holds: findings.length === 0,
    findings,
  };
}

// ---------------------------------------------------------------------------
// RESOURCE CWE Verification Paths
// ---------------------------------------------------------------------------

/**
 * CWE-400: Uncontrolled Resource Consumption
 * Pattern: INGRESS → RESOURCE[any] without CONTROL[limit_check]
 * Property: All resource allocations driven by user input have bounded limits
 *
 * R1: Unbounded resource consumption from user input.
 * Detects when tainted data flows to a RESOURCE node without a CONTROL
 * (validation, size limit, rate limiter) in between.
 */
function verifyCWE400(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const resources = nodesOfType(map, 'RESOURCE');

  for (const src of ingress) {
    for (const sink of resources) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // Check if the resource call has built-in bounds in code_snapshot (strip comments)
        const isBounded = stripComments(sink.code_snapshot).match(
          /\bmax\b|\blimit\b|\bcap\b|\bMAX_|\bLIMIT_|\bmaxSize|\bmaxLength|\bslice\s*\(\s*\d|\bsubstring\s*\(\s*\d/i
        ) !== null;

        if (!isBounded) {
          const subtypeLabel = sink.node_subtype || 'unknown';
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (input size validation or resource limit)',
            severity: subtypeLabel === 'cpu' ? 'high' : 'medium',
            description: `User input from ${src.label} controls ${subtypeLabel} resource allocation at ${sink.label} without bounds. ` +
              `An attacker can exhaust server ${subtypeLabel} resources causing denial of service.`,
            fix: `Validate and limit user input before passing to resource allocation. ` +
              `Add size/count limits: check input length, cap allocation size, use timeouts. ` +
              (subtypeLabel === 'cpu'
                ? 'For regex: use a safe regex library (re2) or limit input length. For crypto: cap iteration counts.'
                : subtypeLabel === 'memory'
                ? 'Cap buffer sizes. Limit request body size. Stream large inputs instead of buffering.'
                : subtypeLabel === 'connections'
                ? 'Use connection pooling with max limits. Set request timeouts. Add rate limiting.'
                : subtypeLabel === 'file_descriptors'
                ? 'Limit concurrent file operations. Close files in finally blocks.'
                : 'Add appropriate resource limits and rate limiting.'),
          });
        }
      }
    }
  }

  // Secondary check: INGRESS → RESOURCE via shared function scope (for patterns where
  // taint flows through local variables without explicit DATA_FLOW edges)
  if (findings.length === 0 && ingress.length > 0 && resources.length > 0) {
    for (const res of resources) {
      for (const src of ingress) {
        if (sharesFunctionScope(map, src.id, res.id)) {
          // Check if there's a CONTROL node in the same scope
          const controlInScope = map.nodes.some(n =>
            n.node_type === 'CONTROL' && sharesFunctionScope(map, n.id, res.id)
          );
          if (!controlInScope) {
            const isBounded = stripComments(res.code_snapshot).match(
              /\bmax\b|\blimit\b|\bcap\b|\bMAX_|\bLIMIT_/i
            ) !== null;
            if (!isBounded) {
              const subtypeLabel = res.node_subtype || 'unknown';
              findings.push({
                source: nodeRef(src),
                sink: nodeRef(res),
                missing: 'CONTROL (input size validation or resource limit)',
                severity: 'medium',
                description: `User input from ${src.label} is accessible in the same scope as ${subtypeLabel} resource allocation at ${res.label} without bounds checking.`,
                fix: 'Add input validation or resource limits between user input and resource allocation.',
              });
            }
          }
        }
      }
    }
  }

  return {
    cwe: 'CWE-400',
    name: 'Uncontrolled Resource Consumption',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-770: Allocation of Resources Without Limits or Throttling
 * Pattern: Multiple INGRESS paths → same RESOURCE without CONTROL[rate_limit]
 * Property: Resource-consuming endpoints have rate limiting
 *
 * R3: DoS via multiple unthrottled paths to the same resource.
 * Checks if RESOURCE nodes reachable from INGRESS have rate limiting applied.
 */
function verifyCWE770(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const resources = nodesOfType(map, 'RESOURCE');

  // Check for rate limiting: CONTROL nodes with rate_limit or rate_limiter subtypes
  const hasRateLimiter = map.nodes.some(n =>
    n.node_type === 'CONTROL' &&
    (n.node_subtype.includes('rate_limit') || n.node_subtype.includes('throttle') ||
     n.code_snapshot.match(/\brate.?limit\b|\bthrottle\b|\brateLimit\b/i) !== null)
  );

  if (hasRateLimiter) {
    return {
      cwe: 'CWE-770',
      name: 'Allocation of Resources Without Limits or Throttling',
      holds: true,
      findings: [],
    };
  }

  // Count how many INGRESS paths reach each RESOURCE
  for (const res of resources) {
    const reachingIngress: NeuralMapNode[] = [];
    for (const src of ingress) {
      // Check if there's any path (tainted or not) from ingress to resource
      const nodeMap = new Map(map.nodes.map(n => [n.id, n]));
      const visited = new Set<string>();
      const queue = [src.id];
      let found = false;

      while (queue.length > 0 && !found) {
        const nodeId = queue.shift()!;
        if (visited.has(nodeId)) continue;
        visited.add(nodeId);

        if (nodeId === res.id) { found = true; break; }

        const node = nodeMap.get(nodeId);
        if (!node) continue;
        for (const edge of node.edges) {
          if (!visited.has(edge.target)) queue.push(edge.target);
        }
      }
      if (found) reachingIngress.push(src);
    }

    // Also check via function scope proximity
    if (reachingIngress.length === 0) {
      for (const src of ingress) {
        if (sharesFunctionScope(map, src.id, res.id)) {
          reachingIngress.push(src);
        }
      }
    }

    if (reachingIngress.length > 0) {
      const subtypeLabel = res.node_subtype || 'unknown';
      findings.push({
        source: nodeRef(reachingIngress[0]),
        sink: nodeRef(res),
        missing: 'CONTROL (rate limiting or request throttling)',
        severity: 'medium',
        description: `${reachingIngress.length} ingress path(s) reach ${subtypeLabel} resource at ${res.label} without rate limiting. ` +
          `An attacker can send many requests to exhaust the resource pool.`,
        fix: 'Add rate limiting middleware (e.g., express-rate-limit) to endpoints that consume shared resources. ' +
          'Set per-IP and global request limits. Use connection pool limits.',
      });
    }
  }

  return {
    cwe: 'CWE-770',
    name: 'Allocation of Resources Without Limits or Throttling',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-1333: Inefficient Regular Expression Complexity (ReDoS)
 * Pattern: INGRESS → RESOURCE[cpu] where code contains new RegExp(tainted)
 * Property: User input is never used to construct regular expressions without safe guards
 *
 * R4: ReDoS via user-controlled regex patterns.
 * Also detects regex constructed from user input even without explicit RESOURCE nodes,
 * by scanning code_snapshots for new RegExp(tainted) patterns.
 */
function verifyCWE1333(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Strategy 1: RESOURCE/cpu nodes with regex in code_snapshot
  const regexResources = map.nodes.filter(n =>
    n.node_type === 'RESOURCE' && n.node_subtype === 'cpu' &&
    /\bRegExp\b|\bregex\b|\bnew\s+RegExp\b/i.test(n.code_snapshot)
  );

  for (const src of ingress) {
    for (const sink of regexResources) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        findings.push({
          source: nodeRef(src),
          sink: nodeRef(sink),
          missing: 'CONTROL (regex input validation or safe regex library)',
          severity: 'high',
          description: `User input from ${src.label} is used to construct a regular expression at ${sink.label}. ` +
            `A crafted input like (a+)+$ can cause catastrophic backtracking (ReDoS), freezing the server.`,
          fix: 'Never pass user input directly to new RegExp(). Options: ' +
            '(1) Use a safe regex library like re2. ' +
            '(2) Escape user input with escapeRegExp() before constructing. ' +
            '(3) Set a timeout on regex execution. ' +
            '(4) Limit input length before regex construction.',
        });
      }
    }
  }

  // Strategy 2: Code-snapshot scan for regex construction patterns across all nodes
  // (catches cases where the mapper didn't create a RESOURCE node but regex is built from taint)
  if (findings.length === 0 && ingress.length > 0) {
    const regexNodes = map.nodes.filter(n =>
      n.node_type !== 'STRUCTURAL' && n.node_type !== 'META' &&
      /\bnew\s+RegExp\s*\(/.test(n.code_snapshot)
    );

    for (const regNode of regexNodes) {
      for (const src of ingress) {
        if (hasTaintedPathWithoutControl(map, src.id, regNode.id) ||
            sharesFunctionScope(map, src.id, regNode.id)) {
          const isEscaped = stripComments(regNode.code_snapshot).match(
            /\bescapeRegExp\b|\bescape\s*\(|\bsanitize\s*\(|\bre2\b|\bsafe.*regex/i
          ) !== null;

          if (!isEscaped) {
            findings.push({
              source: nodeRef(src),
              sink: nodeRef(regNode),
              missing: 'CONTROL (regex input escaping or safe regex library)',
              severity: 'high',
              description: `User input from ${src.label} may reach regex construction at ${regNode.label}. ` +
                `Crafted patterns can cause catastrophic backtracking (ReDoS).`,
              fix: 'Escape user input before passing to new RegExp(), or use the re2 library for safe regex.',
            });
            break;
          }
        }
      }
    }
  }

  return {
    cwe: 'CWE-1333',
    name: 'Inefficient Regular Expression Complexity (ReDoS)',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-404: Improper Resource Shutdown or Release
 * Pattern: RESOURCE[acquire] on error path without RESOURCE[release]
 * Property: All resource acquisitions have corresponding releases on all paths
 *
 * R2: Resource leak detection.
 * Checks if RESOURCE nodes (connections, file descriptors) are properly released
 * by looking for matching release patterns in the same function scope.
 */
function verifyCWE404(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Resource acquire patterns — node_subtype + code_snapshot checks
  const acquirePatterns = /\b(open|createReadStream|createWriteStream|getConnection|acquire|connect|createServer|createConnection)\b/i;
  const releasePatterns = /\b(close|end|release|destroy|releaseConnection|disconnect|shutdown|unref)\b/i;

  const resourceNodes = nodesOfType(map, 'RESOURCE');

  for (const res of resourceNodes) {
    // Only check acquirable resources (connections, file descriptors)
    if (res.node_subtype !== 'connections' && res.node_subtype !== 'file_descriptors') continue;

    // Check if this is an acquire operation
    if (!acquirePatterns.test(res.code_snapshot)) continue;

    // Find the containing function
    const containingFunc = findContainingFunction(map, res.id);
    if (!containingFunc) continue;

    // Look for a matching release in the same function
    const funcNode = map.nodes.find(n => n.id === containingFunc);
    if (!funcNode) continue;

    // Gather all nodes contained in the same function
    const containedNodeIds = new Set<string>();
    const queue = [containingFunc];
    while (queue.length > 0) {
      const id = queue.shift()!;
      const node = map.nodes.find(n => n.id === id);
      if (!node) continue;
      for (const edge of node.edges) {
        if (edge.edge_type === 'CONTAINS' && !containedNodeIds.has(edge.target)) {
          containedNodeIds.add(edge.target);
          queue.push(edge.target);
        }
      }
    }

    // Check if any contained node has a release pattern
    const hasRelease = map.nodes.some(n =>
      containedNodeIds.has(n.id) && releasePatterns.test(n.code_snapshot)
    );

    // Also check code_snapshot of the containing function itself for finally/release
    const funcHasRelease = releasePatterns.test(funcNode.code_snapshot) ||
      /\bfinally\b/.test(funcNode.code_snapshot);

    if (!hasRelease && !funcHasRelease) {
      findings.push({
        source: nodeRef(res),
        sink: nodeRef(res),
        missing: 'RESOURCE (release/close/end on all code paths including error paths)',
        severity: 'medium',
        description: `${res.node_subtype} resource acquired at ${res.label} may not be released on all code paths. ` +
          `This can lead to resource leaks (${res.node_subtype === 'connections' ? 'connection pool exhaustion' : 'file descriptor exhaustion'}).`,
        fix: `Ensure resources are released in a finally block or using a try-with-resources pattern. ` +
          `For connections: always call release() or end() in a finally block. ` +
          `For files: use fs.promises with try/finally, or streams that auto-close.`,
      });
    }
  }

  return {
    cwe: 'CWE-404',
    name: 'Improper Resource Shutdown or Release',
    holds: findings.length === 0,
    findings,
  };
}

// ---------------------------------------------------------------------------
// CWE-328: Use of Weak Hash (broadened — cross-language)
// ---------------------------------------------------------------------------

/**
 * CWE-328: Use of Weak Hash
 * Detects MD5, SHA-1 usage for security purposes across all languages.
 *
 * Two detection strategies:
 *   A. Tainted data flows to a hash-related node whose surrounding context
 *      (same function or the node itself) references a weak algorithm.
 *   B. Any node in the graph invokes a weak hash algorithm on data from
 *      a tainted INGRESS parameter within the same function scope.
 *
 * Language patterns caught:
 *   Java/Kotlin: MessageDigest.getInstance("MD5"), .digest()
 *   Python:      hashlib.md5(), hashlib.sha1()
 *   JavaScript:  crypto.createHash('md5')
 *   PHP:         md5(), sha1()
 *   Swift:       CC_MD5
 *   Ruby:        Digest::MD5, Digest::SHA1
 *   Go:          md5.New(), sha1.New(), md5.Sum()
 *   C#:          MD5.Create(), SHA1.Create()
 */
function verifyCWE328(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Broad weak-hash regex — matches the algorithm name across languages
  const WEAK_HASH_RE = /\b(MD5|SHA-?1|md5|sha1)\b|CC_MD5|Digest::MD5|Digest::SHA1|hashlib\.md5|hashlib\.sha1|md5\.New|sha1\.New|md5\.Sum|sha1\.Sum|MD5\.Create|SHA1\.Create/i;

  // Safe override — if the code also uses a strong algorithm, skip
  const STRONG_HASH_RE = /\bbcrypt\b|\bscrypt\b|\bargon2\b|\bPBKDF2\b|\bSHA-?256\b|\bSHA-?384\b|\bSHA-?512\b|\bSHA3\b|\bblake2\b/i;

  // Strategy A: Find all nodes that look hash-related (broad type match)
  const hashSinks = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL') &&
    (n.node_subtype.includes('hash') || n.node_subtype.includes('crypto') ||
     n.node_subtype.includes('digest') || n.node_subtype.includes('encrypt') ||
     n.attack_surface.includes('crypto') ||
     n.code_snapshot.match(
       /\b(createHash|MD5|SHA1|sha1|md5|hashlib|MessageDigest|digest|hash|CC_MD5|Digest::)/i
     ) !== null)
  );

  for (const src of ingress) {
    for (const sink of hashSinks) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // Check if weak hash is referenced in this node OR its enclosing function
        const sinkCode = stripComments(sink.code_snapshot);
        let weakInScope = WEAK_HASH_RE.test(sinkCode);

        // If not directly on this node, check sibling nodes in the same function
        if (!weakInScope) {
          const parentFn = findContainingFunction(map, sink.id);
          if (parentFn) {
            const parentNode = map.nodes.find(n => n.id === parentFn);
            if (parentNode) {
              weakInScope = WEAK_HASH_RE.test(stripComments(parentNode.code_snapshot));
            }
            // Also check sibling TRANSFORM nodes in the same function
            if (!weakInScope) {
              for (const n of map.nodes) {
                if ((n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL') &&
                    n.id !== sink.id) {
                  const sibParent = findContainingFunction(map, n.id);
                  if (sibParent === parentFn && WEAK_HASH_RE.test(stripComments(n.code_snapshot))) {
                    weakInScope = true;
                    break;
                  }
                }
              }
            }
          }
        }

        if (weakInScope && !STRONG_HASH_RE.test(sinkCode)) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (strong hash algorithm enforcement)',
            severity: 'high',
            description: `Data from ${src.label} is hashed with a weak algorithm at ${sink.label}. ` +
              `MD5 and SHA-1 are cryptographically broken — vulnerable to collision and preimage attacks.`,
            fix: 'Use strong hashing: SHA-256/SHA-3 for integrity, bcrypt/scrypt/Argon2 for passwords. ' +
              'Never use MD5 or SHA-1 for security-sensitive operations.',
          });
        }
      }
    }
  }

  // Strategy B: Scope-based — INGRESS param shares a function with a weak hash node
  // This catches cases where BFS doesn't find a direct edge path.
  // Includes STRUCTURAL nodes (e.g., Swift closures containing CC_MD5).
  if (findings.length === 0) {
    const weakHashNodes = map.nodes.filter(n =>
      (n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL' || n.node_type === 'STRUCTURAL') &&
      WEAK_HASH_RE.test(stripComments(n.code_snapshot)) &&
      !STRONG_HASH_RE.test(stripComments(n.code_snapshot))
    );

    for (const src of ingress) {
      for (const weakNode of weakHashNodes) {
        if (sharesFunctionScope(map, src.id, weakNode.id)) {
          // Avoid duplicate findings
          const already = findings.some(f =>
            f.source.id === src.id && f.sink.id === weakNode.id
          );
          if (!already) {
            findings.push({
              source: nodeRef(src),
              sink: nodeRef(weakNode),
              missing: 'CONTROL (strong hash algorithm enforcement)',
              severity: 'high',
              description: `User input from ${src.label} is in scope with weak hash at ${weakNode.label}. ` +
                `MD5 and SHA-1 are cryptographically broken.`,
              fix: 'Use strong hashing: SHA-256/SHA-3 for integrity, bcrypt/scrypt/Argon2 for passwords. ' +
                'Never use MD5 or SHA-1 for security-sensitive operations.',
            });
          }
        }
      }
    }
  }

  return {
    cwe: 'CWE-328',
    name: 'Use of Weak Hash',
    holds: findings.length === 0,
    findings,
  };
}

// ---------------------------------------------------------------------------
// CWE-117: Improper Output Neutralization for Logs (broadened — cross-language)
// ---------------------------------------------------------------------------

/**
 * CWE-117: Log Injection
 * Detects user input flowing to logging functions without sanitization.
 *
 * The generated verifier only looks at STORAGE nodes, but most logging calls
 * are classified as EGRESS/display (println, print, System.out, fmt.Println)
 * or EXTERNAL (log.info, logger.warn). This override broadens the sink filter.
 *
 * Language patterns caught:
 *   Java/Kotlin: System.out.println(), Logger.info/warn/error(), println()
 *   Python:      logging.info/warn/error(), print()
 *   Go:          log.Printf(), fmt.Println(), log.Println()
 *   PHP:         error_log(), syslog(), trigger_error()
 *   Swift:       print(), NSLog(), os_log()
 *   Ruby:        puts, Logger.info/warn/error
 *   JavaScript:  console.log/warn/error(), winston, bunyan, pino
 *   C#:          Console.WriteLine(), ILogger.Log*
 */
function verifyCWE117(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Broad logging-function regex across all languages
  const LOG_SINK_RE = /\b(console\.(log|warn|error|info|debug|trace)|logger\.(log|error|warn|info|debug|trace|fatal|verbose)|log\.(log|error|warn|info|debug|trace|fatal|Printf|Println|Print)|println|print\s*\(|System\.out\.print|System\.err\.print|NSLog|os_log|error_log|syslog|trigger_error|puts\s|Logger\.(info|warn|error|debug|fatal)|winston\.(log|error|warn|info|debug)|bunyan\.(error|warn|info|debug|trace|fatal)|pino\.(error|warn|info|debug|trace|fatal)|log4js\.(error|warn|info|debug|trace|fatal)|morgan\(|app\.log\.|syslog\.(log|write)|audit\.log|accessLog\.|errorLog\.|Console\.Write|ILogger|_logger\.|logging\.(info|warning|error|debug|critical)|fmt\.Print|fmt\.Fprint|writeLog|appendFile.*log)\b/i;

  // Safe patterns — encoding or sanitization before logging
  const LOG_SAFE_RE = /\bescape\s*\(|\bencode\s*\(|\bsanitize\s*\(|\bstrip.*newline\b|\breplace.*\\n\b|\blog.*safe\b|\bneutralize\s*\(|\bstructured.*log\b|\bjson.*log\b/i;

  // Find logging sinks — EGRESS, EXTERNAL, STORAGE, or TRANSFORM nodes that match
  const logSinks = map.nodes.filter(n =>
    (n.node_type === 'EGRESS' || n.node_type === 'EXTERNAL' ||
     n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM') &&
    (n.node_subtype.includes('log') || n.node_subtype.includes('audit') ||
     n.node_subtype.includes('display') ||
     n.attack_surface.includes('logging') ||
     LOG_SINK_RE.test(n.code_snapshot))
  );

  for (const src of ingress) {
    for (const sink of logSinks) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const sinkCode = stripComments(sink.code_snapshot);
        if (!LOG_SAFE_RE.test(sinkCode)) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'TRANSFORM (log encoding — strip newlines, control chars, delimiters)',
            severity: 'medium',
            description: `User input from ${src.label} is logged at ${sink.label} without neutralization. ` +
              `An attacker can inject fake log entries via newlines or forge audit trails.`,
            fix: 'Strip or encode newlines (\\n, \\r), control characters, and log-format delimiters ' +
              'from user input before logging. Use structured logging (JSON) to prevent injection.',
          });
        }
      }
    }
  }

  // Scope-based fallback: INGRESS param shares a function scope with a logging node
  // that has tainted data_in
  if (findings.length === 0) {
    const taintedLogSinks = logSinks.filter(n => n.data_in.some(d => d.tainted));
    for (const src of ingress) {
      for (const sink of taintedLogSinks) {
        if (src.id === sink.id) continue;
        if (sharesFunctionScope(map, src.id, sink.id)) {
          const sinkCode = stripComments(sink.code_snapshot);
          if (!LOG_SAFE_RE.test(sinkCode)) {
            const already = findings.some(f =>
              f.source.id === src.id && f.sink.id === sink.id
            );
            if (!already) {
              findings.push({
                source: nodeRef(src),
                sink: nodeRef(sink),
                missing: 'TRANSFORM (log encoding — strip newlines, control chars, delimiters)',
                severity: 'medium',
                description: `User input from ${src.label} is logged at ${sink.label} without neutralization. ` +
                  `An attacker can inject fake log entries via newlines or forge audit trails.`,
                fix: 'Strip or encode newlines (\\n, \\r), control characters, and log-format delimiters ' +
                  'from user input before logging. Use structured logging (JSON) to prevent injection.',
              });
            }
          }
        }
      }
    }
  }

  return {
    cwe: 'CWE-117',
    name: 'Improper Output Neutralization for Logs',
    holds: findings.length === 0,
    findings,
  };
}

// ---------------------------------------------------------------------------
// CWE-601: Open Redirect (broadened — cross-language)
// ---------------------------------------------------------------------------

/**
 * CWE-601: Open Redirect
 * Detects user-controlled URLs flowing to redirect operations.
 *
 * The generated verifier only looks at EGRESS/TRANSFORM nodes with redirect
 * subtypes. This override also catches:
 *   - CONTROL/return nodes that return "Location: <user-input>"
 *   - TRANSFORM/template_string nodes that build redirect URLs
 *   - String returns containing redirect-related URLs
 *
 * Language patterns caught:
 *   Java/Kotlin: response.sendRedirect(), "Location: " + url, return "redirect:" + url
 *   Python:      redirect(url), Response(status=302, headers={"Location": url})
 *   Go:          http.Redirect(), w.Header().Set("Location", url)
 *   PHP:         header("Location: " . $url)
 *   Swift/JS:    return "Location: " + url, window.location = url
 */
function verifyCWE601(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Sources: user input that could contain URLs
  const urlInputs = nodesOfType(map, 'INGRESS').filter(n =>
    n.node_subtype.includes('query') || n.node_subtype.includes('param') ||
    n.node_subtype.includes('url') || n.node_subtype.includes('header') ||
    n.node_subtype.includes('http_request') || n.node_subtype.includes('function_param') ||
    n.attack_surface.includes('user_input') || n.attack_surface.includes('url_input') ||
    n.code_snapshot.match(
      /\b(req\.query|req\.params|req\.body|request\.args|request\.form|request\.GET|searchParams|url|redirect|next|return_?to|goto|target|dest|forward|continue|callback|returnUrl)\b/i
    ) !== null
  );

  // Sinks: redirect operations — broadened to catch return statements and template strings
  const REDIRECT_CODE_RE = /\b(res\.redirect|response\.redirect|redirect|sendRedirect|Location\s*[=:]|window\.location|document\.location|meta.*refresh|header\s*\(\s*['"]Location|http\.Redirect)\b|"Location:\s|'Location:\s|redirect\?url=/i;

  const redirectSinks = map.nodes.filter(n =>
    // Original: EGRESS/TRANSFORM with redirect subtypes
    ((n.node_type === 'EGRESS' || n.node_type === 'TRANSFORM') &&
     (n.node_subtype.includes('redirect') || n.node_subtype.includes('location') ||
      n.attack_surface.includes('redirect') ||
      REDIRECT_CODE_RE.test(n.code_snapshot))) ||
    // NEW: CONTROL/return nodes whose code contains redirect/Location patterns
    (n.node_type === 'CONTROL' && n.node_subtype === 'return' &&
     REDIRECT_CODE_RE.test(n.code_snapshot)) ||
    // NEW: template_string nodes that build redirect URLs
    (n.node_type === 'TRANSFORM' && n.node_subtype === 'template_string' &&
     REDIRECT_CODE_RE.test(n.code_snapshot))
  );

  // Safe patterns: allowlist check, relative-path enforcement, same-origin check
  const safeRedirect = (code: string): boolean =>
    /\ballowlist\b|\bwhitelist\b|\ballowed[_-]?(?:urls?|domains?|hosts?)\b/i.test(code) ||
    /\bstartsWith\s*\(\s*['"]\/[^\/]/i.test(code) ||
    /\bnew URL\b.*\.(?:host|origin|hostname)\b/i.test(code) ||
    /\bsame[_-]?origin\b|\burl\.parse\b.*\bhost\b/i.test(code) ||
    /\brelative[_-]?path\b|\bpath\.resolve\b/i.test(code);

  for (const src of urlInputs) {
    for (const sink of redirectSinks) {
      if (src.id === sink.id) continue;

      // Check tainted path first
      let vulnerable = hasTaintedPathWithoutControl(map, src.id, sink.id);

      // Fallback: scope-based check for redirect URLs
      if (!vulnerable && sharesFunctionScope(map, src.id, sink.id)) {
        // Check if the sink's code references the source's label (variable name)
        const srcVarName = src.label.replace(/[^a-zA-Z0-9_]/g, '');
        if (srcVarName && sink.code_snapshot.includes(srcVarName)) {
          vulnerable = true;
        }
        // Also check if sink has tainted data_in
        if (!vulnerable && sink.data_in.some(d => d.tainted)) {
          vulnerable = true;
        }
      }

      if (vulnerable) {
        const scopeSnapshots601 = getContainingScopeSnapshots(map, sink.id);
        const combinedScope601 = scopeSnapshots601.join('\n') || sink.code_snapshot;
        if (!safeRedirect(combinedScope601) && !safeRedirect(src.code_snapshot)) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'CONTROL (URL allowlist or relative-path enforcement before redirect)',
            severity: 'medium',
            description: `User input from ${src.label} controls redirect destination at ${sink.label}. ` +
              `Attackers can craft URLs like ?next=https://evil.com to phish users via your domain.`,
            fix: 'Validate redirect URLs against an allowlist of trusted domains. ' +
              'Use relative paths only: if (!url.startsWith("/") || url.startsWith("//")) reject. ' +
              'Parse with new URL() and check .hostname against allowed origins.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-601',
    name: 'URL Redirection to Untrusted Site (Open Redirect)',
    holds: findings.length === 0,
    findings,
  };
}

// ---------------------------------------------------------------------------
// Sensitive Data Exposure CWEs (CWE-256 through CWE-319)
// ---------------------------------------------------------------------------

/**
 * CWE-256: Plaintext Storage of a Password
 * Pattern: INGRESS/STORAGE containing password data → STORAGE without hashing TRANSFORM
 * Property: Passwords must be hashed (bcrypt/scrypt/argon2) before storage
 */
function verifyCWE256(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Password patterns in code snapshots
  const PASSWORD_RE = /\b(password|passwd|pwd|pass_?word|user_?pass|login_?pass)\b/i;
  // Hashing safe patterns — real password hashing functions
  const HASH_SAFE_RE = /\bbcrypt\b|\bscrypt\b|\bargon2\b|\bPBKDF2\b|\bhash(?:Sync|Password|pwd)\b|\bcreateHash\b|\bgenSalt\b|\bhashpw\b|\bpassword_hash\b|\bgenerate_password_hash\b|\bmake_password\b/i;

  // Find STORAGE nodes that deal with passwords
  const passwordStores = map.nodes.filter(n =>
    n.node_type === 'STORAGE' &&
    (PASSWORD_RE.test(n.code_snapshot) ||
     PASSWORD_RE.test(n.label) ||
     n.data_in.some(d => PASSWORD_RE.test(d.name)))
  );

  // For each password storage, check if a TRANSFORM(hash) precedes it
  for (const store of passwordStores) {
    const storeCode = stripComments(store.code_snapshot);
    // If the store itself references hashing, it's safe
    if (HASH_SAFE_RE.test(storeCode)) continue;

    // Check if any TRANSFORM node on the path to this store performs hashing
    let hasHashTransform = false;
    for (const n of map.nodes) {
      if (n.node_type === 'TRANSFORM' && HASH_SAFE_RE.test(stripComments(n.code_snapshot))) {
        // Check if this hash transform feeds into the store
        for (const edge of n.edges) {
          if (edge.target === store.id) {
            hasHashTransform = true;
            break;
          }
        }
      }
      if (hasHashTransform) break;
    }

    // Also check the containing function scope for hashing
    if (!hasHashTransform) {
      const parentFn = findContainingFunction(map, store.id);
      if (parentFn) {
        const parentNode = map.nodes.find(n => n.id === parentFn);
        if (parentNode && HASH_SAFE_RE.test(stripComments(parentNode.code_snapshot))) {
          hasHashTransform = true;
        }
      }
    }

    if (!hasHashTransform) {
      // Find the source of the password data
      const pwSource = map.nodes.find(n =>
        n.node_type === 'INGRESS' && PASSWORD_RE.test(n.code_snapshot)
      );
      findings.push({
        source: pwSource ? nodeRef(pwSource) : nodeRef(store),
        sink: nodeRef(store),
        missing: 'TRANSFORM (password hashing — bcrypt, scrypt, or argon2)',
        severity: 'critical',
        description: `Password stored in plaintext at ${store.label}. ` +
          `No hashing transform detected before storage. A database breach exposes all user passwords.`,
        fix: 'Hash passwords with bcrypt, scrypt, or Argon2 before storing. ' +
          'Example: const hashed = await bcrypt.hash(password, 12); db.store(hashed). ' +
          'Never store passwords as plaintext or with reversible encoding.',
      });
    }
  }

  return {
    cwe: 'CWE-256',
    name: 'Plaintext Storage of a Password',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-257: Storing Passwords in a Recoverable Format
 * Pattern: Password data goes through reversible encoding (base64, AES, XOR) instead of one-way hash
 * Property: Passwords must use one-way hashing, never reversible encryption/encoding
 */
function verifyCWE257(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const PASSWORD_RE = /\b(password|passwd|pwd|pass_?word|user_?pass|login_?pass)\b/i;
  // Reversible encoding/encryption — NOT one-way hashing
  const REVERSIBLE_RE = /\bbase64\b|\bbtoa\b|\batob\b|\bBuffer\.from\b.*\btoString\b|\bencode\s*\(|\bAES\b|\bDES\b|\b3DES\b|\bTripleDES\b|\bRC4\b|\bXOR\b|\bencrypt\s*\(|\bcipher\s*\(|\bcreateCipher\b|\bCryptoJS\.enc\b|\bfernet\b|\bb64encode\b/i;
  // One-way hash — the CORRECT approach for passwords
  const ONEWAY_HASH_RE = /\bbcrypt\b|\bscrypt\b|\bargon2\b|\bPBKDF2\b|\bhash(?:Sync|Password|pwd)\b|\bgenSalt\b|\bhashpw\b|\bpassword_hash\b|\bgenerate_password_hash\b|\bmake_password\b/i;

  // Find TRANSFORM nodes that apply reversible encoding to password data
  const transforms = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL') &&
    REVERSIBLE_RE.test(stripComments(n.code_snapshot))
  );

  for (const txNode of transforms) {
    const code = stripComments(txNode.code_snapshot);
    // Does this transform handle password data?
    const handlesPassword = PASSWORD_RE.test(code) ||
      PASSWORD_RE.test(txNode.label) ||
      txNode.data_in.some(d => PASSWORD_RE.test(d.name));

    if (!handlesPassword) {
      // Check if an INGRESS with password data flows into this transform
      const pwIngress = map.nodes.filter(n =>
        n.node_type === 'INGRESS' && PASSWORD_RE.test(n.code_snapshot)
      );
      let pwFlows = false;
      for (const src of pwIngress) {
        if (hasTaintedPathWithoutControl(map, src.id, txNode.id)) {
          pwFlows = true;
          break;
        }
      }
      if (!pwFlows) continue;
    }

    // Skip if a one-way hash is ALSO present (reversible encoding might be for transport, not storage)
    if (ONEWAY_HASH_RE.test(code)) continue;

    // Check containing function for one-way hash
    const parentFn = findContainingFunction(map, txNode.id);
    if (parentFn) {
      const parentNode = map.nodes.find(n => n.id === parentFn);
      if (parentNode && ONEWAY_HASH_RE.test(stripComments(parentNode.code_snapshot))) continue;
    }

    findings.push({
      source: nodeRef(txNode),
      sink: nodeRef(txNode),
      missing: 'TRANSFORM (one-way password hash instead of reversible encoding)',
      severity: 'critical',
      description: `Password is stored using reversible encoding/encryption at ${txNode.label}. ` +
        `An attacker who gains access to the stored data can reverse the encoding to recover plaintext passwords.`,
      fix: 'Use one-way hashing (bcrypt, scrypt, Argon2) for passwords — NEVER reversible encryption. ' +
        'Encryption (AES, base64) can be reversed with the key. Hashing cannot be reversed. ' +
        'Example: await bcrypt.hash(password, 12) instead of encrypt(password, key).',
    });
  }

  return {
    cwe: 'CWE-257',
    name: 'Storing Passwords in a Recoverable Format',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-260: Password in Configuration File
 * Pattern: META/config_value or STORAGE nodes with password patterns in config-like contexts
 * Property: Configuration files must not contain hardcoded passwords
 */
function verifyCWE260(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const PASSWORD_IN_CONFIG_RE = /(?:password|passwd|pwd|db_?pass|db_?password|mysql_?password|postgres_?password|redis_?password|smtp_?password|mail_?password|auth_?password)\s*[:=]\s*['"][^'"]{1,}['"]/i;
  // Config file patterns
  const CONFIG_FILE_RE = /\b(config|settings|\.env|\.ini|\.yaml|\.yml|\.json|\.toml|\.properties|\.conf|application)\b/i;
  // Safe: reading from environment or secret manager
  const ENV_SAFE_RE = /\bprocess\.env\b|\bos\.environ\b|\bos\.getenv\b|\benv\(\b|\bENV\[|\bvault\b|\bsecretManager\b|\baws[_-]?ssm\b|\bgetSecret\b|\bSecretClient\b|\bKeyVault\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);

    // Check for password values in config-related nodes
    const isConfigContext = node.node_type === 'META' ||
      (node.node_subtype.includes('config') || node.node_subtype.includes('setting') ||
       CONFIG_FILE_RE.test(node.file) || CONFIG_FILE_RE.test(node.label));

    if (!isConfigContext) continue;
    if (!PASSWORD_IN_CONFIG_RE.test(code)) continue;
    if (ENV_SAFE_RE.test(code)) continue;

    findings.push({
      source: nodeRef(node),
      sink: nodeRef(node),
      missing: 'META (external secret reference — environment variable or secret manager)',
      severity: 'high',
      description: `Password found in configuration at ${node.label}. ` +
        `Hardcoded passwords in config files are exposed via version control, backups, and deployment artifacts.`,
      fix: 'Move passwords to environment variables or a secret manager (AWS SSM, HashiCorp Vault, Azure Key Vault). ' +
        'Reference them as: process.env.DB_PASSWORD or vault.read("secret/db"). ' +
        'Never commit config files with real passwords.',
    });
  }

  return {
    cwe: 'CWE-260',
    name: 'Password in Configuration File',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-261: Weak Encoding for Password
 * Pattern: Password data encoded with weak/trivial encoding (base64, hex, ROT13, XOR)
 * Property: Passwords must use strong one-way hashing, not weak encoding
 */
function verifyCWE261(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const PASSWORD_RE = /\b(password|passwd|pwd|pass_?word|user_?pass)\b/i;
  // Weak encoding patterns — trivially reversible
  const WEAK_ENCODING_RE = /\bbase64\b|\bbtoa\b|\batob\b|\bhex\b|\bROT13\b|\bXOR\b|\bBuffer\.from\b.*['"](?:base64|hex)['"]\b|\bb64encode\b|\bb64decode\b|\bunescape\b|\bencodeURI\b|\bString\.fromCharCode\b/i;
  // Strong one-way hash — correct approach
  const STRONG_HASH_RE = /\bbcrypt\b|\bscrypt\b|\bargon2\b|\bPBKDF2\b|\bSHA-?256\b|\bSHA-?512\b|\bSHA3\b|\bblake2\b|\bhash(?:Sync|Password)\b/i;

  for (const node of map.nodes) {
    if (node.node_type !== 'TRANSFORM' && node.node_type !== 'EXTERNAL') continue;
    const code = stripComments(node.code_snapshot);
    if (!WEAK_ENCODING_RE.test(code)) continue;

    // Does this node handle password data?
    const handlesPassword = PASSWORD_RE.test(code) || PASSWORD_RE.test(node.label) ||
      node.data_in.some(d => PASSWORD_RE.test(d.name));

    if (!handlesPassword) {
      // Check if password data flows into this node from INGRESS
      const pwIngress = map.nodes.filter(n =>
        n.node_type === 'INGRESS' && PASSWORD_RE.test(n.code_snapshot)
      );
      let pwFlows = false;
      for (const src of pwIngress) {
        if (hasTaintedPathWithoutControl(map, src.id, node.id)) {
          pwFlows = true;
          break;
        }
      }
      if (!pwFlows) continue;
    }

    // Skip if strong hashing is also present
    if (STRONG_HASH_RE.test(code)) continue;

    findings.push({
      source: nodeRef(node),
      sink: nodeRef(node),
      missing: 'TRANSFORM (strong one-way hash instead of weak encoding)',
      severity: 'high',
      description: `Password at ${node.label} is protected with weak encoding (base64, hex, etc.). ` +
        `These encodings are trivially reversible and provide zero security.`,
      fix: 'Replace weak encoding with strong one-way hashing: bcrypt, scrypt, or Argon2. ' +
        'Base64 and hex are encoding (reversible), not encryption or hashing. ' +
        'Example: bcrypt.hash(password, 12) instead of btoa(password).',
    });
  }

  return {
    cwe: 'CWE-261',
    name: 'Weak Encoding for Password',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-312: Cleartext Storage of Sensitive Information
 * Pattern: Sensitive data (PII, SECRET, AUTH, FINANCIAL) flows to STORAGE without encryption TRANSFORM
 * Property: Sensitive data must be encrypted before being written to persistent storage
 */
function verifyCWE312(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const SENSITIVE_RE = /\b(password|passwd|pwd|ssn|social.?security|credit.?card|card.?number|cvv|secret|token|api.?key|private.?key|health.?record|medical|dob|date.?of.?birth|bank.?account|routing.?number)\b/i;
  // Encryption or hashing safe patterns — both are valid protections for stored sensitive data
  const ENCRYPT_SAFE_RE = /\bencrypt\s*\(|\bAES\b|\bcipher\s*\(|\bcreateCipher\w*\b|\bcrypto\.subtle\b|\bCryptoJS\b|\bfernet\b|\b\.seal\s*\(|\bsecretbox\b|\bRSA\b|\bgpg\b|\bpgp\b|\bbcrypt\b|\bscrypt\b|\bargon2\b|\bPBKDF2\b|\bhash(?:Sync|Password|pwd)\b|\bgenSalt\b|\bhashpw\b|\bpassword_hash\b|\bgenerate_password_hash\b|\bmake_password\b|\bcreateHash\b/i;

  // Find storage nodes that receive sensitive data without encryption
  const sensitiveStores = map.nodes.filter(n =>
    n.node_type === 'STORAGE' &&
    (n.data_in.some(d => d.sensitivity !== 'NONE') ||
     SENSITIVE_RE.test(n.code_snapshot) ||
     SENSITIVE_RE.test(n.label))
  );

  for (const store of sensitiveStores) {
    const storeCode = stripComments(store.code_snapshot);
    // If the storage node itself performs encryption, it's safe
    if (ENCRYPT_SAFE_RE.test(storeCode)) continue;

    // Check if an encryption TRANSFORM node feeds into this store
    let hasEncryption = false;
    for (const n of map.nodes) {
      if (n.node_type === 'TRANSFORM' && ENCRYPT_SAFE_RE.test(stripComments(n.code_snapshot))) {
        for (const edge of n.edges) {
          if (edge.target === store.id) {
            hasEncryption = true;
            break;
          }
        }
      }
      if (hasEncryption) break;
    }

    // Check containing function scope
    if (!hasEncryption) {
      const parentFn = findContainingFunction(map, store.id);
      if (parentFn) {
        const parentNode = map.nodes.find(n => n.id === parentFn);
        if (parentNode && ENCRYPT_SAFE_RE.test(stripComments(parentNode.code_snapshot))) {
          hasEncryption = true;
        }
      }
    }

    if (!hasEncryption) {
      // Escalate to critical when passwords are involved — they need hashing, not just encryption
      const PASSWORD_RE = /\b(password|passwd|pwd|pass_?word)\b/i;
      const storeCode = stripComments(store.code_snapshot);
      const isPassword = PASSWORD_RE.test(storeCode) || PASSWORD_RE.test(store.label) ||
        store.data_in.some(d => PASSWORD_RE.test(d.name));

      findings.push({
        source: nodeRef(store),
        sink: nodeRef(store),
        missing: isPassword
          ? 'TRANSFORM (password hashing — bcrypt, scrypt, or argon2 before storage)'
          : 'TRANSFORM (encryption before storage)',
        severity: isPassword ? 'critical' : 'high',
        description: isPassword
          ? `Password stored in cleartext at ${store.label}. ` +
            `No hashing transform detected before storage. A database breach exposes all user passwords.`
          : `Sensitive data stored in cleartext at ${store.label}. ` +
            `No encryption transform detected before storage. A data breach exposes raw sensitive data.`,
        fix: isPassword
          ? 'Hash passwords with bcrypt, scrypt, or Argon2 before storing. ' +
            'Example: const hashed = await bcrypt.hash(password, 12); db.store(hashed). ' +
            'Never store passwords as plaintext or with reversible encryption.'
          : 'Encrypt sensitive data before writing to storage using AES-256-GCM or similar. ' +
            'Use field-level encryption for database columns containing PII, secrets, or financial data. ' +
            'Example: const encrypted = crypto.createCipheriv("aes-256-gcm", key, iv).update(data).',
      });
    }
  }

  return {
    cwe: 'CWE-312',
    name: 'Cleartext Storage of Sensitive Information',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-313: Cleartext Storage in a File
 * Pattern: Sensitive data written to file STORAGE nodes without encryption
 * Property: Sensitive data written to files must be encrypted
 */
function verifyCWE313(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const SENSITIVE_RE = /\b(password|secret|token|api.?key|private.?key|ssn|credit.?card|credentials?)\b/i;
  const FILE_WRITE_RE = /\b(writeFile|writeFileSync|appendFile|createWriteStream|fwrite|file_put_contents|open\s*\(.*['"]w|fprintf|fputs|dump|save|to_file|write_text)\b/i;
  const ENCRYPT_SAFE_RE = /\bencrypt\s*\(|\bAES\b|\bcipher\s*\(|\bcreateCipher\w*\b|\bCryptoJS\b|\bfernet\b|\bgpg\b|\bpgp\b|\b\.seal\s*\(/i;

  // Find file-write STORAGE nodes
  const fileStores = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'EXTERNAL') &&
    (n.node_subtype.includes('file') || n.node_subtype.includes('fs') ||
     n.attack_surface.includes('file_access') ||
     FILE_WRITE_RE.test(n.code_snapshot))
  );

  for (const store of fileStores) {
    const code = stripComments(store.code_snapshot);
    // Does this file write contain sensitive data?
    const hasSensitive = SENSITIVE_RE.test(code) || SENSITIVE_RE.test(store.label) ||
      store.data_in.some(d => d.sensitivity !== 'NONE' || SENSITIVE_RE.test(d.name));

    if (!hasSensitive) continue;
    if (ENCRYPT_SAFE_RE.test(code)) continue;

    // Check if encryption happens upstream in the containing function
    const parentFn = findContainingFunction(map, store.id);
    if (parentFn) {
      const parentNode = map.nodes.find(n => n.id === parentFn);
      if (parentNode && ENCRYPT_SAFE_RE.test(stripComments(parentNode.code_snapshot))) continue;
    }

    findings.push({
      source: nodeRef(store),
      sink: nodeRef(store),
      missing: 'TRANSFORM (encryption before writing sensitive data to file)',
      severity: 'high',
      description: `Sensitive data written to file in cleartext at ${store.label}. ` +
        `Files on disk can be read by other processes, backed up unencrypted, or leaked via misconfigured permissions.`,
      fix: 'Encrypt sensitive data before writing to files. Use AES-256-GCM for field-level encryption. ' +
        'Consider using OS-level encrypted storage or a secrets manager instead of plain files. ' +
        'Set restrictive file permissions (0600) as defense in depth.',
    });
  }

  return {
    cwe: 'CWE-313',
    name: 'Cleartext Storage in a File',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-314: Cleartext Storage in the Registry
 * Pattern: Sensitive data written to registry/system-store nodes without encryption
 * Property: Sensitive data in system registries (Windows Registry, plist, etc.) must be encrypted
 *
 * Note: This is mostly a Windows/.NET CWE but can apply to any key-value system store.
 */
function verifyCWE314(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const SENSITIVE_RE = /\b(password|secret|token|api.?key|private.?key|credentials?|license.?key)\b/i;
  const REGISTRY_RE = /\b(Registry|RegKey|HKEY_|RegSetValue|RegCreateKey|reg\.set|winreg|OpenKey|SetValueEx|NSUserDefaults|UserDefaults|SharedPreferences|putString|putExtra|CFPreferences|localStorage\.setItem|sessionStorage\.setItem)\b/i;
  const ENCRYPT_SAFE_RE = /\bencrypt\s*\(|\bAES\b|\bcipher\s*\(|\bcreateCipher\w*\b|\bDPAPI\b|\bProtectedData\b|\bCryptProtectData\b|\bKeychain\b|\bKeyStore\b|\bEncryptedSharedPreferences\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    if (!REGISTRY_RE.test(code)) continue;
    if (!SENSITIVE_RE.test(code) && !node.data_in.some(d => d.sensitivity !== 'NONE')) continue;
    if (ENCRYPT_SAFE_RE.test(code)) continue;

    findings.push({
      source: nodeRef(node),
      sink: nodeRef(node),
      missing: 'TRANSFORM (encryption before storing sensitive data in registry/system store)',
      severity: 'high',
      description: `Sensitive data stored in cleartext in system registry/store at ${node.label}. ` +
        `Registry values are readable by other applications and persist across reboots.`,
      fix: 'Encrypt sensitive values before storing in the registry. On Windows, use DPAPI (ProtectedData.Protect). ' +
        'On macOS/iOS, use Keychain. On Android, use EncryptedSharedPreferences. ' +
        'Never store plaintext passwords or API keys in system registries.',
    });
  }

  return {
    cwe: 'CWE-314',
    name: 'Cleartext Storage in the Registry',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-315: Cleartext Storage of Sensitive Information in a Cookie
 * Pattern: Sensitive data written to cookies without encryption
 * Property: Sensitive data in cookies must be encrypted and use secure flags
 */
function verifyCWE315(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const SENSITIVE_RE = /\b(password|secret|token|api.?key|ssn|credit.?card|session.?id|auth.?token|user.?id|email|private.?key)\b/i;
  const COOKIE_RE = /\b(setCookie|set-cookie|res\.cookie|response\.cookie|document\.cookie|Set-Cookie|cookies?\.\s*set|setcookie|http\.SetCookie|add_cookie|Cookie\()\b/i;
  const COOKIE_SUBTYPE_RE = /cookie/i;
  const ENCRYPT_SAFE_RE = /\bencrypt\s*\(|\bAES\b|\bcipher\s*\(|\bcreateCipher\w*\b|\bjwt\.sign\b|\bJWS\b|\bJWE\b|\bsign\s*\(.*\bsecret\b|\bsigned\s*[:=]\s*true\b|\bsecure\s*[:=]\s*true\b|\bhttpOnly\s*[:=]\s*true\b/i;

  // Find cookie-setting nodes
  const cookieNodes = map.nodes.filter(n =>
    COOKIE_RE.test(n.code_snapshot) ||
    COOKIE_SUBTYPE_RE.test(n.node_subtype) ||
    n.attack_surface.includes('cookie')
  );

  for (const cookie of cookieNodes) {
    const code = stripComments(cookie.code_snapshot);
    const hasSensitive = SENSITIVE_RE.test(code) || SENSITIVE_RE.test(cookie.label) ||
      cookie.data_in.some(d => d.sensitivity !== 'NONE' || SENSITIVE_RE.test(d.name));

    if (!hasSensitive) continue;
    if (ENCRYPT_SAFE_RE.test(code)) continue;

    // Check containing function for encryption
    const parentFn = findContainingFunction(map, cookie.id);
    if (parentFn) {
      const parentNode = map.nodes.find(n => n.id === parentFn);
      if (parentNode && ENCRYPT_SAFE_RE.test(stripComments(parentNode.code_snapshot))) continue;
    }

    findings.push({
      source: nodeRef(cookie),
      sink: nodeRef(cookie),
      missing: 'TRANSFORM (encryption and secure cookie flags)',
      severity: 'high',
      description: `Sensitive data stored in cleartext in a cookie at ${cookie.label}. ` +
        `Cookies are sent with every request and can be intercepted, read by JavaScript, or stolen via XSS.`,
      fix: 'Encrypt sensitive cookie values. Use signed/encrypted cookies (e.g., jwt.sign or cookie-parser with secret). ' +
        'Set flags: httpOnly: true (prevents JS access), secure: true (HTTPS only), sameSite: "strict". ' +
        'Prefer server-side sessions over storing sensitive data in cookies.',
    });
  }

  return {
    cwe: 'CWE-315',
    name: 'Cleartext Storage of Sensitive Information in a Cookie',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-316: Cleartext Storage of Sensitive Information in Memory
 * Pattern: Sensitive data held in memory without scrubbing after use
 * Property: Sensitive data (passwords, keys) should be zeroed/cleared from memory when no longer needed
 *
 * Note: This is difficult to detect statically in garbage-collected languages.
 * We focus on the most detectable patterns: logging sensitive data, caching secrets in global scope.
 */
function verifyCWE316(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const SECRET_RE = /\b(password|secret|private.?key|api.?key|token|credentials?|auth.?token|encryption.?key)\b/i;
  // Patterns that expose secrets in memory beyond their needed scope
  const MEMORY_EXPOSE_RE = /\bglobal\b|\bwindow\.\b|\bprocess\.\b.*(?:password|secret|key|token)|\bcache\b.*(?:password|secret|key|token)|(?:password|secret|key|token).*\bcache\b|\bstatic\s+(?:final\s+)?(?:String|string)\s+\w*(?:PASSWORD|SECRET|KEY|TOKEN)/i;
  // Logging sensitive data is a CWE-316 variant — keeps it in log buffers
  const LOG_EXPOSE_RE = /\b(console\.log|logger?\.\w+|print|puts|System\.out|NSLog|Log\.)\b.*\b(password|secret|key|token|credentials?)\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);

    // Check for logging sensitive data
    if (LOG_EXPOSE_RE.test(code)) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'CONTROL (sensitive data scrubbing before logging)',
        severity: 'medium',
        description: `Sensitive data logged at ${node.label}. ` +
          `Log entries persist in memory buffers, log files, and log aggregation services.`,
        fix: 'Never log passwords, tokens, or secret keys. Redact sensitive fields before logging. ' +
          'Use structured logging with field-level redaction. Example: log({ user: id, password: "[REDACTED]" }).',
      });
      continue;
    }

    // Check for sensitive data cached in global/static scope
    if (SECRET_RE.test(code) && MEMORY_EXPOSE_RE.test(code)) {
      // Skip environment variable reads — those are expected to be in process memory
      if (/\bprocess\.env\b|\bos\.environ\b|\bos\.getenv\b/i.test(code)) continue;

      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'CONTROL (memory scrubbing — clear sensitive data after use)',
        severity: 'medium',
        description: `Sensitive data held in long-lived memory at ${node.label}. ` +
          `Global/static/cached secrets remain in process memory and can be extracted via memory dumps.`,
        fix: 'Minimize the lifetime of sensitive data in memory. Zero buffers after use. ' +
          'In Node.js, use Buffer.alloc() and buf.fill(0) when done. Avoid caching secrets in global scope. ' +
          'In languages with manual memory management, explicitly zero and free secret buffers.',
      });
    }
  }

  return {
    cwe: 'CWE-316',
    name: 'Cleartext Storage of Sensitive Information in Memory',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-319: Cleartext Transmission of Sensitive Information
 * Pattern: Sensitive data sent over HTTP (not HTTPS), or via unencrypted network channels
 * Property: Sensitive data must be transmitted over encrypted channels (TLS/HTTPS)
 */
function verifyCWE319(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const SENSITIVE_RE = /\b(password|secret|token|api.?key|ssn|credit.?card|private.?key|auth|credentials?|session)\b/i;
  // HTTP (not HTTPS) URLs — cleartext transmission
  const HTTP_CLEARTEXT_RE = /['"]http:\/\/[^'"]+/i;
  // Network calls that might use cleartext
  const NET_CALL_RE = /\b(fetch|axios|request|http\.get|http\.post|urllib|requests\.\w+|HttpClient|WebClient|curl|XMLHttpRequest|ajax)\b/i;
  // Safe: HTTPS, TLS, SSL
  const TLS_SAFE_RE = /\bhttps:\/\/\b|\bTLS\b|\bSSL\b|\bsecure\s*[:=]\s*true\b|\brejectUnauthorized\b|\bcert\b|\btls\.\b/i;
  // FTP (not SFTP/FTPS)
  const FTP_CLEARTEXT_RE = /['"]ftp:\/\/[^'"]+/i;
  // Telnet
  const TELNET_RE = /\btelnet\b/i;

  // Strategy 1: Find EGRESS/EXTERNAL nodes that transmit data over HTTP
  const netNodes = map.nodes.filter(n =>
    (n.node_type === 'EGRESS' || n.node_type === 'EXTERNAL') &&
    (NET_CALL_RE.test(n.code_snapshot) ||
     n.node_subtype.includes('http') || n.node_subtype.includes('network') ||
     n.node_subtype.includes('api_call') || n.attack_surface.includes('network'))
  );

  for (const netNode of netNodes) {
    const code = stripComments(netNode.code_snapshot);

    // Check for explicit HTTP:// URLs (not HTTPS)
    if (HTTP_CLEARTEXT_RE.test(code) && !TLS_SAFE_RE.test(code)) {
      // Does this node handle sensitive data?
      const hasSensitive = SENSITIVE_RE.test(code) || SENSITIVE_RE.test(netNode.label) ||
        netNode.data_in.some(d => d.sensitivity !== 'NONE' || SENSITIVE_RE.test(d.name));

      if (hasSensitive) {
        findings.push({
          source: nodeRef(netNode),
          sink: nodeRef(netNode),
          missing: 'CONTROL (TLS/HTTPS encryption for sensitive data transmission)',
          severity: 'high',
          description: `Sensitive data transmitted over cleartext HTTP at ${netNode.label}. ` +
            `HTTP traffic can be intercepted and read by anyone on the network path (MITM attack).`,
          fix: 'Use HTTPS (TLS) for all endpoints that handle sensitive data. ' +
            'Replace http:// with https:// in all API URLs. Configure HSTS headers. ' +
            'In production, enforce TLS 1.2+ and reject downgrade attempts.',
        });
        continue;
      }
    }

    // Check for FTP (not SFTP)
    if (FTP_CLEARTEXT_RE.test(code) && SENSITIVE_RE.test(code)) {
      findings.push({
        source: nodeRef(netNode),
        sink: nodeRef(netNode),
        missing: 'CONTROL (SFTP/FTPS instead of cleartext FTP)',
        severity: 'high',
        description: `Sensitive data transmitted over cleartext FTP at ${netNode.label}. ` +
          `FTP sends credentials and data in plaintext.`,
        fix: 'Use SFTP or FTPS instead of plain FTP. Never transmit sensitive data over unencrypted channels.',
      });
      continue;
    }

    // Check for telnet
    if (TELNET_RE.test(code) && SENSITIVE_RE.test(code)) {
      findings.push({
        source: nodeRef(netNode),
        sink: nodeRef(netNode),
        missing: 'CONTROL (SSH instead of cleartext Telnet)',
        severity: 'high',
        description: `Sensitive data transmitted over Telnet at ${netNode.label}. ` +
          `Telnet sends all data including passwords in plaintext.`,
        fix: 'Use SSH instead of Telnet. Never use unencrypted protocols for sensitive data.',
      });
    }
  }

  // Strategy 2: Check INGRESS nodes that accept data over HTTP
  const httpIngress = map.nodes.filter(n =>
    n.node_type === 'INGRESS' &&
    HTTP_CLEARTEXT_RE.test(stripComments(n.code_snapshot)) &&
    !TLS_SAFE_RE.test(stripComments(n.code_snapshot))
  );

  for (const ing of httpIngress) {
    const code = stripComments(ing.code_snapshot);
    if (SENSITIVE_RE.test(code) || ing.data_in.some(d => d.sensitivity !== 'NONE')) {
      const already = findings.some(f => f.source.id === ing.id);
      if (!already) {
        findings.push({
          source: nodeRef(ing),
          sink: nodeRef(ing),
          missing: 'CONTROL (HTTPS/TLS for receiving sensitive data)',
          severity: 'high',
          description: `Sensitive data received over cleartext HTTP at ${ing.label}. ` +
            `An attacker on the network can intercept passwords, tokens, and PII in transit.`,
          fix: 'Serve all sensitive endpoints over HTTPS. Redirect HTTP to HTTPS. ' +
            'Use HSTS (Strict-Transport-Security header) to prevent downgrade attacks.',
        });
      }
    }
  }

  return {
    cwe: 'CWE-319',
    name: 'Cleartext Transmission of Sensitive Information',
    holds: findings.length === 0,
    findings,
  };
}

// ---------------------------------------------------------------------------
// AUTHENTICATION & CREDENTIAL CWE Verification Paths
// ---------------------------------------------------------------------------

/**
 * CWE-287: Improper Authentication
 * Pattern: INGRESS → sensitive STORAGE/EXTERNAL without AUTH node in path
 * Property: All sensitive operations are gated by proper authentication checks.
 *
 * Unlike CWE-306 (Missing Authentication for Critical Function), CWE-287 is broader:
 * it covers cases where authentication exists but is IMPROPERLY implemented —
 * e.g., checking username but not password, using client-side auth only,
 * or accepting self-signed identity tokens without server-side validation.
 *
 * Detection strategy:
 *  1. Find INGRESS → sensitive sinks without ANY auth node
 *  2. Find AUTH nodes that use weak/improper patterns (client-only checks, always-true)
 */
function verifyCWE287(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');
  const authNodes = nodesOfType(map, 'AUTH');

  // Auth middleware patterns in source code_snapshot — if present, the route is protected
  // even if there's no explicit AUTH node in the graph (middleware runs before handler).
  const authMiddlewarePattern = /\b(passport\.authenticate|requireAuth|isAuthenticated|ensureAuthenticated|authMiddleware|verifyToken|requireLogin|checkAuth|jwt\.verify|authGuard)\b/i;

  // Sensitive operations: STORAGE (including database reads with protected_resource),
  // EXTERNAL calls, admin endpoints, writes, deletes
  const sensitiveSinks = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'EXTERNAL') &&
    (n.node_subtype.includes('write') || n.node_subtype.includes('delete') ||
     n.node_subtype.includes('update') || n.node_subtype.includes('admin') ||
     n.node_subtype.includes('db_write') || n.node_subtype.includes('database') ||
     n.attack_surface.includes('sensitive') || n.attack_surface.includes('admin') ||
     n.attack_surface.includes('protected_resource') ||
     n.code_snapshot.match(/\b(delete|remove|update|insert|drop|admin|modify|destroy|grant|revoke|createUser|changeRole|findOne|find|query)\b/i) !== null)
  );

  // Strategy 1: INGRESS → sensitive sink with NO auth node in the path
  for (const src of ingress) {
    // Skip if the source code_snapshot references auth middleware (route-level protection)
    if (authMiddlewarePattern.test(src.code_snapshot)) continue;

    for (const sink of sensitiveSinks) {
      if (hasTaintedPathWithoutAuth(map, src.id, sink.id)) {
        findings.push({
          source: nodeRef(src),
          sink: nodeRef(sink),
          missing: 'AUTH (proper authentication check before sensitive operation)',
          severity: 'critical',
          description: `Request from ${src.label} reaches sensitive operation ${sink.label} without authentication. ` +
            `Any unauthenticated user can perform this action.`,
          fix: 'Add server-side authentication middleware that validates credentials or session tokens. ' +
            'Use established libraries (passport.js, flask-login, Spring Security). ' +
            'Never rely on client-side authentication checks alone.',
        });
      }
    }
  }

  // Strategy 2: AUTH nodes with improper implementation
  const weakAuthPatterns = [
    /\btrue\b\s*;\s*$/m,                      // always returns true
    /return\s+true/i,                           // unconditional return true in auth
    /isAdmin\s*[:=]\s*req\.(body|query|params)/i, // role from user input
    /role\s*[:=]\s*req\.(body|query)/i,         // role assignment from request body
    /if\s*\(\s*username\s*\)\s*\{/i,            // checks username exists but not password
    /auth.*skip|bypass.*auth|disable.*auth/i,   // explicit auth bypass
  ];

  for (const authNode of authNodes) {
    const code = stripComments(authNode.code_snapshot);
    for (const pattern of weakAuthPatterns) {
      if (pattern.test(code)) {
        findings.push({
          source: nodeRef(authNode),
          sink: nodeRef(authNode),
          missing: 'AUTH (proper credential validation — current check is weak or bypassable)',
          severity: 'critical',
          description: `Authentication at ${authNode.label} uses an improper pattern that can be bypassed. ` +
            `The auth check appears to always succeed, check only partial credentials, or accept user-controlled role claims.`,
          fix: 'Implement proper authentication: validate both username AND password against a secure store. ' +
            'Never derive authorization roles from user input. ' +
            'Never hardcode auth bypasses in production code.',
        });
        break;
      }
    }
  }

  return {
    cwe: 'CWE-287',
    name: 'Improper Authentication',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-288: Authentication Bypass Using an Alternate Path or Channel
 * Pattern: Multiple INGRESS nodes reach the same sensitive sink, but only SOME paths
 *          have AUTH nodes — at least one alternate path bypasses auth entirely.
 *
 * Classic examples: admin panel accessible via /admin AND /api/admin (API lacks auth),
 * debug endpoints that skip auth, alternative protocols (HTTP vs WebSocket).
 *
 * Detection: For each sensitive sink reachable via an authenticated path,
 * check if ANY other INGRESS can reach the same sink WITHOUT auth.
 */
function verifyCWE288(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  const sensitiveSinks = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'EXTERNAL') &&
    (n.node_subtype.includes('write') || n.node_subtype.includes('delete') ||
     n.node_subtype.includes('update') || n.node_subtype.includes('admin') ||
     n.attack_surface.includes('sensitive') ||
     n.code_snapshot.match(/\b(delete|remove|update|insert|admin|modify|destroy)\b/i) !== null)
  );

  // Alternate path patterns: debug routes, internal APIs, websockets
  const altPathPattern = /\b(debug|internal|_internal|test|backdoor|ws:\/\/|websocket|socket\.on|graphql|grpc)\b/i;

  for (const sink of sensitiveSinks) {
    // Find all INGRESS nodes that can reach this sink
    const authedPaths: NeuralMapNode[] = [];
    const unauthedPaths: NeuralMapNode[] = [];

    for (const src of ingress) {
      // Check if there is an unauthed taint path
      if (hasTaintedPathWithoutAuth(map, src.id, sink.id)) {
        unauthedPaths.push(src);
      } else {
        // Check if there is ANY taint path (which means it exists but goes through AUTH)
        if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
          authedPaths.push(src);
        }
      }
    }

    // CWE-288 fires when SOME paths are authed but OTHERS are not
    if (authedPaths.length > 0 && unauthedPaths.length > 0) {
      for (const bypass of unauthedPaths) {
        findings.push({
          source: nodeRef(bypass),
          sink: nodeRef(sink),
          missing: 'AUTH (authentication on alternate path — other paths to the same sink ARE authenticated)',
          severity: 'critical',
          description: `${bypass.label} can reach ${sink.label} without authentication, but other paths to the same operation require auth. ` +
            `An attacker can bypass authentication by using the unprotected alternate path.`,
          fix: 'Ensure ALL paths to sensitive operations require authentication. ' +
            'Apply auth middleware at the operation/service layer, not just at individual routes. ' +
            'Audit debug endpoints, internal APIs, WebSocket handlers, and GraphQL resolvers.',
        });
      }
    }

    // Also flag INGRESS nodes with alt-path patterns that reach sinks without auth
    if (authedPaths.length === 0 && unauthedPaths.length > 0) {
      for (const bypass of unauthedPaths) {
        if (altPathPattern.test(bypass.code_snapshot) || altPathPattern.test(bypass.label)) {
          findings.push({
            source: nodeRef(bypass),
            sink: nodeRef(sink),
            missing: 'AUTH (authentication on debug/internal/alternate endpoint)',
            severity: 'high',
            description: `Alternate endpoint ${bypass.label} (debug/internal/websocket) reaches ${sink.label} without authentication. ` +
              `These alternate channels are often deployed to production without auth.`,
            fix: 'Remove debug/test endpoints from production builds. ' +
              'If internal APIs must exist, protect them with the same auth as primary endpoints. ' +
              'Use environment-based feature flags to disable debug routes.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-288',
    name: 'Authentication Bypass Using Alternate Path or Channel',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-290: Authentication Bypass by Spoofing
 * Pattern: AUTH or CONTROL nodes that make decisions based on spoofable inputs:
 *          IP addresses (X-Forwarded-For, REMOTE_ADDR behind proxies),
 *          DNS names, Referer headers, or client-side cookies without HMAC.
 *
 * Detection: Scan AUTH/CONTROL nodes for spoofable-source patterns in code_snapshot.
 */
function verifyCWE290(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Spoofable source patterns in code — these are NOT reliable for authentication
  const spoofablePatterns: Array<{ pattern: RegExp; desc: string }> = [
    {
      pattern: /\b(x[_-]forwarded[_-]for|x[_-]real[_-]ip|x[_-]client[_-]ip|cf[_-]connecting[_-]ip)\b/i,
      desc: 'IP address from X-Forwarded-For/X-Real-IP header (trivially spoofable)',
    },
    {
      pattern: /\bremote[_-]?addr\b.*\b(auth|allow|trust|whitelist|grant)\b|\b(auth|allow|trust|whitelist|grant)\b.*\bremote[_-]?addr\b/i,
      desc: 'IP-based authentication (spoofable behind proxies, NAT)',
    },
    {
      pattern: /\b(referer|referrer)\b.*\b(check|verify|auth|valid|allow)\b|\b(check|verify|auth|valid|allow)\b.*\b(referer|referrer)\b/i,
      desc: 'Referer header-based authentication (trivially spoofable)',
    },
    {
      pattern: /\b(dns[_-]?lookup|reverse[_-]?dns|gethostbyaddr|gethostbyname)\b.*\b(auth|trust|allow)\b/i,
      desc: 'DNS-based authentication (spoofable via DNS poisoning)',
    },
    {
      pattern: /\b(origin)\b\s*===?\s*['"][^'"]+['"]/i,
      desc: 'Origin header comparison for authentication (can be spoofed in non-browser contexts)',
    },
  ];

  // Check AUTH and CONTROL nodes for spoofable source usage
  const authAndControl = map.nodes.filter(n =>
    n.node_type === 'AUTH' || n.node_type === 'CONTROL'
  );

  for (const node of authAndControl) {
    const code = stripComments(node.code_snapshot);
    for (const { pattern, desc } of spoofablePatterns) {
      if (pattern.test(code)) {
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'AUTH (non-spoofable authentication mechanism — use cryptographic tokens instead of network metadata)',
          severity: 'high',
          description: `${node.label} uses ${desc} for security decisions. ` +
            `These values are controlled by the client or intermediary proxies and can be forged.`,
          fix: 'Never use IP addresses, DNS names, Referer headers, or Origin headers as the sole authentication mechanism. ' +
            'Use cryptographic tokens (JWT, session cookies with HMAC, mutual TLS) for identity verification. ' +
            'IP-based restrictions are acceptable as ADDITIONAL defense-in-depth but never as primary auth.',
        });
        break;
      }
    }
  }

  // Also check INGRESS nodes that read spoofable headers and flow to AUTH
  const spoofableIngress = map.nodes.filter(n =>
    n.node_type === 'INGRESS' &&
    /\b(x[_-]forwarded[_-]for|x[_-]real[_-]ip|referer|referrer|remote[_-]?addr)\b/i.test(n.code_snapshot)
  );

  for (const src of spoofableIngress) {
    for (const authNode of authAndControl) {
      if (hasTaintedPathWithoutControl(map, src.id, authNode.id)) {
        // The spoofable header flows into an auth decision without validation
        const hasIntegrityCheck = stripComments(authNode.code_snapshot).match(
          /\bhmac\b|\bsignature\b|\bcryptographic\b|\bjwt\b|\bverify\s*\(.*\btoken\b|\bverifyToken\b/i
        ) !== null;

        if (!hasIntegrityCheck) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(authNode),
            missing: 'AUTH (cryptographic identity verification instead of spoofable header)',
            severity: 'high',
            description: `Spoofable header from ${src.label} flows to auth decision at ${authNode.label}. ` +
              `An attacker can forge this header to bypass authentication.`,
            fix: 'Replace header-based auth with cryptographic authentication (JWT, session tokens, mutual TLS). ' +
              'If IP-based restrictions are needed, enforce them at the network/firewall level, not in application code.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-290',
    name: 'Authentication Bypass by Spoofing',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-294: Authentication Bypass by Capture-Replay
 * Pattern: AUTH nodes that use static tokens, single-use tokens reused,
 *          or authentication without nonce/timestamp/challenge-response.
 *
 * Detection: Find AUTH nodes that validate tokens/credentials without
 * replay protection (no nonce, no timestamp check, no TOTP/HOTP).
 * Also flags: session tokens sent over non-HTTPS, no token expiry.
 */
function verifyCWE294(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const authNodes = nodesOfType(map, 'AUTH');

  // Replay protection patterns — if present, the auth is likely protected
  const replayProtectionPattern = /\b(nonce|timestamp|exp|expires|expiresIn|maxAge|ttl|totp|hotp|challenge|one[_-]?time|otp|replay[_-]?check|used[_-]?tokens?|token[_-]?blacklist|jti)\b/i;

  // Static/hardcoded token patterns that are vulnerable to replay
  const staticTokenPatterns = [
    /api[_-]?key\s*===?\s*['"][^'"]+['"]/i,      // hardcoded API key comparison
    /token\s*===?\s*['"][^'"]+['"]/i,              // hardcoded token comparison
    /secret\s*===?\s*['"][^'"]+['"]/i,             // hardcoded secret comparison
    /\b(compare|equals)\s*\(\s*['"][^'"]{8,}['"]/i, // comparing against static string
  ];

  for (const authNode of authNodes) {
    const code = stripComments(authNode.code_snapshot);

    // Check for static token comparison (most obvious replay vulnerability)
    for (const pattern of staticTokenPatterns) {
      if (pattern.test(code)) {
        // Only flag if there's no replay protection
        if (!replayProtectionPattern.test(code)) {
          findings.push({
            source: nodeRef(authNode),
            sink: nodeRef(authNode),
            missing: 'AUTH (replay protection — nonce, timestamp, or one-time token)',
            severity: 'high',
            description: `Authentication at ${authNode.label} compares against a static token without replay protection. ` +
              `An attacker who captures this token (via network sniffing, logs, or client-side inspection) can reuse it indefinitely.`,
            fix: 'Use time-limited tokens with expiry (JWT with exp claim). ' +
              'Add nonce or challenge-response to prevent replay. ' +
              'Rotate API keys regularly. Use HTTPS to prevent capture.',
          });
          break;
        }
      }
    }

    // Check for basic auth without TLS indication in the same scope
    if (/\b(basic[_-]?auth|authorization.*basic|atob|base64decode)\b/i.test(code)) {
      if (!replayProtectionPattern.test(code)) {
        findings.push({
          source: nodeRef(authNode),
          sink: nodeRef(authNode),
          missing: 'AUTH (replay protection for Basic Auth — credentials are sent in cleartext per request)',
          severity: 'medium',
          description: `${authNode.label} uses HTTP Basic Authentication. ` +
            `Credentials are base64-encoded (NOT encrypted) and sent with every request, making capture-replay trivial without HTTPS.`,
          fix: 'If Basic Auth is required, ensure HTTPS is enforced (redirect HTTP to HTTPS). ' +
            'Prefer token-based authentication (JWT, OAuth2) with expiry. ' +
            'Add rate limiting to slow brute-force attacks with captured credentials.',
        });
      }
    }
  }

  return {
    cwe: 'CWE-294',
    name: 'Authentication Bypass by Capture-Replay',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-295: Improper Certificate Validation
 * Pattern: EXTERNAL (HTTP/TLS) nodes where certificate validation is explicitly disabled.
 *          e.g., rejectUnauthorized: false, NODE_TLS_REJECT_UNAUTHORIZED=0,
 *          verify=False (Python requests), InsecureSkipVerify: true (Go),
 *          -k / --insecure (curl).
 *
 * Detection: Scan ALL nodes for certificate-disabling patterns in code_snapshot.
 * Unlike flow-based CWEs, this is a static configuration scan.
 */
function verifyCWE295(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Patterns that DISABLE certificate validation — language-specific
  const certDisablePatterns: Array<{ pattern: RegExp; lang: string; desc: string }> = [
    {
      pattern: /rejectUnauthorized\s*:\s*false/i,
      lang: 'Node.js',
      desc: 'rejectUnauthorized: false disables TLS certificate validation',
    },
    {
      pattern: /NODE_TLS_REJECT_UNAUTHORIZED\s*=\s*['"]?0/i,
      lang: 'Node.js',
      desc: 'NODE_TLS_REJECT_UNAUTHORIZED=0 disables ALL TLS validation globally',
    },
    {
      pattern: /process\.env\s*\[\s*['"]NODE_TLS_REJECT_UNAUTHORIZED['"]\s*\]\s*=\s*['"]?0/i,
      lang: 'Node.js',
      desc: 'Programmatic global TLS disable via process.env',
    },
    {
      pattern: /verify\s*=\s*False/,
      lang: 'Python',
      desc: 'requests.get(url, verify=False) disables certificate verification',
    },
    {
      pattern: /CERT_NONE|ssl\._create_unverified_context|check_hostname\s*=\s*False/i,
      lang: 'Python',
      desc: 'SSL context with certificate verification disabled',
    },
    {
      pattern: /InsecureSkipVerify\s*:\s*true/i,
      lang: 'Go',
      desc: 'InsecureSkipVerify: true disables TLS certificate validation',
    },
    {
      pattern: /curl\b.*\s-k\b|curl\b.*--insecure/i,
      lang: 'Shell/curl',
      desc: 'curl --insecure / -k disables certificate validation',
    },
    {
      pattern: /CURLOPT_SSL_VERIFYPEER\s*,\s*(false|0|FALSE)/i,
      lang: 'PHP/C',
      desc: 'CURLOPT_SSL_VERIFYPEER disabled',
    },
    {
      pattern: /ServerCertificateValidationCallback\s*=.*=>\s*true|ServicePointManager\.ServerCertificateValidationCallback/i,
      lang: '.NET',
      desc: 'ServerCertificateValidationCallback always returns true',
    },
    {
      pattern: /\.danger_accept_invalid_certs\s*\(\s*true\s*\)/i,
      lang: 'Rust',
      desc: 'danger_accept_invalid_certs(true) disables cert validation',
    },
  ];

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    for (const { pattern, lang, desc } of certDisablePatterns) {
      if (pattern.test(code)) {
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'CONTROL (TLS certificate validation — currently disabled)',
          severity: 'critical',
          description: `${node.label} disables certificate validation [${lang}]: ${desc}. ` +
            `This allows man-in-the-middle attacks — an attacker on the network can intercept, read, and modify all traffic.`,
          fix: 'NEVER disable certificate validation in production. ' +
            'If connecting to services with self-signed certs, add the CA to the trust store instead. ' +
            'For development, use environment-specific configuration that is NEVER deployed to production.',
        });
        break;
      }
    }
  }

  return {
    cwe: 'CWE-295',
    name: 'Improper Certificate Validation',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-296: Improper Following of a Certificate's Chain of Trust
 * Pattern: TLS/SSL configuration that doesn't validate the full certificate chain.
 *          e.g., custom SSL contexts that skip chain verification, accepting self-signed
 *          certs without pinning, custom trust managers that accept all certificates.
 *
 * Detection: Scan for custom TLS/SSL context creation that skips chain validation.
 */
function verifyCWE296(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Patterns that break the chain of trust
  const chainBreakPatterns: Array<{ pattern: RegExp; desc: string }> = [
    {
      pattern: /TrustManager|X509TrustManager|checkServerTrusted\s*\([^)]*\)\s*\{[\s\S]{0,20}\}/i,
      desc: 'Custom TrustManager that may accept all certificates without chain validation',
    },
    {
      pattern: /SSLContext\.getInstance.*\btrust.*=.*new\b.*TrustManager/i,
      desc: 'Custom SSLContext with custom TrustManager (potentially bypasses chain validation)',
    },
    {
      pattern: /createSSLContext|ssl\.create_default_context.*\bload_default_certs\s*=\s*False/i,
      desc: 'Custom SSL context that skips loading default CA certificates',
    },
    {
      pattern: /ca\s*:\s*\[\s*\]|ca\s*:\s*undefined|ca\s*:\s*null/i,
      desc: 'Empty or null CA list — no chain of trust can be established',
    },
    {
      pattern: /setDefaultSSLSocketFactory|AllowAllHostnameVerifier|NoopHostnameVerifier|ALLOW_ALL_HOSTNAME_VERIFIER/i,
      desc: 'Hostname verifier that accepts all hostnames regardless of certificate CN/SAN',
    },
    {
      pattern: /\.selfSigned\s*\(\s*true\s*\)|self[_-]?signed\s*[:=]\s*true/i,
      desc: 'Explicitly accepting self-signed certificates without pinning',
    },
    {
      pattern: /checkRevocation\s*[:=]\s*false|enableOCSP\s*[:=]\s*false|disableCRL/i,
      desc: 'Revocation checking disabled — cannot detect compromised certificates',
    },
  ];

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    for (const { pattern, desc } of chainBreakPatterns) {
      if (pattern.test(code)) {
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'CONTROL (proper certificate chain validation using system CA store)',
          severity: 'high',
          description: `${node.label}: ${desc}. ` +
            `Without full chain-of-trust validation, the application cannot verify the identity of remote servers, ` +
            `enabling man-in-the-middle attacks.`,
          fix: 'Use the system CA certificate store for chain validation. ' +
            'Do not implement custom TrustManagers unless you are adding certificate pinning. ' +
            'If self-signed certs are needed, add the specific CA to the trust store rather than disabling chain validation. ' +
            'Enable OCSP/CRL checking for revocation detection.',
        });
        break;
      }
    }
  }

  return {
    cwe: 'CWE-296',
    name: 'Improper Following of Chain of Trust',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-297: Improper Validation of Certificate with Host Mismatch
 * Pattern: TLS connections where hostname verification is disabled or overridden.
 *          A valid certificate for evil.com could be presented for bank.com if
 *          hostname matching is skipped.
 *
 * Detection: Scan for hostname verification disabling patterns.
 */
function verifyCWE297(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  const hostMismatchPatterns: Array<{ pattern: RegExp; desc: string }> = [
    {
      pattern: /checkServerIdentity\s*:\s*\(\s*\)\s*=>|checkServerIdentity\s*:\s*function\s*\(\s*\)\s*\{/i,
      desc: 'Node.js checkServerIdentity overridden with no-op function — hostname matching disabled',
    },
    {
      pattern: /AllowAllHostnameVerifier|NoopHostnameVerifier|ALLOW_ALL_HOSTNAME_VERIFIER/i,
      desc: 'Java/Android hostname verifier accepts all hostnames',
    },
    {
      pattern: /check_hostname\s*=\s*False/i,
      desc: 'Python SSL check_hostname disabled — any certificate accepted regardless of hostname',
    },
    {
      pattern: /HostnameVerifier\s*\(\s*\)\s*\{[^}]*return\s+true/i,
      desc: 'Custom HostnameVerifier that always returns true',
    },
    {
      pattern: /verify_peer_name\s*[:=]\s*false|ssl_verify_host\s*[:=]\s*0/i,
      desc: 'Peer name verification disabled',
    },
    {
      pattern: /ServerName\s*[:=]\s*['"]['"]|servername\s*:\s*['"]['"]|sni\s*[:=]\s*false/i,
      desc: 'Empty ServerName / SNI disabled — server cannot select the correct certificate',
    },
  ];

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    for (const { pattern, desc } of hostMismatchPatterns) {
      if (pattern.test(code)) {
        findings.push({
          source: nodeRef(node),
          sink: nodeRef(node),
          missing: 'CONTROL (TLS hostname verification — ensure certificate matches the requested host)',
          severity: 'high',
          description: `${node.label}: ${desc}. ` +
            `Without hostname verification, a valid certificate for any domain will be accepted, ` +
            `enabling man-in-the-middle attacks with a legitimately-issued certificate.`,
          fix: 'Never disable hostname verification. Use the default TLS configuration which includes hostname checking. ' +
            'If custom TLS setup is needed, ensure checkServerIdentity (Node.js) or check_hostname (Python) remains enabled. ' +
            'For Java, use the default HostnameVerifier, never AllowAllHostnameVerifier.',
        });
        break;
      }
    }
  }

  return {
    cwe: 'CWE-297',
    name: 'Improper Validation of Certificate with Host Mismatch',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-521: Weak Password Requirements
 * Pattern: AUTH/CONTROL nodes that validate passwords with insufficient constraints.
 *          e.g., minimum length < 8, no complexity requirements, no check against
 *          breached password lists.
 *
 * Also detects: password fields with no validation at all (INGRESS->STORAGE direct).
 *
 * Detection:
 *  1. Find password validation nodes and check if constraints are too weak
 *  2. Find password storage paths with no validation
 */
function verifyCWE521(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Find password-related nodes
  const passwordNodes = map.nodes.filter(n =>
    /\b(password|passwd|pwd|passphrase)\b/i.test(n.code_snapshot) ||
    /\b(password|passwd|pwd)\b/i.test(n.label)
  );

  // Weak length patterns — min length below 8
  const weakLengthPattern = /\.(length|len)\s*(<|<=|>=?|==)\s*[1-7]\b|minlength\s*[:=]\s*[1-7]\b|min\s*[:=]\s*[1-7]\b.*password|password.*min\s*[:=]\s*[1-7]\b/i;

  // Good password validation patterns
  const strongPasswordPattern = /\b(minlength|min[_-]?length)\s*[:=]\s*([89]|\d{2,})\b|\.(length|len)\s*>=?\s*([89]|\d{2,})\b|\b(zxcvbn|haveibeenpwned|breach|complexity|strength)\b/i;

  // Registration/signup patterns — password is being SET (not just checked)
  const passwordSetPattern = /\b(register|signup|sign[_-]?up|create[_-]?user|new[_-]?password|change[_-]?password|reset[_-]?password|set[_-]?password)\b/i;

  for (const node of passwordNodes) {
    const code = stripComments(node.code_snapshot);

    // Check for explicitly weak length requirements
    if (weakLengthPattern.test(code)) {
      findings.push({
        source: nodeRef(node),
        sink: nodeRef(node),
        missing: 'CONTROL (password length requirement >= 8 characters, ideally >= 12)',
        severity: 'medium',
        description: `${node.label} enforces a password length below 8 characters. ` +
          `Short passwords are vulnerable to brute-force and dictionary attacks.`,
        fix: 'Require passwords of at least 8 characters (NIST SP 800-63B recommends 8+, 12+ is better). ' +
          'Use a password strength estimator (zxcvbn). ' +
          'Check passwords against known breached password lists (HaveIBeenPwned API).',
      });
      continue;
    }

    // Check for password storage without ANY validation
    if (passwordSetPattern.test(code) && node.node_type === 'INGRESS') {
      // Find if this password flows to STORAGE without a CONTROL node
      const storageSinks = nodesOfType(map, 'STORAGE');
      for (const sink of storageSinks) {
        if (hasTaintedPathWithoutControl(map, node.id, sink.id)) {
          // No CONTROL between password input and storage — no validation at all
          if (!strongPasswordPattern.test(code)) {
            findings.push({
              source: nodeRef(node),
              sink: nodeRef(sink),
              missing: 'CONTROL (password strength validation before storage)',
              severity: 'medium',
              description: `Password from ${node.label} is stored at ${sink.label} without strength validation. ` +
                `Users can set arbitrarily weak passwords (including empty or single-character).`,
              fix: 'Add password validation before storage: minimum 8 characters, ' +
                'check against breached password lists, use a strength estimator. ' +
                'NIST SP 800-63B: no composition rules (uppercase/special), but enforce minimum length and breach checking.',
            });
            break;
          }
        }
      }
    }
  }

  return {
    cwe: 'CWE-521',
    name: 'Weak Password Requirements',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-522: Insufficiently Protected Credentials
 * Pattern: Credentials transmitted in cleartext or stored without hashing.
 *          e.g., password stored as plaintext in DB, credentials sent over HTTP (not HTTPS),
 *          credentials logged to console/file, passwords in URL query strings.
 *
 * Detection:
 *  1. Password INGRESS->STORAGE without TRANSFORM(hash/encrypt) in between
 *  2. Credentials in query strings or URLs
 *  3. Credentials sent to logging sinks
 */
function verifyCWE522(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ingress = nodesOfType(map, 'INGRESS');

  // Hashing/encryption patterns — these PROTECT credentials
  const hashPattern = /\b(bcrypt|scrypt|argon2|pbkdf2|hash|sha256|sha512|crypto\.hash|hashSync|createHash|password_hash|generate_password_hash|make_password|hashpw)\b/i;

  // Password-related INGRESS nodes
  const passwordIngress = ingress.filter(n =>
    /\b(password|passwd|pwd|passphrase|credential|secret|token)\b/i.test(n.code_snapshot) ||
    /\b(password|passwd|pwd)\b/i.test(n.label)
  );

  // Storage sinks (databases, files)
  const storageSinks = nodesOfType(map, 'STORAGE');

  // Strategy 1: Password stored without hashing
  for (const src of passwordIngress) {
    for (const sink of storageSinks) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        // Check if there's a TRANSFORM node with hashing between them
        const hasHashing = map.nodes.some(n =>
          n.node_type === 'TRANSFORM' && hashPattern.test(n.code_snapshot)
        );

        // Also check if the sink code itself includes hashing
        const sinkHashes = hashPattern.test(stripComments(sink.code_snapshot));

        if (!hasHashing && !sinkHashes) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(sink),
            missing: 'TRANSFORM (password hashing — bcrypt, scrypt, argon2, or PBKDF2)',
            severity: 'critical',
            description: `Password from ${src.label} is stored at ${sink.label} without hashing. ` +
              `If the database is breached, all passwords are exposed in cleartext.`,
            fix: 'ALWAYS hash passwords before storage using bcrypt, scrypt, or argon2id. ' +
              'NEVER store plaintext passwords. NEVER use MD5/SHA1/SHA256 alone (use PBKDF2 with high iterations at minimum). ' +
              'Use a per-user salt (bcrypt includes this automatically).',
          });
        }
      }
    }
  }

  // Strategy 2: Credentials in query strings or URLs
  const queryStringCreds = map.nodes.filter(n =>
    n.node_type === 'INGRESS' &&
    /\b(query|params|searchParams|url)\b/i.test(n.code_snapshot) &&
    /\b(password|passwd|pwd|token|secret|api[_-]?key)\b/i.test(n.code_snapshot)
  );

  for (const node of queryStringCreds) {
    findings.push({
      source: nodeRef(node),
      sink: nodeRef(node),
      missing: 'CONTROL (credentials must be sent in request body or Authorization header, never in URL)',
      severity: 'high',
      description: `${node.label} reads credentials from URL query parameters. ` +
        `Query strings are logged in server access logs, browser history, proxy logs, and Referer headers.`,
      fix: 'Send credentials in the request body (POST) or Authorization header, never in URL query strings. ' +
        'Use HTTPS to encrypt credentials in transit. ' +
        'Implement token-based auth where the token is sent in the Authorization header.',
    });
  }

  // Strategy 3: Credentials sent to logging sinks
  const loggingNodes = map.nodes.filter(n =>
    (n.node_type === 'EGRESS' || n.node_type === 'EXTERNAL') &&
    /\b(log|logger|console\.(log|info|debug|warn|error)|syslog|winston|bunyan|pino|print|fprintf.*stderr)\b/i.test(n.code_snapshot)
  );

  for (const src of passwordIngress) {
    for (const logSink of loggingNodes) {
      if (hasTaintedPathWithoutControl(map, src.id, logSink.id)) {
        // Check if the log entry mentions redaction
        const isRedacted = stripComments(logSink.code_snapshot).match(
          /\bredact\s*\(|\bmask\s*\(|\b\*{3,}\b|\[REDACTED\]|\[FILTERED\]/i
        ) !== null;

        if (!isRedacted) {
          findings.push({
            source: nodeRef(src),
            sink: nodeRef(logSink),
            missing: 'CONTROL (credential redaction before logging)',
            severity: 'high',
            description: `Credential from ${src.label} flows to logging at ${logSink.label} without redaction. ` +
              `Credentials in log files can be read by developers, ops staff, log aggregation services, and attackers who gain log access.`,
            fix: 'Never log credentials. Redact sensitive fields before logging. ' +
              'Use structured logging with an automatic PII/credential filter. ' +
              'If debugging auth, log success/failure status only, never the actual credentials.',
          });
        }
      }
    }
  }

  return {
    cwe: 'CWE-522',
    name: 'Insufficiently Protected Credentials',
    holds: findings.length === 0,
    findings,
  };
}

/**
 * CWE-620: Unverified Password Change
 * Pattern: Password change operation that does NOT verify the current password first.
 *          If an attacker has a session (via XSS, session fixation, shared computer),
 *          they can change the password without knowing the current one.
 *
 * Detection: Find password change flows and check if current-password is verified.
 *  1. Look for password change endpoints/functions
 *  2. Check if current password is required and verified before the change
 */
function verifyCWE620(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];

  // Password change patterns
  const passwordChangePattern = /\b(change[_-]?password|update[_-]?password|reset[_-]?password|set[_-]?password|modify[_-]?password|new[_-]?password|password[_-]?update|passwd[_-]?change)\b/i;

  // Current password verification patterns — these are SAFE
  const currentPasswordCheckPattern = /\b(current[_-]?password|old[_-]?password|existing[_-]?password|previous[_-]?password|original[_-]?password|confirm[_-]?current|verify[_-]?password|bcrypt\.compare|checkPassword|validatePassword|password_verify|check_password_hash)\b/i;

  // Find password change functions/routes
  const passwordChangeNodes = map.nodes.filter(n =>
    (n.node_type === 'STRUCTURAL' && n.node_subtype === 'route_def' &&
     passwordChangePattern.test(n.code_snapshot)) ||
    (n.node_type === 'STRUCTURAL' && n.node_subtype === 'function' &&
     passwordChangePattern.test(n.code_snapshot)) ||
    (n.node_type === 'STRUCTURAL' && n.node_subtype === 'function' &&
     passwordChangePattern.test(n.label))
  );

  // Also look at AUTH nodes that handle password changes
  const authPasswordChange = map.nodes.filter(n =>
    n.node_type === 'AUTH' && passwordChangePattern.test(n.code_snapshot)
  );

  const allPasswordChangeNodes = [...passwordChangeNodes, ...authPasswordChange];

  for (const changeNode of allPasswordChangeNodes) {
    // Get all nodes within this function's scope
    const scopedNodes = map.nodes.filter(n =>
      n.line_start >= changeNode.line_start &&
      n.line_start <= changeNode.line_end
    );

    // Check if current password is verified within this scope
    const hasCurrentPasswordCheck = scopedNodes.some(n =>
      currentPasswordCheckPattern.test(n.code_snapshot)
    ) || currentPasswordCheckPattern.test(changeNode.code_snapshot);

    // Also check for password reset tokens (valid alternative to current password)
    const hasResetToken = scopedNodes.some(n =>
      /\b(reset[_-]?token|password[_-]?token|token[_-]?verify|verify[_-]?token|resetToken|passwordResetToken)\b/i.test(n.code_snapshot)
    );

    if (!hasCurrentPasswordCheck && !hasResetToken) {
      // Find the actual STORAGE node where the new password is written
      const passwordWrite = scopedNodes.find(n =>
        n.node_type === 'STORAGE' &&
        /\b(password|passwd|pwd)\b/i.test(n.code_snapshot)
      );

      const sinkNode = passwordWrite ?? changeNode;

      findings.push({
        source: nodeRef(changeNode),
        sink: nodeRef(sinkNode),
        missing: 'AUTH (current password verification before allowing password change)',
        severity: 'high',
        description: `Password change at ${changeNode.label} does not verify the current password. ` +
          `If an attacker gains access to an active session (via XSS, session fixation, or shared computer), ` +
          `they can change the password and lock out the legitimate user.`,
        fix: 'Require the current password before allowing password changes. ' +
          'The flow should be: (1) user submits current password + new password, ' +
          '(2) verify current password against stored hash (bcrypt.compare), ' +
          '(3) only then update to the new password. ' +
          'Exception: password RESET via email token is OK (user proves identity via email).',
      });
    }
  }

  return {
    cwe: 'CWE-620',
    name: 'Unverified Password Change',
    holds: findings.length === 0,
    findings,
  };
}

// ---------------------------------------------------------------------------
// Memory Safety & Arithmetic CWE Verification Paths
// ---------------------------------------------------------------------------

/**
 * CWE-119: Improper Restriction of Operations within the Bounds of a Memory Buffer
 * The parent class for all buffer overflow/underflow vulnerabilities.
 * Detects raw memory/buffer operations without bounds validation in C/C++/Rust/Go/JS.
 */
function verifyCWE119(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const UNSAFE_MEM_RE = /\b(memcpy|memmove|memset|strcpy|strcat|sprintf|vsprintf|gets|fgets|sscanf|fscanf|scanf|bcopy|bzero)\s*\(/i;
  const UNSAFE_ALLOC_RE = /\b(malloc|calloc|realloc|alloca|free)\s*\(/i;
  const POINTER_ARITH_RE = /\*\s*\(.*\+|\bptr\s*[\+\-]|\bunsafe\s*\{|\bunsafe\.Pointer|\bslice::from_raw_parts|\b\*mut\b|\b\*const\b/i;
  // UNSAFE_BUFFER_RE: Buffer.allocUnsafe, buffer.write/copy/fill without length check,
  // Buffer.from with user-controlled source (tainted copy without size check),
  // buffer.writeUInt32BE/writeInt32LE etc. (binary writes at user-controlled offset)
  const UNSAFE_BUFFER_RE = /\bBuffer\.allocUnsafe\b|\bbuffer\.(write|copy|fill|writeUInt|writeInt|writeFloat|writeDouble)\s*\((?![^)]*\.length\b[^)]*\)[^;]*if)|\bBuffer\.from\b|\bTypedArray\b.*\[/i;
  const BOUNDS_SAFE_RE = /\bbounds\b.*check|\bif\s*\(.*[<>]=?\s*.*\b(length|size|len|cap|capacity)\b|\bstrncpy\b|\bsnprintf\b|\bstrlcpy\b|\bstrlcat\b|\bmemcpy_s\b|\bstrcpy_s\b|\bsizeof\b.*[<>]=?|\bstd::copy\b|\bstd::copy_n\b|\bBuffer\.alloc\b(?!Unsafe)|\bslice\s*\(\s*\d|\bMath\.min\b.*length|\b\.len\(\)\b.*[<>]|\bchecked_add\b|\bchecked_mul\b/i;
  const memNodes = map.nodes.filter(n =>
    // Include RESOURCE nodes: Buffer.alloc/Buffer.from are classified RESOURCE/memory
    (n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL' || n.node_type === 'RESOURCE') &&
    (UNSAFE_MEM_RE.test(n.code_snapshot) || UNSAFE_ALLOC_RE.test(n.code_snapshot) ||
     POINTER_ARITH_RE.test(n.code_snapshot) || UNSAFE_BUFFER_RE.test(n.code_snapshot) ||
     n.node_subtype.includes('buffer') || n.node_subtype.includes('memory') ||
     n.node_subtype.includes('pointer') || n.attack_surface.includes('buffer_write'))
  );
  const ingress = nodesOfType(map, 'INGRESS');
  for (const src of ingress) {
    for (const sink of memNodes) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id) ||
          sharesFunctionScope(map, src.id, sink.id)) {
        if (!BOUNDS_SAFE_RE.test(stripComments(sink.code_snapshot))) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (bounds validation before memory/buffer operation)',
            severity: 'critical',
            description: `User input from ${src.label} reaches memory operation at ${sink.label} without bounds checking. ` +
              `This can cause buffer overflow, enabling code execution, crash, or data corruption.`,
            fix: 'Validate all buffer sizes and indices before memory operations. ' +
              'Use bounded functions: strncpy/snprintf instead of strcpy/sprintf. ' +
              'In Rust: avoid unsafe blocks or use checked indexing. In Go: validate slice indices against len().',
          });
        }
      }
    }
  }
  if (findings.length === 0) {
    const ALWAYS_DANGEROUS_RE = /\b(gets|sprintf|vsprintf|strcpy|strcat)\s*\(/i;
    for (const node of memNodes) {
      const code = stripComments(node.code_snapshot);
      if (ALWAYS_DANGEROUS_RE.test(code) && !BOUNDS_SAFE_RE.test(code)) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (use of inherently unsafe memory function without bounds)',
          severity: 'critical',
          description: `${node.label} uses an inherently unsafe memory function (gets/strcpy/sprintf/strcat) ` +
            `that has no built-in bounds checking. Vulnerable to buffer overflow regardless of input source.`,
          fix: 'Replace gets() with fgets(). Replace strcpy/strcat with strncpy/strlcat or std::string. ' +
            'Replace sprintf with snprintf.',
        });
      }
    }
  }
  return { cwe: 'CWE-119', name: 'Improper Restriction of Operations within the Bounds of a Memory Buffer', holds: findings.length === 0, findings };
}

/**
 * CWE-120: Buffer Copy without Checking Size of Input (Classic Buffer Overflow)
 * Targets copy operations where source size is not validated against destination capacity.
 * Classic pattern: char buf[256]; strcpy(buf, user_input);
 */
function verifyCWE120(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const COPY_RE = /\b(strcpy|strcat|memcpy|memmove|bcopy|wcscpy|wcscat|lstrcpy|_mbscpy|CopyMemory|RtlCopyMemory)\s*\(/i;
  const SAFE_COPY_RE = /\b(strncpy|strncat|memcpy_s|memmove_s|strlcpy|strlcat|snprintf|std::copy_n|std::string|copy_nonoverlapping)\s*\(/i;
  const SIZE_CHECK_RE = /\bsizeof\s*\(.*dest|\blen\s*[<>]=?\s*.*capacity|\blength\s*[<>]=?\s*sizeof|\bif\s*\(.*strlen.*[<>].*sizeof|\bmin\s*\(.*len.*sizeof|\bstrlen\b.*[<>]=?\s*\d/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const copyNodes = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL') &&
    (COPY_RE.test(n.code_snapshot) || n.node_subtype.includes('buffer_copy') ||
     n.node_subtype.includes('memcpy') || n.attack_surface.includes('buffer_copy'))
  );
  for (const src of ingress) {
    for (const sink of copyNodes) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const code = stripComments(sink.code_snapshot);
        if (!SAFE_COPY_RE.test(code) && !SIZE_CHECK_RE.test(code)) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (size check before buffer copy — validate source length <= dest capacity)',
            severity: 'critical',
            description: `User input from ${src.label} is copied to a buffer at ${sink.label} without checking ` +
              `that the source data fits in the destination. This is the classic buffer overflow.`,
            fix: 'Check source size before copying: if (strlen(src) >= sizeof(dest)) return error. ' +
              'Replace strcpy with strncpy/strlcpy. Replace strcat with strncat/strlcat. ' +
              'Always pass destination buffer size to copy functions.',
          });
        }
      }
    }
  }
  if (findings.length === 0) {
    for (const node of copyNodes) {
      const code = stripComments(node.code_snapshot);
      if (COPY_RE.test(code) && !SAFE_COPY_RE.test(code) && !SIZE_CHECK_RE.test(code)) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (bounded copy function or explicit size validation)',
          severity: 'critical',
          description: `${node.label} uses an unbounded copy function (strcpy/strcat/memcpy) without size validation. ` +
            `If the source ever exceeds the destination capacity, a buffer overflow occurs.`,
          fix: 'Replace strcpy/strcat with strncpy/strlcpy/strlcat. For memcpy, validate: n <= sizeof(dest). ' +
            'Use std::string/std::vector in C++ to avoid manual buffer management.',
        });
      }
    }
  }
  return { cwe: 'CWE-120', name: 'Buffer Copy without Checking Size of Input (Classic Buffer Overflow)', holds: findings.length === 0, findings };
}

/**
 * CWE-125: Out-of-bounds Read
 * Reading data past the end or before the beginning of a buffer.
 * Can leak sensitive data (Heartbleed was CWE-125) or cause crashes.
 */
function verifyCWE125(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const READ_OP_RE = /\b(read|fread|recv|recvfrom|pread|readv|buffer\.read\w+|\.read\w*BE\b|\.read\w*LE\b|get_unchecked|from_raw_parts|ptr\.read|ptr\.add|memchr|strstr|strlen)\s*\(/i;
  const BUFFER_READ_RE = /\bbuffer\.(read|toString|slice)\s*\(|\bDataView\b.*\bget\w+\(/i;
  const SAFE_READ_RE = /\bif\s*\(.*index.*[<>]=?\s*.*length|\bif\s*\(.*offset.*[<>]=?\s*.*size|\b\.get\(\s*\w+\s*\)|\b\.at\(\s*\w+\s*\)|\bchecked\b|\b\.len\(\)\s*[<>]|\bbounds_check|\brange_check|\bslice\(\s*\d+\s*,\s*\d+\s*\)/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const readNodes = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM') &&
    (READ_OP_RE.test(n.code_snapshot) || BUFFER_READ_RE.test(n.code_snapshot) ||
     n.node_subtype.includes('buffer_read') || n.node_subtype.includes('array_access') ||
     n.attack_surface.includes('buffer_read'))
  );
  for (const src of ingress) {
    for (const sink of readNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        if (!SAFE_READ_RE.test(stripComments(sink.code_snapshot))) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (bounds check before read — validate offset < buffer.length)',
            severity: 'high',
            description: `User input from ${src.label} controls a read offset/index at ${sink.label} without bounds validation. ` +
              `Out-of-bounds reads can leak sensitive memory contents (like Heartbleed) or cause crashes.`,
            fix: 'Validate read offsets against buffer length: if (offset + readSize > buf.length) return error. ' +
              'Use safe accessors: .at() in JS, .get() in Rust, bounds-checked slice in Go.',
          });
        }
      }
    }
  }
  return { cwe: 'CWE-125', name: 'Out-of-bounds Read', holds: findings.length === 0, findings };
}

/**
 * CWE-126: Buffer Over-read
 * Variant of CWE-125 — specifically reading PAST the end of a buffer.
 * Often caused by incorrect length calculations or missing null terminators.
 */
function verifyCWE126(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const OVERREAD_RE = /\bstrlen\b|\bwcslen\b|\bstrnlen\b|\bmemchr\b|\bsizeof\b.*read|\bread\s*\(.*sizeof|\b\.length\b.*read|\brecv\b.*\bsizeof\b/i;
  const FIXED_SIZE_READ_RE = /\bread\s*\(\s*\w+\s*,\s*\d+\s*\)|\bmemcpy\s*\(\s*\w+\s*,\s*\w+\s*,\s*\d+\s*\)|\bfread\s*\(\s*\w+\s*,\s*\d+/i;
  const BUFFER_SLICE_RE = /\bbuffer\.(read|toString|slice)\s*\(.*\+|\bsubarray\s*\(/i;
  const SAFE_OVERREAD_RE = /\bstrnlen\b|\bnull.*termin|\b\\0\b.*check|\bif\s*\(.*recv.*[<>]=?|\bif\s*\(.*len\s*[<>]=?\s*.*size|\bmin\s*\(.*len|\bMath\.min\b/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const overreadNodes = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM') &&
    (OVERREAD_RE.test(n.code_snapshot) || FIXED_SIZE_READ_RE.test(n.code_snapshot) ||
     BUFFER_SLICE_RE.test(n.code_snapshot) || n.node_subtype.includes('buffer') ||
     n.attack_surface.includes('buffer_read'))
  );
  for (const src of ingress) {
    for (const sink of overreadNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        if (!SAFE_OVERREAD_RE.test(stripComments(sink.code_snapshot))) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (upper bounds validation — ensure read does not exceed buffer end)',
            severity: 'high',
            description: `User input from ${src.label} influences a read at ${sink.label} that may exceed the buffer boundary. ` +
              `Buffer over-reads leak adjacent memory contents and can expose secrets or cause crashes.`,
            fix: 'Use Math.min(requestedLength, buffer.length - offset) to cap read size. ' +
              'Validate offset + length <= buffer.length before every read. ' +
              'Use strnlen() instead of strlen() for untrusted strings.',
          });
        }
      }
    }
  }
  return { cwe: 'CWE-126', name: 'Buffer Over-read', holds: findings.length === 0, findings };
}

/**
 * CWE-127: Buffer Under-read
 * Reading before the beginning of a buffer due to negative index or
 * pointer arithmetic producing a pointer before the buffer start.
 */
function verifyCWE127(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const NEGATIVE_INDEX_RE = /\[\s*\w+\s*-|\bptr\s*-\s*\d|\boffset\s*-|\b\w+\s*\[\s*-\s*\d/i;
  const SIGNED_INDEX_RE = /\bint\s+\w*index|\bint\s+\w*offset|\bint\s+\w*pos|\bsigned\b.*\[/i;
  const BUFFER_NEGATIVE_RE = /\bbuffer\.\w+\(\s*\w+\s*-|\bslice\s*\(\s*\w+\s*-/i;
  const SAFE_UNDER_RE = /\bif\s*\(.*>=\s*0|\bunsigned\b|\bsize_t\b|\busize\b|\buint\b|\bUint\b|\b>=\s*0\b.*\[|\bMath\.max\s*\(\s*0|\babs\s*\(/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const underreadNodes = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM') &&
    (NEGATIVE_INDEX_RE.test(n.code_snapshot) || SIGNED_INDEX_RE.test(n.code_snapshot) ||
     BUFFER_NEGATIVE_RE.test(n.code_snapshot) || n.node_subtype.includes('buffer') ||
     n.node_subtype.includes('array') || n.attack_surface.includes('array_access'))
  );
  for (const src of ingress) {
    for (const sink of underreadNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        if (!SAFE_UNDER_RE.test(stripComments(sink.code_snapshot))) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (lower bounds check — ensure index >= 0 before buffer access)',
            severity: 'medium',
            description: `User input from ${src.label} may produce a negative index at ${sink.label}, ` +
              `reading before the buffer start. Buffer under-reads leak preceding memory or cause crashes.`,
            fix: 'Validate that indices are non-negative: if (index < 0) return error. ' +
              'Use unsigned types (size_t in C, usize in Rust, uint in Go). ' +
              'Use Math.max(0, index) as a floor in JavaScript.',
          });
        }
      }
    }
  }
  return { cwe: 'CWE-127', name: 'Buffer Under-read', holds: findings.length === 0, findings };
}

/**
 * CWE-131: Incorrect Calculation of Buffer Size
 * Allocated buffer is too small because size calculation is wrong.
 * Common causes: forgetting null terminator (+1), integer overflow in size*count, wrong sizeof.
 */
function verifyCWE131(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const ALLOC_RE = /\b(malloc|calloc|realloc|alloca|new\s+\w+\[|Buffer\.alloc\w*|ArrayBuffer|Uint8Array|allocate)\s*\(/i;
  const DANGER_CALC_RE = /\bmalloc\s*\(\s*\w+\s*\*\s*\w+\s*\)|\bcalloc\s*\(\s*\w+\s*,\s*sizeof|\bstrlen\s*\(\s*\w+\s*\)\s*\)(?!\s*\+\s*1)/i;
  const SAFE_SIZE_RE = /\bchecked_mul\b|\bchecked_add\b|\bsafe_mul\b|\bMath\.min\b.*alloc|\bif\s*\(.*overflow|\bif\s*\(.*MAX_|\bSIZE_MAX\b|\bcalloc\b.*\bsizeof\b|\bstrlen\b.*\+\s*1|\bsizeof\b.*\+\s*1|\bBuffer\.alloc\b(?!Unsafe)/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const allocNodes = map.nodes.filter(n =>
    (n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL') &&
    (ALLOC_RE.test(n.code_snapshot) || n.node_subtype.includes('alloc') ||
     n.node_subtype.includes('memory') || n.attack_surface.includes('allocation'))
  );
  for (const src of ingress) {
    for (const sink of allocNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        if (!SAFE_SIZE_RE.test(stripComments(sink.code_snapshot))) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (validated size calculation — check for overflow, off-by-one, encoding width)',
            severity: 'critical',
            description: `User input from ${src.label} influences buffer size calculation at ${sink.label}. ` +
              `Incorrect size causes buffer overflows (too small) or memory waste (too large).`,
            fix: 'Use checked arithmetic (checked_mul in Rust, __builtin_mul_overflow in GCC). ' +
              'Always add +1 for null terminator. Use calloc(count, size) instead of malloc(count*size). ' +
              'Cap maximum allocation size.',
          });
        }
      }
    }
  }
  if (findings.length === 0) {
    for (const node of allocNodes) {
      const code = stripComments(node.code_snapshot);
      if (DANGER_CALC_RE.test(code) && !SAFE_SIZE_RE.test(code)) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (safe size calculation — use calloc or checked arithmetic)',
          severity: 'high',
          description: `Buffer size calculation at ${node.label} may be incorrect. ` +
            `malloc(a*b) can overflow; strlen(s) without +1 forgets the null terminator.`,
          fix: 'Use calloc(count, size) instead of malloc(count*size). ' +
            'Always add 1 to strlen() for null-terminated string allocation.',
        });
      }
    }
  }
  return { cwe: 'CWE-131', name: 'Incorrect Calculation of Buffer Size', holds: findings.length === 0, findings };
}

/**
 * CWE-190: Integer Overflow or Wraparound
 * Integer value increases past its maximum, wrapping to a small/negative value.
 * When used as buffer size or loop bound, causes overflow or infinite loops.
 */
function verifyCWE190(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const SIZE_ARITH_RE = /\b(size|count|len|length|offset|index|width|height|num|total)\w*\s*[\*\+]|\b[\*\+]\s*\w*(size|count|len|length|num)\b/i;
  const CAST_WIDEN_RE = /\(\s*(int|short|int16_t|int32_t|uint16_t|uint32_t|i16|i32|u16|u32)\s*\)/i;
  const ARITH_RE = /\b\w+\s*[\*\+]\s*\w+|\b\w+\s*\+=\s*\w+|\b\w+\s*\*=\s*\w+|\b\w+\s*<<\s*\w+/;
  const OVERFLOW_SAFE_RE = /\bchecked_add\b|\bchecked_mul\b|\bsaturating_add\b|\bsaturating_mul\b|\b__builtin_\w+_overflow\b|\bSafeInt\b|\bNumber\.isSafeInteger\b|\bMAX_SAFE_INTEGER\b|\bif\s*\(.*>\s*MAX|\bif\s*\(.*>\s*INT_MAX|\bif\s*\(.*>\s*SIZE_MAX|\bif\s*\(.*overflow|\bclamp\b|\bMath\.min\b/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const arithNodes = map.nodes.filter(n =>
    // Include RESOURCE nodes: Buffer.alloc(size + 1) is classified RESOURCE/memory
    // and contains integer arithmetic used as a size argument.
    (n.node_type === 'TRANSFORM' || n.node_type === 'STORAGE' || n.node_type === 'RESOURCE') &&
    (SIZE_ARITH_RE.test(n.code_snapshot) ||
     (ARITH_RE.test(n.code_snapshot) && CAST_WIDEN_RE.test(n.code_snapshot)) ||
     n.node_subtype.includes('arithmetic') || n.node_subtype.includes('numeric') ||
     n.node_subtype.includes('integer') || n.attack_surface.includes('numeric_operation') ||
     // Buffer.alloc/allocUnsafe with arithmetic argument is a direct integer overflow sink
     /\bBuffer\.(alloc|allocUnsafe)\s*\([^)]*[\*\+\-][^)]*\)/.test(n.code_snapshot))
  );
  for (const src of ingress) {
    for (const sink of arithNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id) ||
          sharesFunctionScope(map, src.id, sink.id)) {
        // Check the sink AND the function scope for safety patterns.
        // Number.isSafeInteger / Math.min may be in a sibling CONTROL node.
        const scopeSafe = OVERFLOW_SAFE_RE.test(stripComments(sink.code_snapshot)) ||
          map.nodes.some(n =>
            n.id !== sink.id &&
            sharesFunctionScope(map, sink.id, n.id) &&
            OVERFLOW_SAFE_RE.test(stripComments(n.code_snapshot))
          );
        if (!scopeSafe) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (integer overflow check before arithmetic)',
            severity: 'high',
            description: `User input from ${src.label} feeds into arithmetic at ${sink.label} without overflow protection. ` +
              `Result exceeding the type's maximum wraps to small/negative value, causing buffer overflow or infinite loops.`,
            fix: 'Use checked arithmetic: checked_add/checked_mul in Rust, __builtin_*_overflow in GCC. ' +
              'Validate input ranges before arithmetic. Use Number.isSafeInteger() in JS. ' +
              'Use int64 or BigInt for intermediate calculations.',
          });
        }
      }
    }
  }
  return { cwe: 'CWE-190', name: 'Integer Overflow or Wraparound', holds: findings.length === 0, findings };
}

/**
 * CWE-191: Integer Underflow (Wrap or Wraparound)
 * Integer value decreases below its minimum, wrapping to a large positive (unsigned) value.
 * Classic pattern: unsigned len = packet_length - header_size; // wraps if packet < header
 */
function verifyCWE191(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const SUB_RE = /\b\w+\s*-\s*\w+|\b\w+\s*-=\s*\w+/;
  const SIZE_SUB_RE = /\b(size|count|len|length|offset|remaining|available)\w*\s*-|\b-\s*\w*(size|count|len|length|header)\b/i;
  const UNSIGNED_SUB_RE = /\b(size_t|unsigned|uint\d*|usize|u32|u64|uint)\b.*-/i;
  const UNDERFLOW_SAFE_RE = /\bif\s*\(.*>=\s*\w+|\bif\s*\(.*>\s*\w+.*-|\bchecked_sub\b|\bsaturating_sub\b|\b__builtin_sub_overflow\b|\bMath\.max\s*\(\s*0|\bif\s*\(\s*\w+\s*>=?\s*\w+\s*\).*-/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const subNodes = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'STORAGE') &&
    (SIZE_SUB_RE.test(n.code_snapshot) || UNSIGNED_SUB_RE.test(n.code_snapshot) ||
     n.node_subtype.includes('arithmetic') || n.node_subtype.includes('numeric') ||
     n.attack_surface.includes('numeric_operation'))
  );
  for (const src of ingress) {
    for (const sink of subNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const code = stripComments(sink.code_snapshot);
        if (SUB_RE.test(code) && !UNDERFLOW_SAFE_RE.test(code)) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (underflow check — verify minuend >= subtrahend before subtraction)',
            severity: 'high',
            description: `User input from ${src.label} influences subtraction at ${sink.label} without underflow protection. ` +
              `Unsigned wrap to huge value causes massive allocations or out-of-bounds access.`,
            fix: 'Check before subtracting: if (a < b) return error, else result = a - b. ' +
              'Use checked_sub/saturating_sub in Rust. Use Math.max(0, a - b) in JS.',
          });
        }
      }
    }
  }
  return { cwe: 'CWE-191', name: 'Integer Underflow (Wrap or Wraparound)', holds: findings.length === 0, findings };
}

/**
 * CWE-369: Divide By Zero
 * Division or modulo where divisor can be zero. In C/C++: SIGFPE crash.
 * In other languages: Infinity/NaN or exceptions.
 */
function verifyCWE369(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const DIV_RE = /\s\/\s|\s%\s|\bdiv\b|\bmod\b|\bdivmod\b|\bquotient\b|\bremainder\b/i;
  const DIV_FUNC_RE = /\bMath\.floor\s*\(.*\/|\bMath\.ceil\s*\(.*\/|\bMath\.trunc\s*\(.*\/|\bBigInt\b.*\/|\bidiv\b/i;
  const MODULO_RE = /\b\w+\s*%\s*\w+|\bfmod\b|\bmodulo\b/i;
  const ZERO_SAFE_RE = /\b!==?\s*0\b|\b!=\s*0\b|\b>\s*0\b|\b>=\s*1\b|\bif\s*\(.*divisor|\bif\s*\(\s*\w+\s*\)\s*\{?\s*.*\/|\bzero.*check\b|\bdivisor.*valid\b|\bisNaN\b|\bisFinite\b|\b\|\|\s*1\b|\b\?\?\s*1\b|\bdefault\b.*\b[1-9]/i;
  const ingress = nodesOfType(map, 'INGRESS');
  const divNodes = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'STORAGE') &&
    (DIV_RE.test(n.code_snapshot) || DIV_FUNC_RE.test(n.code_snapshot) ||
     MODULO_RE.test(n.code_snapshot) || n.node_subtype.includes('division') ||
     n.node_subtype.includes('arithmetic') || n.attack_surface.includes('arithmetic'))
  );
  for (const src of ingress) {
    for (const sink of divNodes) {
      if (src.id === sink.id) continue;
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const code = stripComments(sink.code_snapshot);
        if ((DIV_RE.test(code) || DIV_FUNC_RE.test(code) || MODULO_RE.test(code)) && !ZERO_SAFE_RE.test(code)) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (zero divisor check before division/modulo)',
            severity: 'medium',
            description: `User input from ${src.label} controls a divisor at ${sink.label} without zero check. ` +
              `Division by zero causes crashes (SIGFPE in C/C++), exceptions, or NaN/Infinity propagation.`,
            fix: 'Check divisor before dividing: if (divisor === 0) return error or default value. ' +
              'Use || 1 or ?? 1 as fallback. In Rust: checked_div(). In Go: explicit if divisor == 0.',
          });
        }
      }
    }
  }
  if (findings.length === 0) {
    const externalDivNodes = map.nodes.filter(n =>
      (n.node_type === 'TRANSFORM' || n.node_type === 'STORAGE') &&
      (DIV_RE.test(n.code_snapshot) || MODULO_RE.test(n.code_snapshot)) &&
      n.data_in.some(d => d.tainted)
    );
    for (const node of externalDivNodes) {
      if (!ZERO_SAFE_RE.test(stripComments(node.code_snapshot))) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (zero divisor validation)',
          severity: 'medium',
          description: `Division at ${node.label} uses tainted data as divisor without zero check.`,
          fix: 'Always validate divisors are non-zero before division.',
        });
      }
    }
  }
  return { cwe: 'CWE-369', name: 'Divide By Zero', holds: findings.length === 0, findings };
}

/**
 * CWE-476: NULL Pointer Dereference
 * Dereferencing a NULL/null/nil/None pointer/reference. Causes segfaults in C/C++,
 * NullPointerException in Java, TypeError in JS, panic in Go/Rust.
 */
function verifyCWE476(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const NULLABLE_SOURCE_RE = /\b(find|findOne|get|getElementById|querySelector|querySelectorAll|getAttribute|getItem|lookup|search|match|exec|pop|shift|first|last|fetch|load|open|fopen|connect|socket|accept|malloc|calloc|realloc)\b/i;
  const DEREF_RE = /\->\w+|\*\s*\w+\b|\.unwrap\s*\(\s*\)|\.\w+\s*\(|\.\w+\s*\[|\.\w+\s*\.|\[\s*\d+\s*\]/;
  const UNSAFE_UNWRAP_RE = /\.unwrap\s*\(\s*\)/i;
  const NULL_SAFE_RE = /\bif\s*\(\s*\w+\s*[!=]==?\s*null\b|\bif\s*\(\s*\w+\s*[!=]=?\s*nil\b|\bif\s*\(\s*\w+\s*is\s+None\b|\bif\s*\(\s*\w+\s*!=?\s*nullptr\b|\bif\s*\(\s*\w+\s*\)|\b\?\.\b|\b\?\?\b|\bif\s+err\s*!=\s*nil|\bif let\b|\bguard let\b|\bif\s+let\s+Some|\bmatch\b.*\bSome|\bmatch\b.*\bOk|\b\.unwrap_or\b|\b\.unwrap_or_else\b|\b\.ok_or\b|\btypeof\b|\bassert\b.*!=.*null|\brequire\b.*!=.*null/i;
  const nullableSources = map.nodes.filter(n =>
    (n.node_type === 'EXTERNAL' || n.node_type === 'TRANSFORM' || n.node_type === 'STORAGE') &&
    (n.node_subtype.includes('nullable') || n.node_subtype.includes('optional') ||
     n.node_subtype.includes('lookup') || n.node_subtype.includes('query') ||
     NULLABLE_SOURCE_RE.test(n.code_snapshot))
  );
  const derefSinks = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'STORAGE' || n.node_type === 'EXTERNAL') &&
    (DEREF_RE.test(n.code_snapshot) ||
     n.code_snapshot.match(/\.\w+\s*[\([]|\.length\b|\.toString\b|\.valueOf\b/i) !== null)
  );
  // Track seen sink IDs to avoid duplicate findings
  const seenSinks476 = new Set<string>();
  for (const src of nullableSources) {
    for (const sink of derefSinks) {
      if (src.id === sink.id) continue;
      if (seenSinks476.has(sink.id)) continue;
      // Use either DATA_FLOW path or function scope proximity.
      // In JavaScript, db.findOne() result stored in a variable that is then
      // dereferenced in the same function will share scope even without a direct
      // DATA_FLOW edge from the STORAGE source to the dereference TRANSFORM node.
      const reachable = hasPathWithoutControl(map, src.id, sink.id) ||
        sharesFunctionScope(map, src.id, sink.id);
      if (reachable) {
        // Check for null guards in the function scope (not just on src/sink nodes)
        const scopeNullSafe = map.nodes.some(n =>
          sharesFunctionScope(map, src.id, n.id) &&
          NULL_SAFE_RE.test(stripComments(n.code_snapshot))
        );
        if (!NULL_SAFE_RE.test(stripComments(sink.code_snapshot)) &&
            !NULL_SAFE_RE.test(stripComments(src.code_snapshot)) &&
            !scopeNullSafe) {
          seenSinks476.add(sink.id);
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'CONTROL (null/nil/None check before dereference)',
            severity: 'medium',
            description: `Potentially-null value from ${src.label} is dereferenced at ${sink.label} without a null check. ` +
              `NULL dereference causes segfaults in C/C++, NullPointerException in Java, TypeError in JS.`,
            fix: 'Check for null before dereferencing. Use optional chaining (?.) in JS/TS. ' +
              'Use if-let/match in Rust instead of .unwrap(). In Go: check err != nil before using value.',
          });
        }
      }
    }
  }
  if (findings.length === 0) {
    const unwrapNodes = map.nodes.filter(n =>
      UNSAFE_UNWRAP_RE.test(n.code_snapshot) && !NULL_SAFE_RE.test(stripComments(n.code_snapshot))
    );
    for (const node of unwrapNodes) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (handle None/Err case instead of unwrap)',
        severity: 'medium',
        description: `${node.label} uses .unwrap() which panics on None/Err. If the value can be None/Err at runtime, this crashes.`,
        fix: 'Replace .unwrap() with .unwrap_or(default), .unwrap_or_else(|| ...), or pattern matching (match/if-let).',
      });
    }
  }
  return { cwe: 'CWE-476', name: 'NULL Pointer Dereference', holds: findings.length === 0, findings };
}

// ---------------------------------------------------------------------------
// Platform-specific CWE filtering

// ---------------------------------------------------------------------------
// Cryptography CWEs — real crypto weakness detection
// ---------------------------------------------------------------------------

/**
 * CWE-327: Use of a Broken or Risky Cryptographic Algorithm
 * Scans ALL nodes for broken cipher references: DES, 3DES, RC4, RC2, Blowfish, ECB mode.
 */
function verifyCWE327(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const BROKEN_ALGO_RE = /\b(DES|3DES|DESede|TripleDES|RC4|RC2|Blowfish|IDEA|CAST5|SEED|Skipjack|TEA|XTEA)\b|createCipher(?:iv)?\s*\(\s*['"](?:des|des-ede3|des3|rc4|rc2|bf|blowfish|idea|cast5|seed)\b|DES\.(?:encrypt|decrypt)|TripleDES\.(?:encrypt|decrypt)|CryptoJS\.(?:DES|TripleDES|RC4|Rabbit)\b|\bDES_cbc_encrypt\b|\bDES_ecb_encrypt\b|\bEVP_des_\w+\b|\bEVP_rc4\b|\bEVP_bf_\b|\bCipher\.getInstance\s*\(\s*['"](?:DES|DESede|RC4|RC2|Blowfish)\b/i;
  const STRONG_ALGO_RE = /\bAES[-_]?(?:128|256|GCM)\b|\bChaCha20\b|\bPoly1305\b|\bXSalsa20\b|\baes[-_]?256[-_]?(?:gcm|cbc|ctr)\b|\bcreateDecipheriv\s*\(\s*['"]aes/i;
  const ECB_MODE_RE = /\bECB\b|\/ECB\/|['"]aes[-_]?(?:128|256)[-_]?ecb['"]|\bMode\.ECB\b|\bCipher\.getInstance\s*\(\s*['"]AES\/ECB/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    if (BROKEN_ALGO_RE.test(code) && !STRONG_ALGO_RE.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (modern cryptographic algorithm — AES-256-GCM or ChaCha20-Poly1305)',
        severity: 'high',
        description: `Broken cryptographic algorithm used at ${node.label}. ` +
          `DES, 3DES, RC4, RC2, and Blowfish have known vulnerabilities and are considered cryptographically broken.`,
        fix: 'Replace with AES-256-GCM (authenticated encryption) or ChaCha20-Poly1305. ' +
          'For Node.js: crypto.createCipheriv("aes-256-gcm", key, iv). ' +
          'For Java: Cipher.getInstance("AES/GCM/NoPadding"). Never use DES, 3DES, RC4, or Blowfish.',
      });
    }
    if (ECB_MODE_RE.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (secure block cipher mode — GCM, CBC with HMAC, or CTR)',
        severity: 'high',
        description: `ECB block cipher mode used at ${node.label}. ` +
          `ECB encrypts identical plaintext blocks to identical ciphertext blocks, leaking data patterns.`,
        fix: 'Use GCM mode (authenticated encryption) or CBC with HMAC. Never use ECB mode. ' +
          'Example: "aes-256-gcm" instead of "aes-256-ecb".',
      });
    }
  }
  return { cwe: 'CWE-327', name: 'Use of a Broken or Risky Cryptographic Algorithm', holds: findings.length === 0, findings };
}

/**
 * CWE-330: Use of Insufficiently Random Values
 * Detects Math.random(), random.random(), rand() etc. in security-sensitive contexts.
 */
function verifyCWE330(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const WEAK_PRNG_RE330 = /\bMath\.random\s*\(|\brandom\.random\s*\(|\brandom\.randint\s*\(|\brand\s*\(\s*\)|\bsrand\s*\(|\bmt_rand\s*\(|\barray_rand\s*\(|\buniqid\s*\(|\bRandom\(\)\.next|\bjava\.util\.Random\b|\bRandom\.nextInt\b|\brand\.Intn\s*\(|\brand\.Int\s*\(|\brand\.Float/i;
  const SEC_CTX_330 = /\b(token|session|csrf|nonce|secret|key|password|salt|iv|otp|verification|reset|auth|api[_-]?key|access[_-]?token|refresh[_-]?token|generate[_-]?id|uuid)\b/i;
  const CSPRNG_RE330 = /\bcrypto\.randomBytes\b|\bcrypto\.getRandomValues\b|\bsecureRandom\b|\bSecureRandom\b|\bcrypto\.randomUUID\b|\bcrypto\.random\b|\bos\.urandom\b|\bsecrets\.\b|\bcrypto\/rand\b|\bRandomNumberGenerator\b|\brandom_bytes\s*\(/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    if (!WEAK_PRNG_RE330.test(code)) continue;
    const isSec = SEC_CTX_330.test(node.label) || SEC_CTX_330.test(node.node_subtype) || SEC_CTX_330.test(code) ||
      node.attack_surface.some(s => SEC_CTX_330.test(s));
    const flowsToAuth = node.edges.some(e => {
      const t = map.nodes.find(n => n.id === e.target);
      return t && (t.node_type === 'AUTH' || t.node_type === 'CONTROL');
    });
    if ((isSec || flowsToAuth) && !CSPRNG_RE330.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'EXTERNAL (cryptographically secure PRNG — crypto.randomBytes, SecureRandom, os.urandom)',
        severity: 'high',
        description: `Weak PRNG used in security-sensitive context at ${node.label}. ` +
          `Math.random()/random.random()/rand() are predictable and must not be used for tokens, keys, or session IDs.`,
        fix: 'Use a CSPRNG: crypto.randomBytes() (Node.js), secrets.token_hex() (Python), ' +
          'SecureRandom (Java/Ruby), crypto/rand (Go), or crypto.getRandomValues() (browser).',
      });
    }
  }
  return { cwe: 'CWE-330', name: 'Use of Insufficiently Random Values', holds: findings.length === 0, findings };
}

/**
 * CWE-331: Insufficient Entropy
 * Detects short random buffers (<16 bytes), truncated tokens, and short hardcoded salts.
 */
function verifyCWE331(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const LOW_ENT_RE331 = /\brandomBytes\s*\(\s*([1-9]|1[0-5])\s*\)|\brandom_bytes\s*\(\s*([1-9]|1[0-5])\s*\)/i;
  const TRUNC_RE331 = /\.substring\s*\(\s*0\s*,\s*([1-9]|1[0-5])\s*\)|\.slice\s*\(\s*0\s*,\s*([1-9]|1[0-5])\s*\)|\.substr\s*\(\s*0\s*,\s*([1-8])\s*\)/;
  const SEC_CTX_331 = /\b(token|session|csrf|nonce|secret|key|password|salt|iv|otp|verification|reset|auth|api[_-]?key)\b/i;
  const SHORT_SALT_RE331 = /salt\s*[:=]\s*['"][^'"]{1,15}['"]/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    const isSec = SEC_CTX_331.test(node.label) || SEC_CTX_331.test(code) || SEC_CTX_331.test(node.node_subtype);
    if (!isSec) continue;
    if (LOW_ENT_RE331.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (sufficient entropy — at least 16 bytes / 128 bits for security tokens)',
        severity: 'medium',
        description: `Insufficient entropy at ${node.label}. Random buffer < 16 bytes (128 bits), making brute-force feasible.`,
        fix: 'Use at least 32 bytes (256 bits) for keys and 16 bytes (128 bits) for tokens. Example: crypto.randomBytes(32).',
      });
    }
    if (TRUNC_RE331.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (sufficient token length — avoid truncating random values)',
        severity: 'medium',
        description: `Security token at ${node.label} is truncated to a short length, reducing effective entropy.`,
        fix: 'Do not truncate security tokens. Use full CSPRNG output. Use base64url encoding if shorter strings needed.',
      });
    }
    if (SHORT_SALT_RE331.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (sufficient salt length — at least 16 bytes)',
        severity: 'medium',
        description: `Short hardcoded salt at ${node.label}. Salts must be unique per-user and at least 16 bytes.`,
        fix: 'Generate a unique random salt per user/password using crypto.randomBytes(16). Never use hardcoded or short salts.',
      });
    }
  }
  return { cwe: 'CWE-331', name: 'Insufficient Entropy', holds: findings.length === 0, findings };
}

/**
 * CWE-338: Use of Cryptographically Weak PRNG
 * Catches weak PRNGs in action nodes (TRANSFORM, EXTERNAL, AUTH, CONTROL, STORAGE).
 */
function verifyCWE338(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const WEAK_RE338 = /\bMath\.random\s*\(|\brandom\.random\s*\(|\brandom\.randint\s*\(|\brand\s*\(\s*\)|\bmt_rand\s*\(|\bmt_srand\s*\(|\bsrand\s*\(|\blcg_value\s*\(|\buniqid\s*\(|\bjava\.util\.Random\b|\bkotlin\.random\.Random\b|\bRandom\(\)\.next|\brand\.Intn\s*\(|\brand\.Int\s*\(|\bSystem\.Random\b|\bRandom\.Shared\b/i;
  const CSPR_RE338 = /\bcrypto\.randomBytes\b|\bcrypto\.getRandomValues\b|\bsecureRandom\b|\bSecureRandom\b|\bcrypto\.randomUUID\b|\bos\.urandom\b|\bsecrets\.\b|\bcrypto\/rand\b|\bRandomNumberGenerator\b|\brandom_bytes\s*\(|\bRNGCryptoServiceProvider\b/i;
  const actTypes338: NodeType[] = ['TRANSFORM', 'EXTERNAL', 'AUTH', 'CONTROL', 'STORAGE'];

  for (const node of map.nodes) {
    if (!actTypes338.includes(node.node_type)) continue;
    const code = stripComments(node.code_snapshot);
    if (WEAK_RE338.test(code) && !CSPR_RE338.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'EXTERNAL (CSPRNG — crypto.randomBytes, SecureRandom, crypto/rand)',
        severity: 'high',
        description: `Weak PRNG used at ${node.label}. Math.random()/java.util.Random/rand() use predictable algorithms ` +
          `(Mersenne Twister, LCG) that can be reverse-engineered from observed outputs.`,
        fix: 'Replace with a CSPRNG: crypto.randomBytes() (Node.js), java.security.SecureRandom (Java), ' +
          'secrets module (Python), crypto/rand (Go), or crypto.getRandomValues() (browser).',
      });
    }
  }
  return { cwe: 'CWE-338', name: 'Use of Cryptographically Weak PRNG', holds: findings.length === 0, findings };
}

/**
 * CWE-347: Improper Verification of Cryptographic Signature
 * Detects jwt.decode without verify, algorithm "none", disabled verification.
 */
function verifyCWE347(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const UNVER_RE347 = /\bjwt\.decode\b|\bjwtDecode\b|\bjose\.decode\b|\bjwt_decode\s*\(|\bJSON\.parse\s*\(\s*(?:atob|Buffer\.from)\b/i;
  const ALG_NONE_RE347 = /algorithms?\s*:\s*\[?\s*['"]none['"]\s*\]?|algorithm\s*[:=]\s*['"]none['"]/i;
  const SKIP_RE347 = /verify\s*[:=]\s*false|ignoreSignature\s*[:=]\s*true|noVerify\s*[:=]\s*true|skipVerification/i;
  const VER_RE347 = /\bjwt\.verify\b|\bjws\.verify\b|\bjose\.jwtVerify\b|\bverify\s*\(\s*token|\bverifyToken\b|\bverifySignature\b|\bjwtVerify\b/i;

  const sigNodes347 = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL' || n.node_type === 'AUTH' || n.node_type === 'CONTROL') &&
    (n.node_subtype.includes('jwt') || n.node_subtype.includes('auth') || n.node_subtype.includes('token') ||
     n.node_subtype.includes('signature') || n.node_subtype.includes('crypto') || n.node_subtype.includes('verify') ||
     /\bjwt\b|\btoken\b|\bsignature\b|\bjws\b|\bjose\b/i.test(n.code_snapshot))
  );

  for (const node of sigNodes347) {
    const code = stripComments(node.code_snapshot);
    if (ALG_NONE_RE347.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (reject "none" algorithm in JWT verification)',
        severity: 'critical',
        description: `JWT algorithm "none" allowed at ${node.label}. Attackers can forge tokens by stripping the signature.`,
        fix: 'Specify allowed algorithms: jwt.verify(token, secret, { algorithms: ["HS256"] }). Never allow "none".',
      });
      continue;
    }
    if (SKIP_RE347.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (enable cryptographic signature verification)',
        severity: 'critical',
        description: `Signature verification disabled at ${node.label}. Skipping verification allows forged data.`,
        fix: 'Never disable signature verification. Remove verify:false/ignoreSignature:true. Always verify with a trusted key.',
      });
      continue;
    }
    if (UNVER_RE347.test(code) && !VER_RE347.test(code)) {
      const sibs347 = map.nodes.filter(n => n.id !== node.id && sharesFunctionScope(map, node.id, n.id));
      if (!sibs347.some(n => VER_RE347.test(stripComments(n.code_snapshot)))) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (signature verification before trusting decoded data)',
          severity: 'critical',
          description: `Signed data decoded without verification at ${node.label}. jwt.decode() does NOT verify the signature.`,
          fix: 'Use jwt.verify(token, secret) instead of jwt.decode(token). Always verify the signature before trusting the payload.',
        });
      }
    }
  }
  return { cwe: 'CWE-347', name: 'Improper Verification of Cryptographic Signature', holds: findings.length === 0, findings };
}

/**
 * CWE-354: Improper Validation of Integrity Check Value
 * Detects webhook data without HMAC verification, external data without checksums.
 */
function verifyCWE354(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const INTEG_RE354 = /\bverify\s*\(|\bhmac\b.*\bverify\b|\bchecksum\b|\btimingSafeEqual\b|\bcrypto\.verify\b|\bconstant[_-]?time[_-]?compare\b|\bverify[_-]?signature\b|\bverify[_-]?hmac\b|\bcheck.*integrity\b|\bSRI\b|\bintegrity\s*[:=]/i;
  const WEBHOOK_RE354 = /\bwebhook\b|\bsigned[_-]?payload\b|\bX-Hub-Signature\b|\bX-Signature\b|\bStripe-Signature\b|\bx-shopify-hmac\b/i;

  const extNodes354 = map.nodes.filter(n =>
    (n.node_type === 'EXTERNAL' || n.node_type === 'INGRESS') &&
    (n.node_subtype.includes('download') || n.node_subtype.includes('webhook') ||
     n.node_subtype.includes('http_request') || n.node_subtype.includes('file_download') ||
     n.attack_surface.includes('external_data') ||
     /\b(download|webhook|callback|signed.*payload)\b/i.test(n.code_snapshot))
  );

  for (const node of extNodes354) {
    const code = stripComments(node.code_snapshot);
    if (WEBHOOK_RE354.test(code) || WEBHOOK_RE354.test(node.label)) {
      const sibs354 = map.nodes.filter(n => n.id !== node.id && sharesFunctionScope(map, node.id, n.id));
      if (!INTEG_RE354.test(code) && !sibs354.some(n => INTEG_RE354.test(stripComments(n.code_snapshot)))) {
        findings.push({
          source: nodeRef(node), sink: nodeRef(node),
          missing: 'CONTROL (HMAC/signature verification of webhook payload)',
          severity: 'high',
          description: `Webhook data at ${node.label} processed without HMAC signature verification. Attackers can forge payloads.`,
          fix: 'Verify webhook signature using the provider signing secret. Use crypto.timingSafeEqual() for HMAC comparison.',
        });
      }
    }
    if (node.node_type === 'EXTERNAL') {
      const sinks354 = map.nodes.filter(n =>
        (n.node_type === 'STORAGE' || n.node_type === 'TRANSFORM') && node.edges.some(e => e.target === n.id)
      );
      for (const sink of sinks354) {
        const sc = stripComments(sink.code_snapshot);
        if (!INTEG_RE354.test(code) && !INTEG_RE354.test(sc)) {
          if (/\b(install|update|deploy|execute|run|import|require|load|eval|package|module|plugin|binary)\b/i.test(sc)) {
            findings.push({
              source: nodeRef(node), sink: nodeRef(sink),
              missing: 'CONTROL (integrity check — verify hash/checksum/signature before processing)',
              severity: 'high',
              description: `External data from ${node.label} processed at ${sink.label} without integrity verification.`,
              fix: 'Verify integrity: compare SHA-256 hash, verify GPG signature, or use lockfiles with integrity hashes.',
            });
          }
        }
      }
    }
  }
  return { cwe: 'CWE-354', name: 'Improper Validation of Integrity Check Value', holds: findings.length === 0, findings };
}

/**
 * CWE-757: Selection of Less-Secure Algorithm During Negotiation
 * Detects SSLv2/v3, TLS 1.0/1.1, weak cipher suites (EXPORT, NULL, RC4, DES).
 */
function verifyCWE757(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const WEAK_PROTO_RE757 = /\bSSLv2\b|\bSSLv3\b|\bSSLv23\b|\bTLSv1\b(?![\d.])|TLSv1\.0\b|\bTLSv1_0\b|TLSv1\.1\b|\bTLSv1_1\b|\bssl\.PROTOCOL_SSLv[23]\b|\bssl\.PROTOCOL_TLSv1\b|\bTLS_1_[01]\b/i;
  const WEAK_CFG_RE757 = /minVersion\s*[:=]\s*['"]TLSv1['"]|minVersion\s*[:=]\s*['"]TLSv1\.[01]['"]|secureProtocol\s*[:=]\s*['"]SSLv/i;
  const WEAK_CIPH_RE757 = /\bEXPORT\b|\bNULL\b|\baNULL\b|\beNULL\b|\bRC4\b|\bDES\b|\b3DES\b|\bDH_anon\b|\bDHE_anon\b|\bECDH_anon\b/i;
  const STRONG_PROTO_RE757 = /minVersion\s*[:=]\s*['"]TLSv1\.[23]['"]|\bTLSv1_[23]\b|\bTLSv1\.[23]\b|\bTLS_1_[23]\b/i;

  const tlsNodes757 = map.nodes.filter(n =>
    n.node_subtype.includes('tls') || n.node_subtype.includes('ssl') || n.node_subtype.includes('https') ||
    n.node_subtype.includes('crypto') || n.node_subtype.includes('config') || n.node_subtype.includes('server') ||
    /\b(tls|ssl|https|createServer|createSecureServer|secureContext|SSLContext|TLSSocket)\b/i.test(n.code_snapshot)
  );

  for (const node of tlsNodes757) {
    const code = stripComments(node.code_snapshot);
    if (WEAK_PROTO_RE757.test(code) && !STRONG_PROTO_RE757.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (enforce TLS 1.2+ minimum protocol version)',
        severity: 'high',
        description: `Weak TLS/SSL protocol version at ${node.label}. SSLv2/v3/TLS 1.0/1.1 have known vulnerabilities.`,
        fix: 'Enforce TLS 1.2 minimum: { minVersion: "TLSv1.2" } (Node.js), tls.Config{MinVersion: tls.VersionTLS12} (Go).',
      });
    }
    if (WEAK_CFG_RE757.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (enforce TLS 1.2+ minimum protocol version)',
        severity: 'high',
        description: `TLS minimum version set too low at ${node.label}. TLS 1.0 and 1.1 are deprecated.`,
        fix: 'Set minVersion to "TLSv1.2" or higher. TLS 1.3 is preferred where supported.',
      });
    }
    if (WEAK_CIPH_RE757.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'CONTROL (strong cipher suite — disable EXPORT, NULL, RC4, DES ciphers)',
        severity: 'high',
        description: `Weak cipher suite at ${node.label}. EXPORT/NULL/RC4/DES/anonymous DH provide insufficient encryption.`,
        fix: 'Use modern suites: TLS_AES_256_GCM_SHA384, TLS_CHACHA20_POLY1305. Remove EXPORT/NULL/RC4/DES/anon ciphers.',
      });
    }
  }
  return { cwe: 'CWE-757', name: 'Selection of Less-Secure Algorithm During Negotiation', holds: findings.length === 0, findings };
}

/**
 * CWE-759: Use of a One-Way Hash without a Salt
 * Detects password hashing without salt: raw MD5/SHA on passwords.
 */
function verifyCWE759(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const PW_RE759 = /\b(password|passwd|pwd|credential|passphrase|pin|user_pass|password_hash)\b/i;
  const HASH_RE759 = /\bcreateHash\s*\(\s*['"](?:md5|sha1|sha256|sha512)['"]\s*\)\.update\s*\(|\bhashlib\.(?:md5|sha1|sha256|sha512)\s*\(|\bMessageDigest\.getInstance\s*\(\s*['"](?:MD5|SHA-?1|SHA-?256|SHA-?512)['"]\s*\)|\bDigest::(?:MD5|SHA1|SHA256|SHA512)\.(?:hexdigest|digest)\s*\(|\bsha256\.New\(\)|md5\.New\(\)|sha1\.New\(\)|CC_SHA256\(|CC_MD5\(|hash\s*\(\s*['"](?:md5|sha1|sha256|sha512)['"]/i;
  const SALT_RE759 = /\bsalt\b|\brandomBytes\b|\burandom\b|\bSecureRandom\b|\bnonce\b|\brandom_bytes\b|\bcrypto\.random\b|\bos\.urandom\b/i;
  const PROPER_RE759 = /\bbcrypt\b|\bscrypt\b|\bargon2\b|\bPBKDF2\b|\bpassword_hash\b|\bGenerateFromPassword\b|\bpasslib\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    if (!PW_RE759.test(code) && !PW_RE759.test(node.label)) continue;
    if (HASH_RE759.test(code) && !SALT_RE759.test(code) && !PROPER_RE759.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (salted password hashing — bcrypt, scrypt, or Argon2)',
        severity: 'high',
        description: `Password hashed without salt at ${node.label}. Unsalted hashes are vulnerable to rainbow table attacks.`,
        fix: 'Use bcrypt, scrypt, or Argon2id (they handle salting automatically). ' +
          'Never use raw SHA-256/MD5 for passwords. Example: bcrypt.hash(password, 12).',
      });
    }
  }

  // Flow-based: INGRESS(password) -> TRANSFORM(hash) without salt
  const pwIng759 = nodesOfType(map, 'INGRESS').filter(n => PW_RE759.test(n.label) || PW_RE759.test(n.code_snapshot));
  const hashSinks759 = map.nodes.filter(n =>
    (n.node_type === 'TRANSFORM' || n.node_type === 'EXTERNAL') &&
    (n.node_subtype.includes('hash') || n.node_subtype.includes('crypto') || HASH_RE759.test(stripComments(n.code_snapshot)))
  );
  for (const src of pwIng759) {
    for (const sink of hashSinks759) {
      if (hasTaintedPathWithoutControl(map, src.id, sink.id)) {
        const sc = stripComments(sink.code_snapshot);
        if (!SALT_RE759.test(sc) && !PROPER_RE759.test(sc) && !findings.some(f => f.sink.id === sink.id)) {
          findings.push({
            source: nodeRef(src), sink: nodeRef(sink),
            missing: 'TRANSFORM (salted password hashing — unique salt per password)',
            severity: 'high',
            description: `Password from ${src.label} hashed at ${sink.label} without a salt. Rainbow tables can reverse unsalted hashes.`,
            fix: 'Use bcrypt.hash(password, saltRounds) or argon2.hash(password). If PBKDF2, pass a unique random salt.',
          });
        }
      }
    }
  }
  return { cwe: 'CWE-759', name: 'Use of a One-Way Hash without a Salt', holds: findings.length === 0, findings };
}

/**
 * CWE-760: Use of a One-Way Hash with a Predictable Salt
 * Detects hardcoded salts, username/email as salt, timestamp-based salts.
 */
function verifyCWE760(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const HARD_SALT_RE760 = /salt\s*[:=]\s*['"][^'"]+['"]|SALT\s*[:=]\s*['"][^'"]+['"]|\.update\s*\(\s*['"][^'"]+['"]\s*\+|\.update\s*\(\s*password\s*\+\s*['"][^'"]+['"]/i;
  const USER_SALT_RE760 = /salt\s*[:=]\s*(?:user(?:name)?|email|user_id|userId|login|name)\b|\.update\s*\(\s*(?:username|email|user\.name)\s*\+/i;
  const TIME_SALT_RE760 = /salt\s*[:=]\s*(?:Date\.now|time|timestamp|new Date|datetime)/i;
  const PW_RE760 = /\b(password|passwd|pwd|credential|passphrase|pass_hash|password_hash)\b/i;
  const RAND_SALT_RE760 = /\brandomBytes\b|\burandom\b|\bSecureRandom\b|\bcrypto\.random\b|\bcrypto\/rand\b|\brandom_bytes\b|\bgenerate.*salt\b|\bbcrypt\b|\bscrypt\b|\bargon2\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    if (!PW_RE760.test(code) && !PW_RE760.test(node.label)) continue;
    if (HARD_SALT_RE760.test(code) && !RAND_SALT_RE760.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (unique random salt per password — crypto.randomBytes(16))',
        severity: 'high',
        description: `Hardcoded/static salt for password hashing at ${node.label}. Attackers precompute one rainbow table for all users.`,
        fix: 'Generate unique random salt per password: crypto.randomBytes(16). Better: use bcrypt/Argon2 (auto-salting).',
      });
    }
    if (USER_SALT_RE760.test(code) && !RAND_SALT_RE760.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (cryptographically random salt — not derived from user data)',
        severity: 'high',
        description: `Predictable salt (username/email) for password hashing at ${node.label}. Enables targeted precomputation.`,
        fix: 'Use cryptographically random salt: crypto.randomBytes(16). Never use username/email as salt.',
      });
    }
    if (TIME_SALT_RE760.test(code) && !RAND_SALT_RE760.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (cryptographically random salt — not time-based)',
        severity: 'high',
        description: `Time-based salt for password hashing at ${node.label}. Timestamps are predictable, reducing salt space.`,
        fix: 'Use cryptographically random salt: crypto.randomBytes(16). Timestamps have low entropy.',
      });
    }
  }
  return { cwe: 'CWE-760', name: 'Use of a One-Way Hash with a Predictable Salt', holds: findings.length === 0, findings };
}

/**
 * CWE-916: Use of Password Hash With Insufficient Computational Effort
 * Detects fast hashes for passwords, low bcrypt rounds, low PBKDF2 iterations.
 */
function verifyCWE916(map: NeuralMap): VerificationResult {
  const findings: Finding[] = [];
  const PW_RE916 = /\b(password|passwd|pwd|credential|passphrase|pin|pass_hash|password_hash|signUp|register|login|authenticate)\b/i;
  const FAST_RE916 = /\bcreateHash\s*\(\s*['"](?:md5|sha1|sha256|sha512)['"]\s*\)|\bhashlib\.(?:md5|sha1|sha256|sha512)\s*\(|\bMessageDigest\.getInstance\s*\(\s*['"](?:MD5|SHA-?1|SHA-?256|SHA-?512)['"]\s*\)|\bDigest::(?:MD5|SHA1|SHA256|SHA512)\b|\bCC_SHA256\s*\(|\bCC_MD5\s*\(|\bhash\s*\(\s*['"](?:md5|sha1|sha256|sha512)['"]/i;
  const LOW_BC_RE916 = /\bbcrypt\.(?:hash|hashSync)\s*\([^,]+,\s*([1-9])\s*\)|\bsaltRounds\s*[:=]\s*([1-9])\s*[;,]|\bcost\s*[:=]\s*([1-9])\s*[;,\}]|\brounds\s*[:=]\s*([1-9])\s*[;,\}]/i;
  const LOW_PB_RE916 = /\bpbkdf2\b[^;]*iterations?\s*[:=]\s*(\d{1,4})\b/i;
  const PROPER_RE916 = /\bbcrypt\b|\bscrypt\b|\bargon2\b|\bPBKDF2\b/i;

  for (const node of map.nodes) {
    const code = stripComments(node.code_snapshot);
    if (!PW_RE916.test(code) && !PW_RE916.test(node.label)) continue;
    if (FAST_RE916.test(code) && !PROPER_RE916.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (adaptive password hash — bcrypt, scrypt, or Argon2id)',
        severity: 'high',
        description: `Fast hash for password at ${node.label}. MD5/SHA compute in microseconds — billions of guesses per second.`,
        fix: 'Use bcrypt (cost >= 12), scrypt, or Argon2id. Never use MD5/SHA directly for password storage.',
      });
      continue;
    }
    if (LOW_BC_RE916.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (sufficient bcrypt work factor — minimum 10 rounds, recommended 12+)',
        severity: 'medium',
        description: `Low bcrypt cost factor at ${node.label}. Fewer than 10 rounds gives insufficient brute-force resistance.`,
        fix: 'Set bcrypt cost to at least 12: bcrypt.hash(password, 12). Re-hash on login when upgrading.',
      });
    }
    if (LOW_PB_RE916.test(code)) {
      findings.push({
        source: nodeRef(node), sink: nodeRef(node),
        missing: 'TRANSFORM (sufficient PBKDF2 iterations — minimum 600000 for SHA-256)',
        severity: 'medium',
        description: `Low PBKDF2 iteration count at ${node.label}. OWASP recommends >= 600,000 for SHA-256.`,
        fix: 'Set PBKDF2 iterations to >= 600,000 for SHA-256. Better: migrate to Argon2id.',
      });
    }
  }
  return { cwe: 'CWE-916', name: 'Use of Password Hash With Insufficient Computational Effort', holds: findings.length === 0, findings };
}
